-- Poems batch 110
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('6bd06c04-b60b-45c1-80ba-b1005e29202c','春雪得小詩五首且約客登賞心亭  其三','韓元吉','宋','宋诗','song-poetry','','[]','臘前未見梅如雪，春到還驚雪似梅。',32,'全唐诗/poet.song.124000.json','["臘前未見梅如雪，春到還驚雪似梅。", "可是天公有情思，便令花樹一時開。"]'),
('027e881a-3177-48b4-a655-7a692060c6a3','春雪得小詩五首且約客登賞心亭  其四','韓元吉','宋','宋诗','song-poetry','','[]','江南絕景賞心亭，卧雪難尋舊畫屏。',32,'全唐诗/poet.song.124000.json','["江南絕景賞心亭，卧雪難尋舊畫屏。", "白鷺洲前夜來雪，故應此畫勝丹青。"]'),
('0a521e8f-e60f-402e-8495-be809923c28b','春雪得小詩五首且約客登賞心亭  其五','韓元吉','宋','宋诗','song-poetry','','[]','竹爐聽雪坐蒲團，長笑詩人不耐寒。',32,'全唐诗/poet.song.124000.json','["竹爐聽雪坐蒲團，長笑詩人不耐寒。", "未辦貂裘走南陌，肯來高處一憑欄。"]'),
('23ed7972-d761-4d9d-b62c-760e193e367c','夜雪  其一','韓元吉','宋','宋诗','song-poetry','','[]','爐火深紅蠟炬明，打窗風雪正縱橫。',32,'全唐诗/poet.song.124000.json','["爐火深紅蠟炬明，打窗風雪正縱橫。", "瓦瓶旋注山泉滿，却作瀟瀟細雨聲。"]'),
('1b24db32-e257-40e2-ac2f-cb60f5e4d5e9','夜雪  其二','韓元吉','宋','宋诗','song-poetry','','[]','伴眼文書細作行，昏昏愁卧雪穿廊。',32,'全唐诗/poet.song.124000.json','["伴眼文書細作行，昏昏愁卧雪穿廊。", "何人恰弄風前笛，錯認梅花到枕傍。"]'),
('2afd9a56-68a2-471b-beb2-291abdaae2b2','詠晴','韓元吉','宋','宋诗','song-poetry','','[]','愁眼東西萬里情，山雲斜度水風清。',32,'全唐诗/poet.song.124000.json','["愁眼東西萬里情，山雲斜度水風清。", "客行歲晚忽春盡，看到枯林綠葉成。"]'),
('f3fd3c4a-a3e1-4ed5-adc4-cd8ab032484d','春日書事五首  其一','韓元吉','宋','宋诗','song-poetry','','[]','十年騎馬聽朝雞，老竊州符簿領迷。',32,'全唐诗/poet.song.124000.json','["十年騎馬聽朝雞，老竊州符簿領迷。", "衙鼓不聞春睡足，閉門聊喜得幽棲。"]'),
('57a6e6ed-de22-4904-9fea-3e4fc2ab0bc4','春日書事五首  其二','韓元吉','宋','宋诗','song-poetry','','[]','曉猿夜鶴寂無生，春至山禽百種鳴。',32,'全唐诗/poet.song.124000.json','["曉猿夜鶴寂無生，春至山禽百種鳴。", "步繞新泉聊洗耳，由來心與地俱清。"]'),
('0ba12e05-88bd-406f-aed4-e05cfa85e42b','春日書事五首  其三','韓元吉','宋','宋诗','song-poetry','','[]','極目亭邊花定開，野棠山杏手親栽。',32,'全唐诗/poet.song.124000.json','["極目亭邊花定開，野棠山杏手親栽。", "春風拂檻知何似，應記劉郎兩度來。"]'),
('3dd13da3-4216-47b3-a78f-7eec63c8a4d8','春日書事五首  其四','韓元吉','宋','宋诗','song-poetry','','[]','憶上金華第一峰，相君官重酒樽同。',32,'全唐诗/poet.song.124000.json','["憶上金華第一峰，相君官重酒樽同。", "夢尋絕壑誰重到，零落山桃小院風。"]'),
('bc31eb55-bd0e-4332-88bb-0dd3545ce109','春日書事五首  其五','韓元吉','宋','宋诗','song-poetry','','[]','溪邊亂石蛟鼉卧，煙裏千花錦繡圍。',32,'全唐诗/poet.song.124000.json','["溪邊亂石蛟鼉卧，煙裏千花錦繡圍。", "記得年時作寒食，山橋吹笛雨中歸。"]'),
('90e8a5d1-f65b-4f80-a7bc-caf217058290','晨興','韓元吉','宋','宋诗','song-poetry','','[]','北窗松竹夜蕭騷，詩就呼兒進濁醪。',32,'全唐诗/poet.song.124000.json','["北窗松竹夜蕭騷，詩就呼兒進濁醪。", "睡美不知新雨足，曉來南澗水聲高。"]'),
('4c2206d9-ef5f-4ac1-9e5c-59424f4b86cf','聽雨','韓元吉','宋','宋诗','song-poetry','','[]','吚軋籃輿不計肩，五更殘夢尚悠然。',32,'全唐诗/poet.song.124000.json','["吚軋籃輿不計肩，五更殘夢尚悠然。", "紅油蓋重聽朝雨，却似西江坐釣船。"]'),
('85d8466f-2601-4b3f-94b8-228d19a76071','題張幾仲所藏醉道士圖','韓元吉','宋','宋诗','song-poetry','','[]','何須坐客總能文，呼酒相逢日暮雲。',32,'全唐诗/poet.song.124000.json','["何須坐客總能文，呼酒相逢日暮雲。", "醉倒儘如狂道士，夜歸誰問故將軍。"]'),
('9dfa0c16-b66f-41e7-9c3f-2db421664e99','浙江觀潮','韓元吉','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','江翻海涌勢難平，鼇擲鵬鶱自不停。',32,'全唐诗/poet.song.124000.json','["江翻海涌勢難平，鼇擲鵬鶱自不停。", "端爲君王洗兵馬，參旗井鉞萬雷霆。"]'),
('6027d714-0105-4864-ac05-d37baef200e9','太湖秋晚','韓元吉','宋','宋诗','song-poetry','','["\u592a\u6e56"]','片帆幾日下西風，湖色秋容暮靄中。',32,'全唐诗/poet.song.124000.json','["片帆幾日下西風，湖色秋容暮靄中。", "買得鱸魚弔張翰，卧聽欵乃度垂虹。"]'),
('b026db14-3f92-42c1-9d7b-83f7e3c870a9','海門斜照','韓元吉','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','雲夢懸知八九吞，銀山萬疊漲天門。',32,'全唐诗/poet.song.124000.json','["雲夢懸知八九吞，銀山萬疊漲天門。", "長江日落魚龍舞，古寺煙深鳥雀喧。"]'),
('35add8ba-d731-4b60-94e0-711fdfd5a18d','武昌春色','韓元吉','宋','宋诗','song-poetry','','[]','樊山宮殿已成陳，煙雨陰晴到處春。',32,'全唐诗/poet.song.124000.json','["樊山宮殿已成陳，煙雨陰晴到處春。", "花柳不知興廢事，隔江相倚鬭時新。"]'),
('498ec793-a833-4489-824b-26eb31a8b662','七夕','韓元吉','宋','宋诗','song-poetry','','[]','銀河翻浪拍空流，玉女停梭清露秋。',32,'全唐诗/poet.song.124000.json','["銀河翻浪拍空流，玉女停梭清露秋。", "天上一年真一日，人間風月自生愁。"]'),
('72880a08-0062-4b4a-a3b5-5be61931e1e4','秋懷十首  其一','韓元吉','宋','宋诗','song-poetry','','[]','朝行佛屋魚千里，暮借僧牀鷯一枝。',32,'全唐诗/poet.song.124000.json','["朝行佛屋魚千里，暮借僧牀鷯一枝。", "窗下秋蟲解人意，似憐羈客伴哦詩。"]'),
('b53d4197-e49a-4468-8ed7-2e56be87898b','秋懷十首  其二','韓元吉','宋','宋诗','song-poetry','','[]','酒熟橙黄盛物華，重陽無客不思家。',32,'全唐诗/poet.song.124000.json','["酒熟橙黄盛物華，重陽無客不思家。", "鵝兒剪雪開巖桂，鶴羽攢金散菊花。"]'),
('9baea833-fd01-4087-a7c6-015a8775ed9b','秋懷十首  其三','韓元吉','宋','宋诗','song-poetry','','["\u897f\u6e56"]','小雨驚秋滴夜闌，晴雲和日曉斑斑。',32,'全唐诗/poet.song.124000.json','["小雨驚秋滴夜闌，晴雲和日曉斑斑。", "誰憐客舍塵埃底，猶得西湖一兩山。"]'),
('235c645e-af35-44ed-a4b8-2e979c550e4c','秋懷十首  其四','韓元吉','宋','宋诗','song-poetry','','[]','何許砧聲清夢回，丁東猶作珮環猜。',32,'全唐诗/poet.song.124000.json','["何許砧聲清夢回，丁東猶作珮環猜。", "卷簾風露凉如水，端爲嫦娥向此來。"]'),
('dda86eab-7459-4a85-b85b-f00e30172280','秋懷十首  其五','韓元吉','宋','宋诗','song-poetry','','[]','城外秋荷一半黄，尚餘疏柳照回塘。',32,'全唐诗/poet.song.124000.json','["城外秋荷一半黄，尚餘疏柳照回塘。", "江南底許風光好，塞雁來時未有霜。"]'),
('17374953-7305-4914-bd62-32a7cd395c20','秋懷十首  其六','韓元吉','宋','宋诗','song-poetry','','[]','右手持杯左不空，蟹螯已作雪蒙茸。',32,'全唐诗/poet.song.124000.json','["右手持杯左不空，蟹螯已作雪蒙茸。", "秋風莫起鱸魚夢，未似先生阿堵中。"]'),
('70930238-115b-4bae-87ce-9eb7a5d695fb','秋懷十首  其七','韓元吉','宋','宋诗','song-poetry','','[]','八月濤頭舊有名，今年潮淺岸纔平。',32,'全唐诗/poet.song.124000.json','["八月濤頭舊有名，今年潮淺岸纔平。", "應緣享帝千靈在，豫使魚龍不敢鳴。"]'),
('d2bb588d-d934-4e3a-906b-283cbc753ca4','秋懷十首  其八','韓元吉','宋','宋诗','song-poetry','','[]','塞草初黄邊馬肥，邊塵莫便向南飛。',32,'全唐诗/poet.song.124000.json','["塞草初黄邊馬肥，邊塵莫便向南飛。", "江頭鶴唳秋風起，看取陰山六騎歸。"]'),
('faba9e70-dec4-4020-ac61-4333316a5aba','秋懷十首  其九','韓元吉','宋','宋诗','song-poetry','','["\u897f\u6e56"]','江南四百八十寺，未抵西湖勝處多。',32,'全唐诗/poet.song.124000.json','["江南四百八十寺，未抵西湖勝處多。", "不用樓臺带煙雨，只看宮殿壓晴波。"]'),
('a137ca8d-e9f6-49af-89d8-a605cae179f0','秋懷十首  其一○','韓元吉','宋','宋诗','song-poetry','','[]','閉戶跏趺意已清，爐香燒盡一燈明。',32,'全唐诗/poet.song.124000.json','["閉戶跏趺意已清，爐香燒盡一燈明。", "空庭葉落知多少，一任西風百種聲。"]'),
('b219e3d6-e104-4123-bb61-954c7c508381','聖政更新詔書正告訐之罪因得小詩十首  其一','韓元吉','宋','宋诗','song-poetry','','[]','惡復凶終事久知，豈知聖斷不踰時。',32,'全唐诗/poet.song.124000.json','["惡復凶終事久知，豈知聖斷不踰時。", "小儒未歎周南滯，但喜逢人敢說詩。"]'),
('923372f0-3c0a-422d-8a7f-eeac91fb8830','聖政更新詔書正告訐之罪因得小詩十首  其二','韓元吉','宋','宋诗','song-poetry','','[]','桓溫將死謝安起，霍氏初除魏相來。',32,'全唐诗/poet.song.124000.json','["桓溫將死謝安起，霍氏初除魏相來。", "誰與聖君安大業，巍巍廊廟可無材。"]'),
('5c6a6456-0ffc-4961-8fa4-01a8fcf57cfd','聖政更新詔書正告訐之罪因得小詩十首  其三','韓元吉','宋','宋诗','song-poetry','','[]','聖朝遂失誅元載，公議猶能去霍山。',32,'全唐诗/poet.song.124000.json','["聖朝遂失誅元載，公議猶能去霍山。", "落膽徒聞溫御史，不知睿意在羣奸。"]'),
('1a6aebe9-07ec-4d86-b219-94c557bd2be3','聖政更新詔書正告訐之罪因得小詩十首  其四','韓元吉','宋','宋诗','song-poetry','','[]','元祐諸公秉國均，詔條先請惠吾民。',32,'全唐诗/poet.song.124000.json','["元祐諸公秉國均，詔條先請惠吾民。", "孤雛腐鼠何勞逐，準擬朝廷政事新。"]'),
('7f571b0e-fa77-4753-87af-57ff9fb87315','聖政更新詔書正告訐之罪因得小詩十首  其五','韓元吉','宋','宋诗','song-poetry','','[]','金貂七葉誰能必，石槨三年計自愚。',32,'全唐诗/poet.song.124000.json','["金貂七葉誰能必，石槨三年計自愚。", "得鹿覆蕉真一夢，求魚緣木信狂圖。"]'),
('50e9dbf4-873e-41fd-a94d-aced53a6775a','聖政更新詔書正告訐之罪因得小詩十首  其六','韓元吉','宋','宋诗','song-poetry','','[]','獻可爭先詆荆國，瑩中居首論莆陽。',32,'全唐诗/poet.song.124000.json','["獻可爭先詆荆國，瑩中居首論莆陽。", "十年言路皆支黨，前無一語譏安昌。"]'),
('2a8a747d-1eaa-4f25-a23f-2d0f1e3a1822','聖政更新詔書正告訐之罪因得小詩十首  其七','韓元吉','宋','宋诗','song-poetry','','[]','近聞羔鴈已成羣，藻鑒渠能涇渭分。',32,'全唐诗/poet.song.124000.json','["近聞羔鴈已成羣，藻鑒渠能涇渭分。", "急士且須侯雍齒，得賢端可吏朱雲。"]'),
('2710d21d-2199-4207-a4b5-d4dd8cf94312','聖政更新詔書正告訐之罪因得小詩十首  其八','韓元吉','宋','宋诗','song-poetry','','[]','刺字幾漫冠欲塵，向來浮薄自紛紛。',32,'全唐诗/poet.song.124000.json','["刺字幾漫冠欲塵，向來浮薄自紛紛。", "爾曹胸次多周孔，忍作銅山破賊文。"]'),
('1443df58-13ae-47a7-b877-6e650ed0c9a0','聖政更新詔書正告訐之罪因得小詩十首  其九','韓元吉','宋','宋诗','song-poetry','','[]','荆棘誰令滿路栽，雷州司戶却生回。',32,'全唐诗/poet.song.124000.json','["荆棘誰令滿路栽，雷州司戶却生回。", "獨憐陽陸真天命，不見承平公道開。"]'),
('09ea4e8e-abaf-4d40-9e93-99c0faaaef52','聖政更新詔書正告訐之罪因得小詩十首  其一○','韓元吉','宋','宋诗','song-poetry','','[]','潮陽初謫八千里，中令俄成十九年。',32,'全唐诗/poet.song.124000.json','["潮陽初謫八千里，中令俄成十九年。", "地下修文應泚筆，衛公精爽故依然。"]'),
('21f07da3-6bc0-4d9a-bfc9-b1d3ff39f11b','卧病','韓元吉','宋','宋诗','song-poetry','','[]','有身自覺皆爲患，了事從來却號癡。',32,'全唐诗/poet.song.124000.json','["有身自覺皆爲患，了事從來却號癡。", "貧裏定知强健樂，未妨斗酒百篇詩。"]'),
('4c321e1c-dd50-43fa-9888-4c78ea6eb1b4','夜宿青陽旅舍起觀林端積雪半消疑山礬盛開','韓元吉','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','風卷千林夜雪晴，九華山下月微明。',32,'全唐诗/poet.song.124000.json','["風卷千林夜雪晴，九華山下月微明。", "不須更覓唐昌蘂，樹樹瓏璁玉刻成。"]'),
('cbfdcebd-a60e-406b-8157-9ef86902ec64','去草','韓元吉','宋','宋诗','song-poetry','','[]','永日荒園獨荷鋤，草根藤蔓喜無餘。',32,'全唐诗/poet.song.124000.json','["永日荒園獨荷鋤，草根藤蔓喜無餘。", "誰憐仲舉平生志，却學齊民種樹書。"]'),
('4b02866c-0494-4f8d-971d-38e287b1a6bb','偶興四首  其一','韓元吉','宋','宋诗','song-poetry','','[]','桂花飄盡菊花黄，閑對芳叢靜愛香。',32,'全唐诗/poet.song.124000.json','["桂花飄盡菊花黄，閑對芳叢靜愛香。", "堂下草深須一丈，會看春意滿池塘。"]'),
('0edab033-d438-4f67-a83b-0486a61b16fd','偶興四首  其二','韓元吉','宋','宋诗','song-poetry','','[]','小園無數菊花開，準擬花殘便見梅。',32,'全唐诗/poet.song.124000.json','["小園無數菊花開，準擬花殘便見梅。", "不恨無花正無酒，敲門誰送一樽來。"]'),
('9edbb17b-75f2-48c9-80ba-114a9442c31e','偶興四首  其三','韓元吉','宋','宋诗','song-poetry','','[]','江南菊少開金色，只有霜葩雜御黄。',32,'全唐诗/poet.song.124000.json','["江南菊少開金色，只有霜葩雜御黄。", "乞得黄花真愛惜，明年賸種壓羣芳。"]'),
