('d7988c65-5f9d-4901-aadc-8882eb5241d9','以雙蓮戲韓子師  其一','韓元吉','宋','宋诗','song-poetry','','[]','雨洗風梳兩鬭新，凌波微步襪生塵。',32,'全唐诗/poet.song.124000.json','["雨洗風梳兩鬭新，凌波微步襪生塵。", "真成紅玉嬌相倚，不減昭陽第一人。"]'),
('f9b63f9c-e0b7-417b-afa0-0974fe9e46e0','以雙蓮戲韓子師  其二','韓元吉','宋','宋诗','song-poetry','','[]','並舞連歌意態新，水晶宮裏向無塵。',32,'全唐诗/poet.song.124000.json','["並舞連歌意態新，水晶宮裏向無塵。", "一時風月誰能許，要是君家兩玉人。"]'),
('ebb448f6-098c-4155-88ba-e8bd611b77c4','種竹','韓元吉','宋','宋诗','song-poetry','','[]','香苞吹盡翠成圍，牆角蕭蕭一徑微。',32,'全唐诗/poet.song.124000.json','["香苞吹盡翠成圍，牆角蕭蕭一徑微。", "已喜軒窗無俗韵，更憐風月有清輝。"]'),
('ec0d57b0-0870-4f3e-9f09-ba94cc2adbd0','謝陳秀才送詩','韓元吉','宋','宋诗','song-poetry','','[]','偶因借得官書讀，小札于君一向疏。',32,'全唐诗/poet.song.124000.json','["偶因借得官書讀，小札于君一向疏。", "忽寄江湖詩百紙，梅花擔上雪晴初。"]'),
('ae15497c-3210-4c94-a0f0-ea36561940e5','用梁士衡韵還鄧器先道中詩卷','韓元吉','宋','宋诗','song-poetry','','[]','夢繞江南雲水鄉，麻姑壇下月如霜。',32,'全唐诗/poet.song.124000.json','["夢繞江南雲水鄉，麻姑壇下月如霜。", "風光景色一千里，都在君家古錦囊。"]'),
('9b8df25c-6022-4940-b77c-e85818e396ea','悼老瓊二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','歌舞相從六換年，秦箏已斷不能絃。',32,'全唐诗/poet.song.124000.json','["歌舞相從六換年，秦箏已斷不能絃。", "荷花滿眼垂楊綠，腸斷清宵月正圓。"]'),
('b657af12-6639-41f4-a78d-d54870e80240','悼老瓊二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','江水東流湖水西，水邊花落夢回時。',32,'全唐诗/poet.song.124000.json','["江水東流湖水西，水邊花落夢回時。", "南屏山下風吹土，猶作蕭蕭暮雨垂。"]'),
('f8796f81-9989-4de5-a102-ccb10b79f832','紙鳶','韓元吉','宋','宋诗','song-poetry','','[]','排風决起閙羣兒，勢力由來一線微。',32,'全唐诗/poet.song.124000.json','["排風决起閙羣兒，勢力由來一線微。", "天上鵷鸞徒似耳，却驚遮日傍雲飛。"]'),
('5935b0de-1ad1-40e4-8cc4-07690b31d9d0','廬山霽色','韓元吉','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','山北山南佛寺開，煙銷日出更崔嵬。',32,'全唐诗/poet.song.124000.json','["山北山南佛寺開，煙銷日出更崔嵬。", "讀書誰伴謫仙老，沽酒要須陶令來。"]'),
('ae28b451-a9d4-4b49-9455-1a89cd640902','靈隠冷泉','韓元吉','宋','宋诗','song-poetry','','[]','山涵水影兩空明，水到山前百尺清。',32,'全唐诗/poet.song.124000.json','["山涵水影兩空明，水到山前百尺清。", "洞裏臞仙應一笑，抱琴時爲寫寒聲。"]'),
('f59e70ef-eefe-4128-b2dc-f116cd65b319','南巖','韓元吉','宋','宋诗','song-poetry','','[]','官曹簿領無時空，一春蹙蹙塵埃中。',192,'全唐诗/poet.song.124000.json','["官曹簿領無時空，一春蹙蹙塵埃中。", "溪南十里巖谷好，俗駕屢整無由窮。", "前時相邀雨斷道，今時不雨天亦風。", "乃知書生不解事，每以慳澀勤天公。", "興來邂逅始一往，相與縱轡隨飛鴻。", "野棠著子梅杏老，密葉尚带殘花紅。", "崢嶸屋宇吁可怪，無乃開闢煩豐隆。", "却尋危徑山巉絕，俯仰曠野迷西東。", "涓涓寒流滴冰雪，一酌爲我凉心胸。", "山川何曾歲月計，可憐翠阜紛磨礱。", "人生歡笑不易得，此會幾許誰能同。", "春禽正喧日已暮，歎我歸期還匆匆。"]'),
('12406b88-5922-4380-a08f-d34f825a7479','句  其一','韓元吉','宋','宋诗','song-poetry','','[]','幾年家住玉溪頭，乘興時來上釣舟。',16,'全唐诗/poet.song.124000.json','["幾年家住玉溪頭，乘興時來上釣舟。"]'),
('d74dd5d7-baa4-47e1-a147-f273142f080a','句  其二','韓元吉','宋','宋诗','song-poetry','','[]','但如王粲賦從軍，莫爲班姬詠團扇。',16,'全唐诗/poet.song.124000.json','["但如王粲賦從軍，莫爲班姬詠團扇。"]'),
('5648d520-4ed4-4da0-a2d7-f36cbe1df69d','賈司倉祠','李占','宋','宋诗','song-poetry','','[]','爲詩直欲無前古，留骨如今錮一山。',32,'全唐诗/poet.song.124000.json','["爲詩直欲無前古，留骨如今錮一山。", "富貴當年人曷在，只君詩價滿人間。"]'),
('c248dfd7-ffba-4051-a7fe-f8f3bb861334','句','馮顯','宋','宋诗','song-poetry','','[]','甲子循環幸一終。',8,'全唐诗/poet.song.124000.json','["甲子循環幸一終。"]'),
('74cdf8a9-0ff5-4879-866e-14aac1364a6e','寧師西閣','趙善應','宋','宋诗','song-poetry','','[]','飄泊南來幾歲寒，追談往事漫心酸。',32,'全唐诗/poet.song.124000.json','["飄泊南來幾歲寒，追談往事漫心酸。", "雲烟暮隔中原望，歸折梅花忍淚看。"]'),
('f21f13cf-9525-48b6-94f3-e4969755b012','次韵李長卿','趙善應','宋','宋诗','song-poetry','','[]','一別芳洲不計年，舊時攀折柳依然。',32,'全唐诗/poet.song.124000.json','["一別芳洲不計年，舊時攀折柳依然。", "故人似欲撩詩興，賸折梅花向酒邊。"]'),
('cf87725b-e313-4f78-8337-76020ffefbd8','喜閒  其一','趙善傅','宋','宋诗','song-poetry','','[]','林泉違約久，歸此有餘歡。',48,'全唐诗/poet.song.124000.json','["林泉違約久，歸此有餘歡。", "引水來新沼，鈎簾見好山。", "漁歌能破寂，鷗侶可陪閒。", "榮辱曾何絆，怡然見考槃。"]'),
('6f132c9b-f005-4cf8-850b-446768d875a0','喜閒  其二','趙善傅','宋','宋诗','song-poetry','','[]','向晚幽棲地，襟懷頗自宜。',48,'全唐诗/poet.song.124000.json','["向晚幽棲地，襟懷頗自宜。", "品題風與月，驅使酒兼詩。", "供興千巖竹，應門一局棋。", "此中無俗慮，高卧復何之。"]'),
('6d7914b5-04b3-4154-ad44-b446153f1fdc','勉善信弟志學','趙善傅','宋','宋诗','song-poetry','','[]','白日如飛去莫羈，於今舊發弗違疑。',32,'全唐诗/poet.song.124000.json','["白日如飛去莫羈，於今舊發弗違疑。", "爲人欲立持身本，入學先培進德基。"]'),
('5046fadd-71c3-4656-bff1-6f093ff07c9a','寓居等慈寺感懷','趙善傅','宋','宋诗','song-poetry','','[]','欽從王命寄招提，寂寂荒階綠草齊。',32,'全唐诗/poet.song.124000.json','["欽從王命寄招提，寂寂荒階綠草齊。", "明月夜深接佛閣，看來不比汴梁時。"]'),
('4c41360b-61b8-448b-a52b-8e05e2f90f90','秋夜有懷孟兄','趙善傅','宋','宋诗','song-poetry','','[]','日落寒山剪剪風，一行雁字各西東。',32,'全唐诗/poet.song.124000.json','["日落寒山剪剪風，一行雁字各西東。", "雖然顔面睽千里，料得相思兩地同。"]'),
('99650c63-2d7a-4285-a433-fce60fcba4cb','仲兄書至','趙善傅','宋','宋诗','song-poetry','','[]','別後曾無一紙書，忽於今日寄雙魚。',32,'全唐诗/poet.song.124000.json','["別後曾無一紙書，忽於今日寄雙魚。", "開緘盡是離鄉思，何日重來舜里居。"]'),
('c17cf28b-7783-4d98-b348-7adca3c6f9df','南郊即景','趙善信','宋','宋诗','song-poetry','','[]','勝日覓芳行，白雲朝露濕。',48,'全唐诗/poet.song.124000.json','["勝日覓芳行，白雲朝露濕。", "沙頭人過頻，橋底湍流急。", "花在隔籬明，鵑於高樹泣。", "青帘沽酒家，和氣春風集。"]'),
('291b9506-39ab-4aa3-a384-97c4364e724a','步月池','趙善信','宋','宋诗','song-poetry','','[]','燈火黄昏盡，無家不掩門。',48,'全唐诗/poet.song.124000.json','["燈火黄昏盡，無家不掩門。", "爲看橋上月，印破水中雲。", "樹影縱橫見，蛙聲雜遝聞。", "幽人思正苦，獨坐更難論。"]'),
('a65fb883-a4e4-43c1-9c07-c450a8c97d89','車輅院書懷','趙善信','宋','宋诗','song-poetry','','[]','地僻人稀到，兀然對百樓。',48,'全唐诗/poet.song.124000.json','["地僻人稀到，兀然對百樓。", "墨花香入硯，詩草色傾甌。", "晝迥拋書睡，雨餘著屐遊。", "還須期報主，檀爇紫雲浮。"]'),
('50cadf2f-dbf9-48eb-98cb-a1c115929b5e','舉野狐話頌','釋印','宋','宋诗','song-poetry','','[]','不落不昧，誣人之罪。',36,'全唐诗/poet.song.124000.json','["不落不昧，誣人之罪。", "不昧不落，無繩自縛。", "可憐柳絮隨春風，有時自西還自東。"]'),
('5529b2d7-08a0-48d1-9f7b-aa1db8570ba4','挽薛艮齋','徐定','宋','宋诗','song-poetry','','[]','今古名流特地奇，生平學術得真師。',64,'全唐诗/poet.song.124000.json','["今古名流特地奇，生平學術得真師。", "纘將管樂爲操藴，論切周唐入設施。", "經理遠橅歸使節，撫循中道稱藩麾。", "堪驚四十成埋玉，嘆息襟期有未爲。"]'),
('5c4016b5-3901-4adc-90d8-d1a47e8b4b25','句','李全之','宋','宋诗','song-poetry','','[]','還山終戴鹿皮巾。',8,'全唐诗/poet.song.124000.json','["還山終戴鹿皮巾。"]'),
('8637bd68-e3f1-4ac6-9a03-be421685cc47','題薌氏慈節卷','羅珊','宋','宋诗','song-poetry','','[]','子甫七齡夫蚤世，獨將慈節鑄心肝。',64,'全唐诗/poet.song.124000.json','["子甫七齡夫蚤世，獨將慈節鑄心肝。", "含暉寸草流光遠，天矢孤闈正氣寒。", "苦味燈前餘粉膽，清風塵外振衿鞶。", "悠悠甲子知無恙，看到恩深紫誥鸞。"]'),
('747a2d69-5419-4949-a0d9-4a8219267a75','賀羅珊','新喻宰','宋','宋诗','song-poetry','','[]','刑部二品尚書郎，匹馬蕭然返故鄉。',32,'全唐诗/poet.song.124000.json','["刑部二品尚書郎，匹馬蕭然返故鄉。", "點檢庭前親種柳，於今森列總成行。"]'),
('e0423e53-c944-4929-8b93-0b60c614e9f8','送劉朝美侍郎歸蜀','關耆孫','宋','宋诗','song-poetry','','[]','清議久不作，世無公是非。',48,'全唐诗/poet.song.124000.json','["清議久不作，世無公是非。", "祇因翻故紙，不覺蹈危機。", "東壁夢初斷，西山蕨正肥。", "十年成底事，贏得載書歸。"]'),
('a484ec3a-afd7-4f6f-9368-382ab8527478','遊東屯','關耆孫','宋','宋诗','song-poetry','','[]','呼船渡西瀼，策馬行東屯。',264,'全唐诗/poet.song.124000.json','["呼船渡西瀼，策馬行東屯。", "猶有竹下屋，依然柴作門。", "林深多鳥雀，山對有猱猿。", "世隔券尤在，堂非基自存。", "稼雲迷曠野，屏翠隨層軒。", "土厚疑吾里，溪清何處源。", "餐英金有種，飯粒玉爲根。", "蘆筍戀春渚，蕨芽蕃故園。", "山名竊諸葛，城榜爲公孫。", "雲雨峽前夢，琵琶山後村。", "留人惟野趣，隔世絕塵喧。", "牆度鳥飛影，泥留兔走痕。", "漁樵老歲月，藜莧過朝昏。", "槎漢我初返，梯參君暫捫。", "車徒今附驥，行列舊同鵷。", "休沐因閑日，攜持訪古原。", "摧頹一弊節，走逐雙朱轓。", "凉飆薄巾袂，佳氣浮酒樽。", "出遊有此樂，相視而無言。", "則爲樵夫嘲，甚於人言煩。", "取君古錦囊，盛我浣花番。", "歸去待星上，隨江看月翻。"]'),
('118f10a3-614b-444c-b5a7-7f52d1a63122','句','關耆孫','宋','宋诗','song-poetry','','[]','况此憔悴州，居人仰煮鹵。',24,'全唐诗/poet.song.124000.json','["况此憔悴州，居人仰煮鹵。", "煮鹵數十年，餘者皆貧寠。"]'),
('d95509f8-012d-48b9-bbbc-3c04f58661b8','采菊亭','朱豈','宋','宋诗','song-poetry','','[]','霜降草花落，林柯亦紛披。',156,'全唐诗/poet.song.124000.json','["霜降草花落，林柯亦紛披。", "耿耿園中菊，煌煌發幽姿。", "良夜積華露，花葉繁以滋。", "風流賢史君，澹然與花期。", "黎旦曳杖去，採掇欣忘疲。", "佳色彌清興，明艷侔晨煇。", "雅尚已千載，神交此一時。", "秉芬寄遐想，載詠閒居詩。", "氣清秋改容，景晏山益奇。", "佳處要領略，忘言心自怡。", "客來無可語，坐見花陰移。", "夕英浮凍醴，痛飲須反卮。", "歸來北窗下，古風良可追。"]'),
('e2ccd606-4d24-41a5-bde4-9f03e12c4c51','七臺山','黄克仁','宋','宋诗','song-poetry','','[]','登陟最高頂，四圍山盡低。',48,'全唐诗/poet.song.124000.json','["登陟最高頂，四圍山盡低。", "星辰可手掬，杉檜與天齊。", "只覺風生腋，恍如雲作梯。", "何當謝塵事，來此共幽棲。"]'),
('807d2f2c-7bb3-497c-8e5e-46b5d391eb9f','題涪江石魚次何憲韵','盛辛','宋','宋诗','song-poetry','','[]','巨浸浮空無路通，雙鱗紀瑞杳難窮。',64,'全唐诗/poet.song.124000.json','["巨浸浮空無路通，雙鱗紀瑞杳難窮。", "昔人刻石留山趾，今日呈祥表歲豐。", "衆喜有年歌善政，獨慚無補助成功。", "須知顯晦將千載，往哲標名歲大中。"]'),
('59c9baee-f7b7-4537-a5bb-c013de0804b9','五洩山寺','廖虞弼','宋','宋诗','song-poetry','','[]','招提深鎖綠苔幽，故遣高人向此留。',64,'全唐诗/poet.song.124000.json','["招提深鎖綠苔幽，故遣高人向此留。", "萬疊雲山從地湧，雙源瀑布自天流。", "風翻象宇松聲碎，雨過禪房竹翠浮。", "試問苾芻會厭客，乘閒還許再來否。"]'),
('bd5a9a16-2bb1-4541-9ecb-8db480fc6480','望洞陽','蔡宰','宋','宋诗','song-poetry','','[]','歲事今無幾，清霜苦見侵。',48,'全唐诗/poet.song.124000.json','["歲事今無幾，清霜苦見侵。", "寒深落雁渚，風急搗衣砧。", "翠縠紋秋水，斑綃纈霧林。", "洞陽棲隠地，樓觀白雲深。"]'),
('a5043f65-5a18-40c0-80dc-e4fe6b3e9a54','絕句','燕照鄰','宋','宋诗','song-poetry','','[]','女矮兒癡十口餘，進時無業退無廬。',32,'全唐诗/poet.song.124000.json','["女矮兒癡十口餘，進時無業退無廬。", "一窗風雪韓城夜，火冷燈青照舊書。"]'),
('740c7b84-84f2-49df-be93-8c5cc43e7f4e','次韻張晉彥秋日','王從','宋','宋诗','song-poetry','','[]','地迥高樓目，天寒故國心。',48,'全唐诗/poet.song.124000.json','["地迥高樓目，天寒故國心。", "江鷗無萬里，雲木自千尋。", "門掩斜陽下，人歸落葉深。", "風前悵何許，入耳越鄉吟。"]'),
('f3900805-032b-4ec8-8673-84dd40581d42','句  其一','王從','宋','宋诗','song-poetry','','[]','落木森猶力，寒山淡欲無。',12,'全唐诗/poet.song.124000.json','["落木森猶力，寒山淡欲無。"]'),
('077fca86-c36e-47a6-ae56-e641fe4a7911','句  其二','王從','宋','宋诗','song-poetry','','[]','凉風回遠笛，暝色带歸舟。',12,'全唐诗/poet.song.124000.json','["凉風回遠笛，暝色带歸舟。"]'),
('d2709aa9-2b18-45b3-8e33-b01b6bd77aca','句  其三','王從','宋','宋诗','song-poetry','','[]','塵心依水凈，歸鬢與山青。',12,'全唐诗/poet.song.124000.json','["塵心依水凈，歸鬢與山青。"]'),
('6599cd74-88e4-4455-b168-8c0860c15b53','句  其四','王從','宋','宋诗','song-poetry','','[]','墮蕊盡教輸燕子，嫩寒猶及占梨花。',16,'全唐诗/poet.song.124000.json','["墮蕊盡教輸燕子，嫩寒猶及占梨花。"]'),
('95089a6a-f611-4515-b9ac-b20ac87bcc97','句  其五','王從','宋','宋诗','song-poetry','','[]','一番風雨催寒食，千里鶑花想故園。',16,'全唐诗/poet.song.124000.json','["一番風雨催寒食，千里鶑花想故園。"]'),
('02335698-2ecc-4ef8-b55e-b1ac2a419eb7','句  其六','王從','宋','宋诗','song-poetry','','[]','身閑更得憑陵酒，花早殊非愛惜春。',16,'全唐诗/poet.song.124000.json','["身閑更得憑陵酒，花早殊非愛惜春。"]'),
('e9e6f8a3-b7ac-4737-8c3a-4044aea890d7','句  其七','王從','宋','宋诗','song-poetry','','[]','秋生列岫雲尤薄，泉漱懸崖路更慳。',16,'全唐诗/poet.song.124000.json','["秋生列岫雲尤薄，泉漱懸崖路更慳。"]'),
('049091b2-fdd5-48b8-bc1c-d15e31766eef','句  其八','王從','宋','宋诗','song-poetry','','[]','臨春慘不舒，蓋國空自香。',12,'全唐诗/poet.song.124000.json','["臨春慘不舒，蓋國空自香。"]'),
('1f36cc1d-301c-44df-a4d7-598e879c295b','第一山','顔師魯','宋','宋诗','song-poetry','','[]','聞說淮南第一山，老來方此憑欄干。',32,'全唐诗/poet.song.124000.json','["聞說淮南第一山，老來方此憑欄干。", "孤城不隔長安望，落日空悲汴水寒。"]'),
('2805a93d-914a-40b9-ae2d-cff67bb52dc3','瓊花','顔師魯','宋','宋诗','song-poetry','','[]','后土祠中二月暮，瓊花放後有蜂來。',32,'全唐诗/poet.song.124000.json','["后土祠中二月暮，瓊花放後有蜂來。", "東君不怕春歸去，留待詩人一夜開。"]'),
('5e3a55c5-ac4b-4ba7-ae93-36faace22d73','天開圖畫亭','王正己','宋','宋诗','song-poetry','','[]','夜來殘暑鏖西風，秋聲摵摵先井桐。',176,'全唐诗/poet.song.124000.json','["夜來殘暑鏖西風，秋聲摵摵先井桐。", "纖雲四捲天開容，一碧萬里磨青銅。", "使君退食新凉逢，厭看凝寢江雲濃。", "領客欲送孤飛鴻，城隅高亭濕青紅。", "曠望四野開心胸，前瞻江山勝而雄。", "瑠璃波光群玉峰，水墨正爾難爲工。", "天開地闢今古中，此景自若無初終。", "天豈爲我施新功，我心得之眼相從。", "收入几席無遺蹤，錦囊得助防詩窮。", "向來神秀造化鍾，李成郭熙將無同。", "强名圖畫託天公，撫掌一笑浮金鍾。"]'),
('0c341185-3f34-406f-97be-9bb7b7eab458','九侯山神詩','蔡如松','宋','宋诗','song-poetry','','[]','誰言少康真禹子，子孫九人流到此。',256,'全唐诗/poet.song.124000.json','["誰言少康真禹子，子孫九人流到此。", "誰言鬼侯遭紂虐，冤魄至今靈故壘。", "誕哉二說太荒唐，未識根原有初始。", "我曾南自五羊回，杖屨空山問遺址。", "數間古屋傍林巒，一簇偶人皆劍履。", "斷碑仆地蒼蘚沒，滿庭落葉秋風起。", "歲時伏臘走村翁，醵錢買酒烹羊豕。", "粵巫擊鼓細吹角，整日歌呼乞新祉。", "饑烏攫肉舞盤間，野蝶尋馨投盞裏。", "愚民驚怪相駭誕，巧囀笙簧縈俗耳。", "那知三代去已遠，鬼神豈肯歆非祀。", "漳川遐僻在窮閩，北去中州幾萬里。", "從來不及風馬牛，廟食胡爲而至是。", "濫觴曲士妄穿鑿，湍激妖狐因倚恃。", "噓烟吹霧作精變，歷古冥冥無辨理。", "何當濟會狄梁公，爲我乘時皆斥毀。"]'),
('84dd7a27-aa9e-4a44-9842-53a762690b68','國師南巖詩','蔡如松','宋','宋诗','song-poetry','','[]','七閩山秀江逾碧，俗知禮義亡姦慝。',256,'全唐诗/poet.song.124000.json','["七閩山秀江逾碧，俗知禮義亡姦慝。", "賊潮何事率淮民，擁衆南來稍蠶食。", "椎埋却冢荒徑裏，醉飽呼天爛漁弋。", "孽駒躡迹逞神怪，河海波騰雲潑墨。", "門開啟聖像雙闕，臺築三清伴紫極。", "一朝春燕飛入宮，九龍帳底生荆棘。", "舉宗屠肆血腥穢，骸骨無人坎墳域。", "群凶睨目暗招邀，起火狐鳴乘月黑。", "雪峯禪客漏遺種，物色漳川俄訪得。", "蘆黄葦白秋風多，欲話辛酸語還塞。", "易衣傳入虎狼口，翻覆死生難可測。", "至今尚餘下輦處，巧作妖言相誕惑。", "我曾親到國師巖，父老頗能爲記憶。", "吐冤戟手駡從效，陰與群姦爲羽翼。", "孤僧逼將上車去，水石含悲空寂默。", "唯有霜鍾音韻清，破寒千里傳消息。"]'),
('11ba8ff5-b66b-4ef8-98b8-0b769781c907','君山','王濯','宋','宋诗','song-poetry','','[]','無際波光滉太虛，君山一點暮雲孤。',32,'全唐诗/poet.song.124000.json','["無際波光滉太虛，君山一點暮雲孤。", "危樓欄檻能多少，展盡江湖萬里圖。"]'),
('54747be7-29b6-4c85-a26a-ca7eaaf517b2','清都觀','王濯','宋','宋诗','song-poetry','','[]','天上清都人莫到，山間仙觀久荒凉。',32,'全唐诗/poet.song.124000.json','["天上清都人莫到，山間仙觀久荒凉。", "惟余舊浴丹砂井，一酌猶令齒頰香。"]'),
('28b14adc-c502-416e-81ca-8c538916c8c6','句','王濯','宋','宋诗','song-poetry','','[]','絕壁高千丈，清泉應六時。',12,'全唐诗/poet.song.124000.json','["絕壁高千丈，清泉應六時。"]'),
('aae14c4b-aae3-4644-a3fe-f44188a84082','題凌歊臺','莊革','宋','宋诗','song-poetry','','[]','姑孰溪邊霜葉飛，凌歊臺上暮雲歸。',32,'全唐诗/poet.song.124000.json','["姑孰溪邊霜葉飛，凌歊臺上暮雲歸。", "謫仙一去不復返，悵望青山空翠微。"]'),
('78a0c013-f671-4cc7-9e64-bb957c565084','瓊花','鄭良嗣','宋','宋诗','song-poetry','','[]','玉立祠庭久不衰，俄經剪伐重能栽。',64,'全唐诗/poet.song.124000.json','["玉立祠庭久不衰，俄經剪伐重能栽。", "端知妙護有神力，更喜當時殲厥魁。", "種不他傳焉得子，年將豐稔輒多開。", "天生異物初無伴，只許翻階近侍來。"]'),
('40eae19a-558b-47b9-9cc7-6ba994392013','蒼嶺','杜師旦','宋','宋诗','song-poetry','','[]','休嗟道險未堪行，却到層巒足較輕。',32,'全唐诗/poet.song.124000.json','["休嗟道險未堪行，却到層巒足較輕。", "山險還如心險否，心平履險險仍平。"]'),
('aa6f1972-8f0b-45c3-92f9-68bfb189b09b','大滌洞天留題  其一','趙崇渭','宋','宋诗','song-poetry','','[]','福地天然號洞霄，王畿密邇路非遥。',64,'全唐诗/poet.song.124000.json','["福地天然號洞霄，王畿密邇路非遥。", "淡濃翠碧山重列，圓碎珠璣泉一條。", "九鎖真成仙境勝，借行頓使客愁銷。", "超凡得道從茲始，未減金華王子喬。"]'),
('c1774f31-ea31-45a2-abc1-2220f0a22d1e','大滌洞天留題  其二','趙崇渭','宋','宋诗','song-poetry','','[]','一到琳宮事事幽，炎天正好暫時留。',32,'全唐诗/poet.song.124000.json','["一到琳宮事事幽，炎天正好暫時留。", "鶴仙共此泉流樂，氣象全勝白鷺洲。"]'),
('3ceac0a6-fdb7-4590-8db4-06b2360c0a26','春暖','趙崇森','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春晴多得兩三日，便覺暄于輕暑天。',64,'全唐诗/poet.song.124000.json','["春晴多得兩三日，便覺暄于輕暑天。", "行客停鞭爭買扇，侍兒啟笥請收綿。", "把杯早自嫌溫酒，盥手相將喜冷泉。", "此去西湖已初夏，安排絺綌上游船。"]'),
('70100cfe-1c8e-40a8-8d3c-33c04d74cd3b','久旱喜雨','趙崇森','宋','宋诗','song-poetry','','[]','五月炎歊化作霖，分明滴滴是黄金。',64,'全唐诗/poet.song.124000.json','["五月炎歊化作霖，分明滴滴是黄金。", "田禾預卜六分熟，河水新添一尺深。", "和氣已能周禹甸，至誠端自感湯林。", "此時此澤人知否，大慰饑民望歲心。"]'),
('e4e97e79-268c-4fe0-be7e-8d451873408b','玩秋月','趙崇森','宋','宋诗','song-poetry','','[]','玉宇秋光無一塵，人人共喜桂花新。',32,'全唐诗/poet.song.124000.json','["玉宇秋光無一塵，人人共喜桂花新。", "看來世態炎凉盡，惟有月明無貴貧。"]'),
('f290c48c-9da7-4f9c-9208-b5307b227c3e','漏屋雨','趙崇森','宋','宋诗','song-poetry','','[]','官屋無錢可得修，雨來難免震凌憂。',64,'全唐诗/poet.song.124000.json','["官屋無錢可得修，雨來難免震凌憂。", "牆基有罅相將踣，地杖無釘自在浮。", "僕折松枝通夾溜，兒編竹葉學行舟。", "衣衾漂濕渾閑事，且上書樓把畫收。"]'),
('16f6cb7f-1638-4022-96b1-4edf69baef88','春雨','趙崇森','宋','宋诗','song-poetry','','[]','連朝連夜雨，春盡轉瀟瀟。',48,'全唐诗/poet.song.124000.json','["連朝連夜雨，春盡轉瀟瀟。", "巷陌泥沾足，田疇水侵腰。", "麥黄皆倒穗，桑凍不抽條。", "花事今休矣，祈晴且救苗。"]'),
('ace29e9e-43dc-41b0-a00c-0b2814006320','雪','趙崇森','宋','宋诗','song-poetry','','[]','今年寒較早，十月雪霏霏。',48,'全唐诗/poet.song.124000.json','["今年寒較早，十月雪霏霏。", "冰渚魚深逝，風林鳥倦飛。", "家人催買炭，客子慮無衣。", "便好騎馿過，羊羔酒正肥。"]'),
('288113be-4a0d-46b1-b86c-ccb078f8725c','江行','趙崇森','宋','宋诗','song-poetry','','[]','貪看湘江景，蓬窗手自捫。',48,'全唐诗/poet.song.124000.json','["貪看湘江景，蓬窗手自捫。", "沙陳鳥行迹，石带水流痕。", "大樹多遮廟，疏林間有村。", "蘆花自彌望，消得酒盈尊。"]'),
('a55a3f16-30ac-407c-a476-22199acc55dc','琴','趙崇森','宋','宋诗','song-poetry','','[]','群胥推案去，一客抱琴來。',48,'全唐诗/poet.song.124000.json','["群胥推案去，一客抱琴來。", "喚起高山趣，驅除俗吏埃。", "耳根從此凈，指法看君開。", "剩欲傳佳操，仙舟且莫回。"]'),
('fd8df3d6-92d2-494e-9c5e-62ab0d876aaa','椰簟','趙崇森','宋','宋诗','song-poetry','','[]','贈子椰心簟，波紋細欲流。',48,'全唐诗/poet.song.124000.json','["贈子椰心簟，波紋細欲流。", "來浮南海遠，好伴浙西游。", "睡處知溫凊，行時便卷收。", "不知風雨夜，能憶故人不。"]'),
('d5ce1b0b-ec29-41cf-80a3-68fd0dc623ca','砧','趙崇森','宋','宋诗','song-poetry','','[]','誰家夜月響秋砧，一段清愁不自禁。',32,'全唐诗/poet.song.124000.json','["誰家夜月響秋砧，一段清愁不自禁。", "况是客中欹枕聽，聲聲搗碎故鄉心。"]'),
('bbda6fe5-046a-4369-8b3c-d0ec052ec866','隠逸','趙崇森','宋','宋诗','song-poetry','','[]','懶散數椽下，于人無所求。',48,'全唐诗/poet.song.124000.json','["懶散數椽下，于人無所求。", "靜觀棋得趣，閑坐石忘憂。", "對酒紅生頰，孤吟白上頭。", "高山有佳趣，便欲作清游。"]'),
('721117ef-5ae6-434d-bb10-27954d37ca7d','題三女岡白蓮花','趙崇森','宋','宋诗','song-poetry','','[]','舊址來從晉，史更幾廢興。',48,'全唐诗/poet.song.124000.json','["舊址來從晉，史更幾廢興。", "一蓮開陸地，三女卧岡陵。", "題詠誇先輩，流傳得主僧。", "林深鐘梵寂，長夜一明燈。"]'),
('270e3e31-336c-44d3-9494-c3b231ab0e67','梅巖  其一','趙崇釠','宋','宋诗','song-poetry','','[]','嵌空天影落元間，更著梅花迥莫攀。',32,'全唐诗/poet.song.124000.json','["嵌空天影落元間，更著梅花迥莫攀。", "休說橫斜欠清淺，此巖正不減孤山。"]'),
('ce652269-1f79-434d-ab0c-0f95267c8186','梅巖  其二','趙崇釠','宋','宋诗','song-poetry','','[]','梅花應只在巖間，無奈官身不可攀。',32,'全唐诗/poet.song.124000.json','["梅花應只在巖間，無奈官身不可攀。", "幾度句中尋夜佛，鉅靈安得爲移山。"]'),
('74dc5a62-6549-4c8f-8ea5-fb7edae541ac','龍潭寺','趙崇傑','宋','宋诗','song-poetry','','["\u897f\u6e56"]','欲覓龍潭何處是，青山影裏見浮圖。',64,'全唐诗/poet.song.124000.json','["欲覓龍潭何處是，青山影裏見浮圖。", "紅蕖映日真花藏，碧水涵天瑩玉壺。", "已放源流通北海，未饒風物說西湖。", "侍中菴外多閑地，容我他年卜築無。"]'),
('8649a61c-2ab2-43cf-bd2e-2df0051d3226','進詩','皇甫坦','宋','宋诗','song-poetry','','[]','夜靜天中星歷歷，曉來壇上月娟娟。',32,'全唐诗/poet.song.124000.json','["夜靜天中星歷歷，曉來壇上月娟娟。", "皇圖鞏固中興業，帝祚遐昌億萬年。"]'),
('2b28da63-4119-46c4-803e-64473b912313','句','皇甫坦','宋','宋诗','song-poetry','','[]','每蒙天一笑，遂與物爲春。',12,'全唐诗/poet.song.124000.json','["每蒙天一笑，遂與物爲春。"]'),
('a0c47204-cf95-4f24-a3b6-903e31520ef2','丁香','洪遵','宋','宋诗','song-poetry','','[]','來自丁香國，還應世所稀。',48,'全唐诗/poet.song.124000.json','["來自丁香國，還應世所稀。", "叢生盛枝葉，亂結罥中衣。", "冷艷瓊爲色，低枝翠作圍。", "蔓連疑鎖骨，時見玉塵飛。"]'),
('6bf0fc75-97df-4a93-a7e3-ec90fba58544','和弟景盧月臺詩','洪遵','宋','宋诗','song-poetry','','[]','築臺結閣兩爭華，便覺流涎過麴車。',32,'全唐诗/poet.song.124000.json','["築臺結閣兩爭華，便覺流涎過麴車。", "戶小難禁竹葉酒，睡多須藉菊苗茶。"]'),
('59ecf036-a218-4b1b-8c12-24942e7891d5','憶西湖','洪遵','宋','宋诗','song-poetry','','["\u897f\u6e56"]','憶昔西湖上，芳醪手自斟。',48,'全唐诗/poet.song.124000.json','["憶昔西湖上，芳醪手自斟。", "龜游低芰亂，魚闖小萍沉。", "意遠山猶迥，心清水共深。", "三秋未許見，聊向夢中尋。"]'),
('6482de34-cec4-4fe1-aa6d-961e90241f63','次韻相兄舫齋詩二首  其一','洪遵','宋','宋诗','song-poetry','','[]','長年三老漫良圖，何用西風十幅蒲。',32,'全唐诗/poet.song.124000.json','["長年三老漫良圖，何用西風十幅蒲。", "四壁煙光長在眼，公知杖屨有江湖。"]'),
('014d50bc-62f6-4a11-9d39-1065b32c7e3d','次韻相兄舫齋詩二首  其二','洪遵','宋','宋诗','song-poetry','','[]','浮家泛宅古無多，只有高人張志和。',32,'全唐诗/poet.song.124000.json','["浮家泛宅古無多，只有高人張志和。", "心似虛舟元不繫，泊然聊與世同波。"]'),
('bb5efde6-8e06-494b-99b6-76be3aae505d','洛花不望而至次相兄韻','洪遵','宋','宋诗','song-poetry','','[]','多謝吳中客，移花五畝園。',48,'全唐诗/poet.song.124000.json','["多謝吳中客，移花五畝園。", "灰心勞遠夢，繭足蹈前言。", "定是黄金蕊，真須白玉尊。", "從今付幽賞，不用賦招魂。"]'),
('d5073b77-3dd7-4db1-bf8c-862ed85c2adc','王世英秀才出示曾卿詩求和','洪遵','宋','宋诗','song-poetry','','[]','投筆文章壯志休，鳥經鶴訓漫心留。',64,'全唐诗/poet.song.124000.json','["投筆文章壯志休，鳥經鶴訓漫心留。", "若爲一見開青眼，解使三公出黑頭。", "望隴自應知可否，折潮須信妙源流。", "夜光明月無虛售，可忍庸人按劍求。"]'),
('0decf6a0-327b-4509-bc40-3f0332b311b9','漢詔郡縣行鄉飲酒禮頌詩  其一','洪遵','宋','宋诗','song-poetry','','[]','天生蒸民，曷其有識。',20,'全唐诗/poet.song.124000.json','["天生蒸民，曷其有識。", "維聖摩勵，規閑矩飭。"]'),
('f88d0353-e12b-4c55-b593-47bff4497874','漢詔郡縣行鄉飲酒禮頌詩  其二','洪遵','宋','宋诗','song-poetry','','[]','陽禮教遜，誥誓上儀。',20,'全唐诗/poet.song.124000.json','["陽禮教遜，誥誓上儀。", "降周迄秦，淟涊弗治。"]'),
('4a3da2a9-3472-4ff6-8570-8522b88bae92','漢詔郡縣行鄉飲酒禮頌詩  其三','洪遵','宋','宋诗','song-poetry','','[]','斤斤顯宗，黼黻王度。',20,'全唐诗/poet.song.124000.json','["斤斤顯宗，黼黻王度。", "三宮孔陽，精意治具。"]'),
('642e6a22-a6bf-4d0a-b002-b988cc5e794b','漢詔郡縣行鄉飲酒禮頌詩  其四','洪遵','宋','宋诗','song-poetry','','[]','爰勑方國，禮行于鄉。',20,'全唐诗/poet.song.124000.json','["爰勑方國，禮行于鄉。", "稽經諏律，屬民橫堂。"]'),
('4281e3e4-9af7-4219-8ffa-ef82d1d6516d','漢詔郡縣行鄉飲酒禮頌詩  其五','洪遵','宋','宋诗','song-poetry','','[]','先聖嚴嚴，拜跪薦祭。',20,'全唐诗/poet.song.124000.json','["先聖嚴嚴，拜跪薦祭。", "冠纓莘莘，鱗差櫛比。"]'),
('05b36563-8f84-409d-acdf-4fec81e91b32','漢詔郡縣行鄉飲酒禮頌詩  其六','洪遵','宋','宋诗','song-poetry','','[]','迺速庠門，迺潔東榮。',20,'全唐诗/poet.song.124000.json','["迺速庠門，迺潔東榮。", "賓主僎介，堪輿是程。"]'),
('6dc97571-8d2f-493e-8b6a-fec73398e001','漢詔郡縣行鄉飲酒禮頌詩  其七','洪遵','宋','宋诗','song-poetry','','[]','笙流觶揚，少長位辨。',20,'全唐诗/poet.song.124000.json','["笙流觶揚，少長位辨。", "已事而竣，不誡用勸。"]'),
('d6757796-c106-4612-a673-1ed99c0a1b6f','漢詔郡縣行鄉飲酒禮頌詩  其八','洪遵','宋','宋诗','song-poetry','','[]','詠仁蹈德，駸駸措刑。',20,'全唐诗/poet.song.124000.json','["詠仁蹈德，駸駸措刑。", "舄弈千載，薰爲太平。"]'),
('6394f0ed-d48b-47a4-a41d-982117f26db2','漢詔郡縣行鄉飲酒禮頌詩  其九','洪遵','宋','宋诗','song-poetry','','[]','乾清坤夷，軒豁呈露。',20,'全唐诗/poet.song.124000.json','["乾清坤夷，軒豁呈露。", "萬祥畢溱，登三咸五。"]'),
('d2c40b21-bfda-4f47-ac79-fb5c2788176a','漢詔郡縣行鄉飲酒禮頌詩  其一○','洪遵','宋','宋诗','song-poetry','','[]','昔在建武，大聖載營。',20,'全唐诗/poet.song.124000.json','["昔在建武，大聖載營。", "有臣曰湛，示我漢行。"]'),
('dcbe7f0d-a533-42fe-a6aa-59c6eabc27db','漢詔郡縣行鄉飲酒禮頌詩  其一一','洪遵','宋','宋诗','song-poetry','','[]','緜蕝無傳，莫克用人。',20,'全唐诗/poet.song.124000.json','["緜蕝無傳，莫克用人。", "孰播其馨，孝明是似。"]'),
('c02139a9-78e2-4275-8584-25beae32725b','漢詔郡縣行鄉飲酒禮頌詩  其一二','洪遵','宋','宋诗','song-poetry','','[]','允哉帝德，侯其偉而。',20,'全唐诗/poet.song.124000.json','["允哉帝德，侯其偉而。", "矢詩不多，維後之詒。"]'),
('85914370-c904-4493-9cf1-dda3b718c87e','送樞密相公樓仲暉歸田','周因','宋','宋诗','song-poetry','','[]','雲水茫茫慘別情，悲風吹樹作離聲。',64,'全唐诗/poet.song.124000.json','["雲水茫茫慘別情，悲風吹樹作離聲。", "酒傾銀斚臨江滸，潮落沙汀带月明。", "千里綠煙芳草合，一天囗雨落花輕。", "老予對景成三嘆，不覺潸然淚雨傾。"]'),
('e7c90861-a34f-4708-8e63-16bad5d4528a','句','周因','宋','宋诗','song-poetry','','[]','一網多收泮水英。',8,'全唐诗/poet.song.124000.json','["一網多收泮水英。"]'),
('92728e37-6cf8-489d-a6e3-84e656ff3652','送左彥武歸鄉','魏杞','宋','宋诗','song-poetry','','[]','折桂歸來日，西風萬里秋。',48,'全唐诗/poet.song.124000.json','["折桂歸來日，西風萬里秋。", "錦衣天上客，紅葉渡頭舟。", "把酒難爲別，題詩更欲留。", "明朝山水隔，何日是重遊。"]'),
('08dd64e8-f413-4aca-b213-eb34f68a5f24','次韵送汪尚書致政還鄉','魏杞','宋','宋诗','song-poetry','','[]','諸賢投紱孟前期，愧我需章獨厚時。',64,'全唐诗/poet.song.124000.json','["諸賢投紱孟前期，愧我需章獨厚時。", "勉徇禮經聊弭謗，敢貪榮祿計遷資。", "歸兮陶令惟三徑，去矣君嚴有二宜。", "處世功勳忘厚饗，人生知止要能知。"]'),
('75814943-49d7-45ba-b6de-6886eb377a27','到巖豅寺勸農','魏杞','宋','宋诗','song-poetry','','[]','王事忽來此，今朝天氣新。',48,'全唐诗/poet.song.124000.json','["王事忽來此，今朝天氣新。", "溪山渾是句，樽酒可無人。", "幽鳥空驚夢，殘花不當春。", "飄然又歸去，明月滿衣巾。"]'),
('da65e1e8-818f-447b-b504-9e73d509d9aa','欲飯野人家見拒甚力','魏杞','宋','宋诗','song-poetry','','[]','山崦筠車轉屈蟠，欲尋野店具盤餐。',64,'全唐诗/poet.song.124000.json','["山崦筠車轉屈蟠，欲尋野店具盤餐。", "主人變色行蠶忌，客子包羞坐虱官。", "早見此生真寄寓，更知行役是艱難。", "逡巡攬袂來旁舍，曉月朦朧春夢殘。"]'),
('18d8fe55-d6d1-4729-8dd6-a2ab74d79a77','送吳僉判之官濠州','魏杞','宋','宋诗','song-poetry','','[]','舉觴屬明月，送君江上舟。',120,'全唐诗/poet.song.124000.json','["舉觴屬明月，送君江上舟。", "王事知有程，翩然不可留。", "濠梁古佳郡，觀魚記莊周。", "年來邊徼清，桑麻被田疇。", "有詔蠲民租，拊摸頼郡侯。", "樂入芙蓉幕，君其贊嘉猷。", "僉曹簿領餘，拄頰興未休。", "淮山千萬疊，丐君回青眸。", "才命各有時，行止非人謀。", "主公方拔士，入奉甘泉遊。"]'),
('8f9e0637-689d-4027-8c03-e617b42f6178','送袁朝奉芳秩滿趨朝','魏杞','宋','宋诗','song-poetry','','[]','壯年鼓篋上神京，歎息驚人未一鳴。',64,'全唐诗/poet.song.124000.json','["壯年鼓篋上神京，歎息驚人未一鳴。", "白髮尚堪談世事，青衫原不墜詩名。", "簿書堆案三年夢，風月張帆午夜程。", "去矣飛騰九霄上，莫忘瞻衮話平生。"]'),
('38860117-eaa7-4910-991d-b6f1df3d3500','延慶寺','魏杞','宋','宋诗','song-poetry','','[]','開山何日事，斷碣卧荒榛。',48,'全唐诗/poet.song.124000.json','["開山何日事，斷碣卧荒榛。", "食盡僧行脚，兵來佛捨身。", "燒痕侵殿址，租額累山鄰。", "可是天魔盛，誰能問大鈞。"]'),
('bb3d2fbe-c752-4b09-a3a8-9eee73dd5ab3','偈頌十首  其一','釋曇密','宋','宋诗','song-poetry','','[]','一二三四五，金木水火土。',48,'全唐诗/poet.song.124000.json','["一二三四五，金木水火土。", "拾得語寒山，豐干騎老虎。", "報君知，莫莽鹵。", "從來保福四謾人，不似禾山解打鼓。"]'),
('811251c6-9880-42cb-8f46-2114ad51c076','偈頌十首  其二','釋曇密','宋','宋诗','song-poetry','','[]','五祖箇老翁，從來多指注。',24,'全唐诗/poet.song.124000.json','["五祖箇老翁，從來多指注。", "不是不知歸，忘却來時路。"]'),
('39c5bbf0-db85-42b6-941d-3919561793fa','偈頌十首  其三','釋曇密','宋','宋诗','song-poetry','','[]','連緜雨不晴，穀子多損失。',55,'全唐诗/poet.song.124000.json','["連緜雨不晴，穀子多損失。", "二麥未入泥，憂心常惕惕。", "來歲不饑荒，未敢相委悉。", "啟告梵天帝釋天玉皇大帝天，且放日頭出。"]'),
('af62e4b7-e8ba-468f-9283-f24cb282e0be','偈頌十首  其四','釋曇密','宋','宋诗','song-poetry','','[]','春日晴，黄鶑鳴，更聽斷崖流水聲。',34,'全唐诗/poet.song.124000.json','["春日晴，黄鶑鳴，更聽斷崖流水聲。", "青山疊翠，款步作程，歸來煙島有誰爭。"]'),
('d0132801-9a30-450e-880c-9d639a8e35ec','偈頌十首  其五','釋曇密','宋','宋诗','song-poetry','','[]','即心即佛，非心非佛。',70,'全唐诗/poet.song.124000.json','["即心即佛，非心非佛。", "不是心，不是佛，不是物，半夜虛空揣出骨。", "十分描摸畫難成，試問諸人是何物。", "阿呵呵，咄咄咄。", "拶倒門前大案山，搏風放出遼天鶻。"]'),
('285d0b92-0c5c-4468-b3e1-148044af8e2c','偈頌十首  其六','釋曇密','宋','宋诗','song-poetry','','[]','一身浪宕無拘撿，閙市門頭恣意遊。',79,'全唐诗/poet.song.124000.json','["一身浪宕無拘撿，閙市門頭恣意遊。", "漢地不收秦不管，不風流處也風流。", "健則坐，困則休，信任從教雪滿頭。", "寄語宣和政和元和佛陀，張僧伽李達磨，老聃孔丘，照顧溈山水牯牛。"]'),
('9bb72661-9c76-4f9d-8215-e15041700c5e','偈頌十首  其七','釋曇密','宋','宋诗','song-poetry','','[]','豈弟張夫子，遺我徑寸璧。',24,'全唐诗/poet.song.124000.json','["豈弟張夫子，遺我徑寸璧。", "中有數箇字，字字無人識。"]'),
('c11e2190-fb64-4c42-a7b3-74c78d767823','偈頌十首  其八','釋曇密','宋','宋诗','song-poetry','','[]','菩提妙心作麽發，日應萬機元不差。',32,'全唐诗/poet.song.124000.json','["菩提妙心作麽發，日應萬機元不差。", "回首瞥然輕覷著，大千沙界是皇家。"]'),
('d1971005-89da-4330-9cc5-a237447ae208','偈頌十首  其九','釋曇密','宋','宋诗','song-poetry','','[]','咄這花木瓜，苦澁無以加。',48,'全唐诗/poet.song.124000.json','["咄這花木瓜，苦澁無以加。", "驀然嚼得碎，清風生齒牙。", "種性惡，不堪誇。", "楊岐老馿三隻脚，蹋人無數滿天涯。"]'),
('1b98a639-9953-40cb-8e14-1163f9d18161','偈頌十首  其一○','釋曇密','宋','宋诗','song-poetry','','[]','湖山疊亂青，湖水漾虛碧。',36,'全唐诗/poet.song.124000.json','["湖山疊亂青，湖水漾虛碧。", "斷岸蓼花紅，疎林秋露滴。", "良哉觀世音，處處失彌勒。"]'),
('b576f2c9-107d-4f35-8820-9c1798a0a970','頌古二首  其一','釋曇密','宋','宋诗','song-poetry','','[]','塞北平沙闊，黄河衮底流。',24,'全唐诗/poet.song.124000.json','["塞北平沙闊，黄河衮底流。", "征帆纔及岸，蠻狄一時收。"]'),
('d0083b4b-4863-4588-b47b-9021274ab84d','頌古二首  其二','釋曇密','宋','宋诗','song-poetry','','[]','汲水僧歸林下寺，待船人立渡頭沙。',32,'全唐诗/poet.song.124000.json','["汲水僧歸林下寺，待船人立渡頭沙。", "澄江渺渺煙波窄，雲靜一天星斗斜。"]'),
('a7a8ea0d-5f58-4b94-a223-c48781b03a5a','數珠','釋曇密','宋','宋诗','song-poetry','','[]','百八摩尼顆顆圓，遼天鼻孔一時穿。',32,'全唐诗/poet.song.124000.json','["百八摩尼顆顆圓，遼天鼻孔一時穿。", "恒河沙數佛菩薩，日日呼來跳一圈。"]'),
('3edac72f-8bdd-4f78-8876-257b0d102da7','頌古','釋曇密','宋','宋诗','song-poetry','','[]','平地摝魚蝦，遼天射飛鶚。',24,'全唐诗/poet.song.124000.json','["平地摝魚蝦，遼天射飛鶚。", "跛脚老雲門，千錯與萬錯。"]'),
('b26e7fb5-1572-4efb-8bf6-83d95a2c4bd0','頌古','釋曇密','宋','宋诗','song-poetry','','[]','崔顥曾題黄鶴樓，長沙拈起當風流。',32,'全唐诗/poet.song.124000.json','["崔顥曾題黄鶴樓，長沙拈起當風流。", "大千國土俱家業，諸佛何曾有地頭。"]'),
('1d05fea4-f435-42e7-abab-be9e6a026154','舉趙州勘婆話頌','釋賢','宋','宋诗','song-poetry','','[]','冰雪佳人貌最奇，常將玉笛向人吹。',32,'全唐诗/poet.song.124000.json','["冰雪佳人貌最奇，常將玉笛向人吹。", "曲中無限花心動，獨許東君第一枝。"]'),
('003b1036-d19b-4c53-a816-e65d535e9a79','舉罽賓國王問師子尊者藴空公案頌','釋鑑','宋','宋诗','song-poetry','','[]','尊者何曾得藴空，罽賓徒自斬春風。',32,'全唐诗/poet.song.124000.json','["尊者何曾得藴空，罽賓徒自斬春風。", "桃花雨後已零落，染得一溪流水紅。"]'),
('a6f060f8-c8c3-4e76-ade4-46d5e68f49a5','偈三首  其一','釋祖珠','宋','宋诗','song-poetry','','[]','機前一句子，用處不留情。',24,'全唐诗/poet.song.124000.json','["機前一句子，用處不留情。", "如撞幢子弩，箭箭中紅心。"]'),
('550abf7f-df79-437a-ab9a-5551ee6d73e8','偈三首  其二','釋祖珠','宋','宋诗','song-poetry','','[]','不是心，不是佛，不是物。',74,'全唐诗/poet.song.124000.json','["不是心，不是佛，不是物。", "瀝盡野狐涎，趯翻山鬼窟。", "平田淺草裏，露出焦尾大蟲。", "太虛寥廓中，放出遼天俊鶻。", "阿呵呵，露風骨。", "等閑拈出衆人前，畢竟分明是何物。"]'),
('7e56c8dd-9172-4f13-bedd-82b9a61c079f','偈三首  其三','釋祖珠','宋','宋诗','song-poetry','','[]','玉露垂青草，金風動白蘋。',24,'全唐诗/poet.song.124000.json','["玉露垂青草，金風動白蘋。", "一聲寒雁叫，喚起未惶人。"]'),
('54995b29-a12d-4f3f-9e88-d24a06ca83b4','題出山相','釋祖珠','宋','宋诗','song-poetry','','[]','半夜逾城往雪山，龍樓鳳閣絕躋攀。',32,'全唐诗/poet.song.124000.json','["半夜逾城往雪山，龍樓鳳閣絕躋攀。", "如今輥出草窠裏，一箇閑人天地間。"]'),
('d7bc524b-47d1-4088-a582-69bc984ebd7d','自贊','釋祖珠','宋','宋诗','song-poetry','','[]','月色照幽谷，泉聲落斷崖。',24,'全唐诗/poet.song.124000.json','["月色照幽谷，泉聲落斷崖。", "水光山色裏，一塊爛枯柴。"]'),
('6c6f4425-7176-432d-b9ef-c09897adc1fc','聽講圓覺經有省作頌','釋真慈','宋','宋诗','song-poetry','','[]','一顆明珠，在我這裏。',20,'全唐诗/poet.song.124000.json','["一顆明珠，在我這裏。", "撥著動著，放光動地。"]'),
('d50ac073-01be-45d8-9d24-2a60fd318a9e','頌','釋真慈','宋','宋诗','song-poetry','','[]','撥塵見佛，佛亦是塵。',20,'全唐诗/poet.song.124000.json','["撥塵見佛，佛亦是塵。", "問了答了，直下翻身。"]'),
('2b8bab7d-d107-4ec3-8b9e-2443f123aa00','頌塵塵三昧','釋真慈','宋','宋诗','song-poetry','','[]','鉢裏飯，桶裏水，別寶崑崙坐潭底。',44,'全唐诗/poet.song.124000.json','["鉢裏飯，桶裏水，別寶崑崙坐潭底。", "一塵塵上走須彌，明眼波斯笑彈指。", "笑彈指，珊瑚枝上清風起。"]'),
('597e1399-8790-486b-8245-cf1c81947089','舉俱胝豎指因緣頌','釋法演','宋','宋诗','song-poetry','','[]','佳人睡起懶梳頭，把得金釵插便休。',32,'全唐诗/poet.song.124000.json','["佳人睡起懶梳頭，把得金釵插便休。", "大抵還他肌骨好，不涂紅粉也風流。"]'),
('3220b02d-3622-4e7e-9308-71a36ec55029','偈頌七首  其一','釋南雅','宋','宋诗','song-poetry','','[]','葛陂化杖誰爲力，陶壁飛梭事有因。',32,'全唐诗/poet.song.124000.json','["葛陂化杖誰爲力，陶壁飛梭事有因。", "好是風雲相際會，崢嶸頭角自驚群。"]'),
('bc4d8063-368a-4939-a284-5f2372b040d3','偈頌七首  其二','釋南雅','宋','宋诗','song-poetry','','[]','百歲光陰彈指頃，萬緣休處是良謀。',32,'全唐诗/poet.song.124000.json','["百歲光陰彈指頃，萬緣休處是良謀。", "文章蓋世今何在，到了還歸土一坵。"]'),
('018756ad-e4aa-4608-aded-5f3247f2d15b','偈頌七首  其三','釋南雅','宋','宋诗','song-poetry','','[]','生而無生，一片浮雲點太清。',58,'全唐诗/poet.song.124000.json','["生而無生，一片浮雲點太清。", "滅而無滅，萬里寒空沈曉月。", "箇些兒，佛不知，擬心棲處隔山迷。", "直饒不擬棲心處，猶落吾家第二機。"]'),
('40eead22-55cc-41e8-940b-fd04513febcc','偈頌七首  其四','釋南雅','宋','宋诗','song-poetry','','[]','生是死之生，死是生之死。',24,'全唐诗/poet.song.124000.json','["生是死之生，死是生之死。", "兩路坦然平，無彼亦無此。"]'),
('9dfc1d10-6a6b-4766-8475-74a75cdeab69','偈頌七首  其五','釋南雅','宋','宋诗','song-poetry','','[]','瞎馿滅却正法眼，臨濟宗風始大張。',40,'全唐诗/poet.song.124000.json','["瞎馿滅却正法眼，臨濟宗風始大張。", "的的單傳至今日，繩繩不斷愈光揚。", "有價數，沒商量。"]'),
('38e6d683-853b-4ef3-950c-73aa0dae28ed','偈頌七首  其六','釋南雅','宋','宋诗','song-poetry','','[]','去年今月正今日，北高峯前，冷泉亭畔。',100,'全唐诗/poet.song.124000.json','["去年今月正今日，北高峯前，冷泉亭畔。", "懸羊頭，賣狗肉，秤頭斤兩惜如玉。", "幾多高價來相酬，盡力相酬酬不足。", "今年今日正今時，竹山頂上，棲風亭邊。", "饑即餐，困即眠，石頭爲枕草爲氈。", "永日蕭然無箇事，白雲深處不朝天。"]'),
('7bb9c753-8313-43bc-bc3c-96ab08a6f8f3','偈頌七首  其七','釋南雅','宋','宋诗','song-poetry','','[]','十方同聚會，箇箇學無爲。',24,'全唐诗/poet.song.124000.json','["十方同聚會，箇箇學無爲。", "此是選佛場，心空及第歸。"]'),
('9f170a68-ae07-46ac-9bb9-34f80dbaa5df','見見之時見非是見','釋南雅','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','見見之時非是見，見猶離見若爲論。',32,'全唐诗/poet.song.124000.json','["見見之時非是見，見猶離見若爲論。", "錢塘江上中秋後，風急潮聲萬馬奔。"]'),
('e0bc483a-2e5a-4844-8078-b7480baf1aba','真覺禪師','釋南雅','宋','宋诗','song-poetry','','[]','德山棒下桶底脫，又被巖頭轟一喝。',32,'全唐诗/poet.song.124000.json','["德山棒下桶底脫，又被巖頭轟一喝。", "懸崖萬丈放全身，松山撐破秋空月。"]'),
('aa1a2f48-c4bd-4512-b238-1b09098f5fb7','偈二首  其一','釋南雅','宋','宋诗','song-poetry','','[]','大機貴直截，大用貴頓發。',24,'全唐诗/poet.song.124000.json','["大機貴直截，大用貴頓發。", "縱有嚙鏃機，一鎚須打殺。"]'),
('539c0df8-6995-4bf7-a1b3-e94e7ece8db4','偈二首  其二','釋南雅','宋','宋诗','song-poetry','','[]','紫蕨伸拳笋破梢，楊花飛盡綠陰交。',32,'全唐诗/poet.song.124000.json','["紫蕨伸拳笋破梢，楊花飛盡綠陰交。", "分明西祖單傳句，黄栗留鳴燕語巢。"]'),
('9c977570-de6e-420d-9715-ed475170779c','進敬天圖','程叔達','宋','宋诗','song-poetry','','[]','自幸躬逢時盛治，人欣官備掌絲綸。',192,'全唐诗/poet.song.124000.json','["自幸躬逢時盛治，人欣官備掌絲綸。", "頻年館閣更新進，屢世階墀作近臣。", "憶昔中興開六位，旋禪歷數轉雙輪。", "禎符龍馬南江出，寶籙臺垣北極陳。", "端拱明堂時御世，溯源清廟允尊親。", "無爲效舜惟恭己，受攝如堯只布仁。", "四海群生回泰運，萬幾一日起黎民。", "曾聞洪範平康福，尤守丹書敬勝身。", "昨見江湖雖飲馬，將來京洛靖烽塵。", "吾儒所學惟誠正，稽古欽哉有誡詢。", "四國八風生萬象，九重一語定三辰。", "遥祈天鑒納遺老，抃舞溫和渾是春。"]'),
('2ac5de44-ec81-4c82-bb98-8eec1d525aab','喜賀恩減本州絹額','程叔達','宋','宋诗','song-poetry','','[]','山國不栽桑，抱布貿絲藏。',24,'全唐诗/poet.song.124000.json','["山國不栽桑，抱布貿絲藏。", "恩詔光明燭，寒燈織室光。"]'),
('5886696d-52c9-4911-8729-1bac8d285fb9','和姜梅山見寄','汪大猷','宋','宋诗','song-poetry','','["\u897f\u6e56"]','投分雖深迹却疏，君居東婺我西湖。',64,'全唐诗/poet.song.124000.json','["投分雖深迹却疏，君居東婺我西湖。", "兒曹方喜承毛檄，父執應容效鯉趨。", "慨念舊遊多宿草，僅餘二老見霜鬚。", "詩來喚起相思夢，又向梅山得楷模。"]'),
('70e5acc6-ae39-44d6-a672-c49a7cfd4978','通山縣寄朱元晦','汪大猷','宋','宋诗','song-poetry','','[]','碧澗環山麓，高低滿百家。',48,'全唐诗/poet.song.124000.json','["碧澗環山麓，高低滿百家。", "途窮疏騎氣，縣古聽蜂衙。", "書倩雲中雁，歌煩水底蛙。", "陽和不擇地，隨分得春花。"]'),
('c9f3a175-646b-41d1-8539-4db8da543dcf','題樂天居士詩集後時謫居廬山','汪大猷','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','居士當年謫九江，高懷往往寓篇章。',64,'全唐诗/poet.song.124000.json','["居士當年謫九江，高懷往往寓篇章。", "多言世上風波惡，不似閒中氣味長。", "千載聲名雖莫及，一時蹤跡偶相望。", "若容俗駕追遺矩，待看南山結草堂。"]'),
('e3fdb6f4-f4d6-446a-bdd2-ee1e0032c6cf','次韵奉答諸公  其一','汪大猷','宋','宋诗','song-poetry','','[]','自入中書不計年，只將方寸作良田。',64,'全唐诗/poet.song.124000.json','["自入中書不計年，只將方寸作良田。", "桑榆物外都無累，桃李人家賸有緣。", "放意不妨娛綠野，勒功何必向燕然。", "姓名元在丹臺上，千歲徜徉小洞天。"]'),
('f8e94fe9-d593-4ef5-9218-27cab0461da3','次韵奉答諸公  其二','汪大猷','宋','宋诗','song-poetry','','[]','衰年已過縱心期，安得聰明及往時。',64,'全唐诗/poet.song.124000.json','["衰年已過縱心期，安得聰明及往時。", "既老固應全晚節，雖貧豈暇計留資。", "元非矯飾求爲異，自是行藏要合宜。", "曾記詩僧林下約，爲將蹤跡報渠知。"]'),
('045049ff-2d78-4d08-abf0-21d26914cb41','題袁右丞滋像','汪大猷','宋','宋诗','song-poetry','','[]','金玉相輝滿畫扉，高風未許一行題。',64,'全唐诗/poet.song.124000.json','["金玉相輝滿畫扉，高風未許一行題。", "五朝冠蓋聯朱紫，八代文章煥壁奎。", "四老德推商皓並，群英名許魯賢齊。", "憑將世譜從頭看，道此真源出道溪。"]'),
('ba0370a1-2224-473d-b19e-94b7cc1df6ba','紀夢','鄭若沖','宋','宋诗','song-poetry','','[]','包括乾坤一環堵，拍手千門輝藻黼。',384,'全唐诗/poet.song.124000.json','["包括乾坤一環堵，拍手千門輝藻黼。", "編茅何事傍雲根，川觀巖居天固予。", "憶昔卧病歲壬午，夢行澗石憩衡宇。", "常充達庵表其門，大楷金書爰仰覩。", "吉符應已分行藏，二紀唐捐惜無補。", "我生六年哀怙恃，三殤相繼泣同乳。", "隻影危蹤巢在幕，孽子孤臣氣如縷。", "千金不忍坐垂堂，十稔詎能酬鞠撫。", "六張五角具孤虛，萬死一生逃險阻。", "矛頭淅米劍頭炊，耕常得晴刈常雨。", "菲末葑根有荆棘，鼠牙雀舌皆强禦。", "意行足下起關山，夕計朝謀成齟齬。", "先時敗事後失機，囀喉觸諱默招侮。", "貧來富往見交情，行信言忠貽罪罟。", "一本難令親者親，四海何由兄弟普。", "數奇嘗愧李將軍，五窮未嗟韓吏部。", "人生美惡半乘除，我常一味無甘苦。", "五十知非計已遲，見機而作今猶愈。", "結廬茲境了前緣，端居漫作溪山主。", "列壑攢峯無聳峭，疊穎飛柯不瞋拒。", "一室凝塵號全拙，茶鐺酒壺編簡聚。", "草亭臨流倚夢溪，觀罷魚游呼鶴舞。", "地饒松竹秀而腴，林生蘭蕙香頻吐。", "泉清洗耳何妨枕，晴軒炙背還堪俯。"]'),
('8b2deff5-d3cd-4938-b49b-b156ff2330c6','安定山','張恪','宋','宋诗','song-poetry','','[]','常懷玉壘李謫仙，精神浩瀚游八表。',256,'全唐诗/poet.song.124000.json','["常懷玉壘李謫仙，精神浩瀚游八表。", "頂摩蒼天弄白日，方丈蓬萊思清矯。", "吾鄉夙號山水邦，縈青繚白雜蒼縹。", "人間要自有佳趣，何必東瞷扶桑曉。", "江郎秀色照閩吳，咀嚼自可忘幽悄。", "爛柯山與浮雲齊，突星騎石凌飛鳥。", "何獨此山名未燿，無乃潛德避喧擾。", "定是壺中小有天，衆星未易立譚了。", "物之顯晦固有數，巧曆誰能窮忽秒。", "我聞雁岩古來無，山經不載事沉杳。", "後世奇祕始發見，游人足迹竟盤繞。", "九華妙觀人未覩，劉郎當時眼偏瞭。", "固知有物必有遇，此理甚明非深渺。", "豈惟安定名不腐，自覺劉郎才力少。", "我詩那能爲重輕，九鼎借助鴻毛小。", "群豪自可繼唐賢，聯名况有詩僧皎。"]'),
('7dc46c4e-50c0-4337-8a5a-7d68222ac2d4','偈三首  其一','釋有權','宋','宋诗','song-poetry','','[]','黑漆崑崙把釣竿，古帆高掛下驚湍。',32,'全唐诗/poet.song.124000.json','["黑漆崑崙把釣竿，古帆高掛下驚湍。", "蘆花影裏弄明月，引得盲龜上釣船。"]'),
('487d0396-791f-442c-a0a5-a7676b117182','偈三首  其二','釋有權','宋','宋诗','song-poetry','','[]','今朝結却布袋口，明眼衲僧莫亂走。',56,'全唐诗/poet.song.124000.json','["今朝結却布袋口，明眼衲僧莫亂走。", "心行滅處解翻身，噴嚏也成師子吼。", "旃檀林，任馳驟。", "剔起眉毛頂上生，剜肉成瘡露家醜。"]'),
('8e3738e2-ccfb-4564-ba0f-101436f98c8f','偈三首  其三','釋有權','宋','宋诗','song-poetry','','[]','禪禪，無黨無偏。',20,'全唐诗/poet.song.124000.json','["禪禪，無黨無偏。", "迷時千里隔，悟在口皮邊。"]'),
('4606f24b-d5e4-48ed-90f0-efac1daa8359','頌古十一首  其一','釋有權','宋','宋诗','song-poetry','','[]','石上栽花分外奇，枝頭春色暗芳菲。',32,'全唐诗/poet.song.124000.json','["石上栽花分外奇，枝頭春色暗芳菲。", "馨香徧界無人嗅，一任狂風取次吹。"]'),
('0f3ccde6-31cd-43df-a9a1-81cf8000cb5a','頌古十一首  其二','釋有權','宋','宋诗','song-poetry','','[]','秀才覓火和烟得，長沙賣石著雲饒。',32,'全唐诗/poet.song.124000.json','["秀才覓火和烟得，長沙賣石著雲饒。", "欲知千佛居何土，贏得詩禪價轉高。"]'),
('60acc2ca-7315-4eb7-a359-93d8fffce505','頌古十一首  其三','釋有權','宋','宋诗','song-poetry','','[]','衣錦還鄉人盡見，長時富貴許誰知。',32,'全唐诗/poet.song.124000.json','["衣錦還鄉人盡見，長時富貴許誰知。", "無言童子呵呵笑，贏得風光滿面歸。"]'),
('7e1f84a3-ccd8-469a-a4d5-4a6d8d44b4ec','頌古十一首  其四','釋有權','宋','宋诗','song-poetry','','[]','瀲瀲灧灧水光浮，不見孤帆不見舟。',32,'全唐诗/poet.song.124000.json','["瀲瀲灧灧水光浮，不見孤帆不見舟。", "斜陽欲落未落處，盡是離人今古愁。"]'),
('bd16e265-7db3-490d-8e76-4ce73b842594','頌古十一首  其五','釋有權','宋','宋诗','song-poetry','','[]','萬鈞之弩射何人，箭未離弦已喪身。',32,'全唐诗/poet.song.124000.json','["萬鈞之弩射何人，箭未離弦已喪身。", "带累盲龜失浮木，欲來火裏透金塵。"]'),
('fada0a84-b963-444b-9e26-bf1334b9cc99','頌古十一首  其六','釋有權','宋','宋诗','song-poetry','','[]','我手何似佛手，二八恰恰十九。',28,'全唐诗/poet.song.124000.json','["我手何似佛手，二八恰恰十九。", "年尾算到年頭，家內一錢無有。"]'),
('2fbe2549-7540-4060-b9b5-5c915c43149e','頌古十一首  其七','釋有權','宋','宋诗','song-poetry','','[]','我脚何似馿脚，踏著趙州略彴。',28,'全唐诗/poet.song.124000.json','["我脚何似馿脚，踏著趙州略彴。", "驚得迦葉皺眉，文殊却打無著。"]'),
('b5674a0b-afdd-42bd-b97c-e5bec733a88a','頌古十一首  其八','釋有權','宋','宋诗','song-poetry','','[]','人人有箇生緣，男兒氣宇衝天。',28,'全唐诗/poet.song.124000.json','["人人有箇生緣，男兒氣宇衝天。", "若是爭田競地，我即喚死如眠。"]'),
('4af9432f-b4f1-461d-b167-208612f45362','頌古十一首  其九','釋有權','宋','宋诗','song-poetry','','[]','佛手馿脚生緣，浩浩叢林盛傳。',28,'全唐诗/poet.song.124000.json','["佛手馿脚生緣，浩浩叢林盛傳。", "直饒一穿穿却，未免十萬八千。"]'),
('b1c26cd3-ad2b-4164-9886-7faf5366054b','頌古十一首  其一○','釋有權','宋','宋诗','song-poetry','','[]','揭大夔鼓噪紅塵，徧地刀鎗解出身。',32,'全唐诗/poet.song.124000.json','["揭大夔鼓噪紅塵，徧地刀鎗解出身。", "結角羅紋隨處入，銀山鐵壁是通津。"]'),
('3287569c-e5f7-4694-9caa-e10c0ddd0a2b','頌古十一首  其一一','釋有權','宋','宋诗','song-poetry','','[]','黑雲當午蔽清虛，白雨翻空失畫圖。',32,'全唐诗/poet.song.124000.json','["黑雲當午蔽清虛，白雨翻空失畫圖。", "雨過雲收山色凈，趙州東壁掛葫蘆。"]'),
('beba301a-426f-4d3f-ae5a-dbf34afe6d99','題羅漢洞','應材','宋','宋诗','song-poetry','','[]','石磴巍峩捉膝行，行時不覺看時驚。',32,'全唐诗/poet.song.124000.json','["石磴巍峩捉膝行，行時不覺看時驚。", "縱教良匠描難就，自是天工造化成。"]'),
('c2d0027a-6f9d-4249-8619-d08a1eca18db','浮橋','陳興','宋','宋诗','song-poetry','','[]','千尋鐵綰蒼龍骨，七十舟橫赤雁行。',32,'全唐诗/poet.song.124000.json','["千尋鐵綰蒼龍骨，七十舟橫赤雁行。", "來往渾如履平地，渡頭無復立斜陽。"]'),
('64aaf9af-0dde-489f-9509-22dee084dff5','句','李南壽','宋','宋诗','song-poetry','','[]','我以銅符吏營浦，聞古刺史元最賢。',16,'全唐诗/poet.song.124000.json','["我以銅符吏營浦，聞古刺史元最賢。"]'),
('47964250-de21-4604-bda9-4d680a543c07','句','范崇','宋','宋诗','song-poetry','','[]','川源通漢沔，舟楫下瀟湘。',12,'全唐诗/poet.song.124000.json','["川源通漢沔，舟楫下瀟湘。"]'),
('8401d596-6bab-4457-9e70-9cf4319fa5e6','題張許雙廟','曾伋','宋','宋诗','song-poetry','','[]','國憑節義壯洪基，激厲頹風屬聖時。',32,'全唐诗/poet.song.124000.json','["國憑節義壯洪基，激厲頹風屬聖時。", "曾屈帝尊親降輦，可因祈福幸公祠。"]'),
('d595d9d5-fcc7-4d3a-a4f1-089dbc80b584','讀留題張許雙廟詩','曾伋','宋','宋诗','song-poetry','','[]','篇卷留題盡昔賢，讀之英氣凜然寒。',32,'全唐诗/poet.song.124000.json','["篇卷留題盡昔賢，讀之英氣凜然寒。", "時人不曉尊崇意，都與叢祠一例看。"]'),
('e986ac75-6eff-4aa3-a733-d0ffa243c86d','鄉校頌  其一','陸淞','宋','宋诗','song-poetry','','[]','維鄉有校，示民有知。',26,'全唐诗/poet.song.124000.json','["維鄉有校，示民有知。", "教始豫遜，迪于訓彝，維風化是裨。"]'),
('08a97e1d-ab4c-4719-95d9-8a4013733646','鄉校頌  其二','陸淞','宋','宋诗','song-poetry','','[]','維校在鄉，示民有防。',26,'全唐诗/poet.song.124000.json','["維校在鄉，示民有防。", "入孝出悌，爲忠爲良，斯邦家之光。"]'),
('d9255813-a67d-4481-90cd-7cc3c2898f1c','鄉校頌  其三','陸淞','宋','宋诗','song-poetry','','[]','鄉校有基，如德弗虧。',26,'全唐诗/poet.song.124000.json','["鄉校有基，如德弗虧。", "劉侯遷之，魏侯新之，李侯能成之。"]'),
('41d4adc7-5231-41a2-9dd6-028209513ae5','鄉校頌  其四','陸淞','宋','宋诗','song-poetry','','[]','其遷者初，其新者中。',26,'全唐诗/poet.song.124000.json','["其遷者初，其新者中。", "肄業傳道，有師有宗，繄李侯之功。"]'),
('22fa3d47-bc62-4212-a9f3-efb379c6bd52','鄉校頌  其五','陸淞','宋','宋诗','song-poetry','','[]','樂只君子，孰後孰先。',26,'全唐诗/poet.song.124000.json','["樂只君子，孰後孰先。", "顯有嘉聞，於斯萬年，維大夫之賢。"]'),
('ce817f17-853e-4609-95e6-3983b1c60d05','蔬飲聯句','楊輔世','宋','宋诗','song-poetry','','[]','蕨含春味紫如椽，酒入春風浪似山。',32,'全唐诗/poet.song.124000.json','["蕨含春味紫如椽，酒入春風浪似山。", "未信乾坤非細物，小吞螺浦半杯間。"]'),
('e2320cfa-56f8-4a52-ac7a-ec120826c935','金罌花聯句','楊輔世','宋','宋诗','song-poetry','','[]','兩日風狂雨更顛，取將暖去更衣單。',32,'全唐诗/poet.song.124000.json','["兩日風狂雨更顛，取將暖去更衣單。", "金罌花發關誰事，何用夜來如許寒。"]'),
('5f68a308-451d-4cd5-b3b3-667a0fceceaa','南溪','楊輔世','宋','宋诗','song-poetry','','["\u897f\u6e56"]','碧玉寒塘瑩不流，紅蕖影裏立沙鷗。',32,'全唐诗/poet.song.124000.json','["碧玉寒塘瑩不流，紅蕖影裏立沙鷗。", "便當不作南溪看，當得西湖十里秋。"]'),
('70543048-5199-4cd2-a3c7-92f13012aac8','牡丹','趙彥端','宋','宋诗','song-poetry','','[]','沉香亭北無消息，魏國姚家亦寂寥。',32,'全唐诗/poet.song.124000.json','["沉香亭北無消息，魏國姚家亦寂寥。", "不見君王殿中見，溪園堂下雨瀟瀟。"]'),
('0bbaac57-73ce-4538-9ea9-96c0d30ee7d1','觀送迎有感','趙彥端','宋','宋诗','song-poetry','','[]','來車去馬何紛綸，城西三日吹沙塵。',163,'全唐诗/poet.song.124000.json','["來車去馬何紛綸，城西三日吹沙塵。", "道旁鶴立亂青紫，千騎夾轂弓刀陳。", "共誇官軍勢雄盛，腰下黄金大邦印。", "舊人桃李已成蹊，新尹號令風雲馳。", "迎新爭勤送爭遠，相勸行行畏天晚。", "西風折柳翠不禁，落日轉旗紅半掩。", "別筵淚粉猶霑衣，旌旗畫戟重光輝。", "堂前昨夜語離燕，朝來賀厦成懽飛。", "江南陌上多芳草，長短亭邊貴人老。", "君不見田間有客徒步歸，年比使君白髮少。"]'),
('f3699125-e479-4eb3-b3c4-c217311f90e0','題西隠','趙彥端','宋','宋诗','song-poetry','','[]','西風數客一闌干，秋色翛然得細看。',64,'全唐诗/poet.song.124000.json','["西風數客一闌干，秋色翛然得細看。", "潦水倍知寒事早，夕陽更覺晚山寬。", "小留待月鐘無遽，半醉題詩燭未殘。", "憶得向來幽獨處，黄精未熟客衣單。"]'),
('698cf3f5-bc52-44c9-9759-6a21ba3f0ce9','雪後飲水慧聚寺','趙彥端','宋','宋诗','song-poetry','','[]','雪後山更佳，冷松及脩竹。',48,'全唐诗/poet.song.124000.json','["雪後山更佳，冷松及脩竹。", "茫然枝上鳥，伴我夢亦熟。", "陰崖得寒乳，夜半勝酒淥。", "惜無同心人，共此一杯玉。"]'),
('3d72a9f0-0f92-41d8-a391-77cd0452a56a','與諸公會飲崑山放生池亭','趙彥端','宋','宋诗','song-poetry','','[]','初疑山遥遥，不知日車永。',192,'全唐诗/poet.song.124000.json','["初疑山遥遥，不知日車永。", "杖藜起衰病，適此氛翳屏。", "北山喜覿面，倒屣客不領。", "讙然呼斷橋，快掃風柳影。", "扁舟載幽具，二面納倒景。", "荷香已坐足，不待花破穎。", "潛魚出銀刀，盈月上金餠。", "琴間得新弄，棋醉有新警。", "長笛者誰歟，喧靜同一境。", "行歌带亦適，還坐燭初耿。", "吾曹困重陰，濕處混蛙黽。", "忽逢天宇寬，況此星斗冷。", "酒爲河朔傾，大勝汲寒井。", "詩成西園句，浩若轉脩綆。", "君看萬象色，回首森已暝。", "吾歡豈異茲，瓶罄勿三請。"]'),
('f18cf5a8-7c09-4902-8b8a-1b521ba34302','崑山呂正之三男子連中神童科蓋奇事也建康嚴別駕爲之賦詩某因次其韻','趙彥端','宋','宋诗','song-poetry','','[]','疇昔從公杖屨閒，風乎嬉舞水雲閒。',64,'全唐诗/poet.song.124000.json','["疇昔從公杖屨閒，風乎嬉舞水雲閒。", "千言自我一聞悟，十駕從渠九折艱。", "蚤歲道山應徧住，他年畫戟許誰攀。", "何詞可贈張童子，莫忘楊公陽翟山。"]'),
('f8ec0def-96d1-4cae-8a3d-ff979d25da1e','次韻鄭逢辰直閣遷新居  其一','趙彥端','宋','宋诗','song-poetry','','[]','早向承明倦直廬，蕭然林下十年書。',64,'全唐诗/poet.song.124000.json','["早向承明倦直廬，蕭然林下十年書。", "便名盤谷雖惡可，閒賦斜川豈不如。", "山擁北窗凉雨後，月生南浦夜潮餘。", "江湖必有從公者，風際挐音儻是歟。"]'),
('97e3c2b4-d03e-410a-8513-78d3f6491c68','次韻鄭逢辰直閣遷新居  其二','趙彥端','宋','宋诗','song-poetry','','[]','生當带索守林廬，不合輕拋種樹書。',64,'全唐诗/poet.song.124000.json','["生當带索守林廬，不合輕拋種樹書。", "賀燕得公真是樂，弊貂將我竟何如。", "殊鄉更覺鄰爲貴，晚歲深期燭有餘。", "上下牀閒相去幾，未知夢覺孰非歟。"]'),
('8de230c8-aa4a-4436-936d-bf8fef4402b6','壽皇太子  其一','趙彥端','宋','宋诗','song-poetry','','[]','日日龍樓問寢時，雞人未動漏花遲。',32,'全唐诗/poet.song.124000.json','["日日龍樓問寢時，雞人未動漏花遲。", "前星一點朝天節，只有清臺太史知。"]'),
('7b3e1d02-3d2b-430a-983b-ba0bb3c67e74','壽皇太子  其二','趙彥端','宋','宋诗','song-poetry','','[]','子晉吹笙未是仙，阿丕橫槊少全篇。',32,'全唐诗/poet.song.124000.json','["子晉吹笙未是仙，阿丕橫槊少全篇。", "小吟青著梅梢句，一日東風四海傳。"]'),
('827b7b26-eb4d-4b82-b43f-a08cbfcea44a','壽皇太子  其三','趙彥端','宋','宋诗','song-poetry','','[]','光堯初御六龍天，上直參維大火躔。',32,'全唐诗/poet.song.124000.json','["光堯初御六龍天，上直參維大火躔。", "天意分明昌宋德，誕辰王世總丁年。"]'),
('aa90f0cc-ff87-475b-95d9-bca80cadcf36','壽皇孫','趙彥端','宋','宋诗','song-poetry','','[]','前星炳煥領孫星，環拱中天日兩輪。',64,'全唐诗/poet.song.124000.json','["前星炳煥領孫星，環拱中天日兩輪。", "四葉重光同聖世，千秋佳節近生辰。", "本支秀茂旦復旦，典學熙明新又新。", "喜入威顔天一笑，壽觴分賜一枝椿。"]'),
('182457c4-a70b-41c7-a62a-f301cacc66a5','梅花','趙彥端','宋','宋诗','song-poetry','','[]','南山如佳人，迥立未可親。',24,'全唐诗/poet.song.124000.json','["南山如佳人，迥立未可親。", "而况得道者，其間梅子真。"]'),
('89dddc77-971c-44da-881e-238f48d09cc2','海棠','趙彥端','宋','宋诗','song-poetry','','[]','杜陵先生詩萬紙，剩欲題花無可擬。',32,'全唐诗/poet.song.124000.json','["杜陵先生詩萬紙，剩欲題花無可擬。", "昭陽深殿睡東風，一日聲名勝妃子。"]'),
('10c0ad64-d98d-4ebf-bfa3-64ee831531cb','玉真臺','趙彥端','宋','宋诗','song-poetry','','[]','春色無窮巷，農鄉有太和。',48,'全唐诗/poet.song.124000.json','["春色無窮巷，農鄉有太和。", "病嗟聞道晚，貧喜得閑多。", "草徑供徐步，鄰花獲屢過。", "層臺宜抗榭，誰與買烟波。"]'),
('20d61523-5619-4cc8-9a12-bee6f5e725b5','崇安道中','趙彥端','宋','宋诗','song-poetry','','[]','風柳疎無力，秋花冷不香。',48,'全唐诗/poet.song.124000.json','["風柳疎無力，秋花冷不香。", "客請隨去燕，凉思起啼螿。", "地入閩山隘，天連越樹長。", "年年擣衣石，爲爾感征裳。"]'),
('9726f7f5-cd08-401f-ab9b-e52f32abddfa','壽皇太子  其一','趙彥端','宋','宋诗','song-poetry','','[]','清賞堂中無管弦，鳳山樓上有雲烟。',32,'全唐诗/poet.song.124000.json','["清賞堂中無管弦，鳳山樓上有雲烟。", "儲皇側畔何人侍，黄卷團欒是聖賢。"]'),
('408a18f7-a176-4b7a-8062-a8a09359c0b8','壽皇太子  其二','趙彥端','宋','宋诗','song-poetry','','[]','二聖多能似仲尼，儲皇家學自庭闈。',32,'全唐诗/poet.song.124000.json','["二聖多能似仲尼，儲皇家學自庭闈。", "銀鈎已有淳熙脚，玉句仍傳德壽衣。"]'),
('7825f88f-e331-41c2-8c53-8ab3df14e53f','壽皇太子  其三','趙彥端','宋','宋诗','song-poetry','','[]','明河楂上有仙翁，犯月撞星列碧穹。',32,'全唐诗/poet.song.124000.json','["明河楂上有仙翁，犯月撞星列碧穹。", "金闕東邊銀榜處，大書天地長男宮。"]'),
('33ff3a9d-cb76-49a3-abe8-f6eac353ae9b','壽皇太子  其四','趙彥端','宋','宋诗','song-poetry','','[]','大安宮裏漆園椿，子幹孫枝葉葉新。',32,'全唐诗/poet.song.124000.json','["大安宮裏漆園椿，子幹孫枝葉葉新。", "今日四株高下碧，相承一樣八千春。"]'),
('fd208a39-7dbc-4853-9b28-ce1fa9acec71','壽皇太子  其五','趙彥端','宋','宋诗','song-poetry','','[]','菊花潭上菊花新，不是花潭是壽盃。',32,'全唐诗/poet.song.124000.json','["菊花潭上菊花新，不是花潭是壽盃。", "天賜生朝千斛水，一年一斛送將來。"]'),
('72a47374-5438-46b1-b37f-f1a25b089d84','壽皇太子  其六','趙彥端','宋','宋诗','song-poetry','','[]','禹子湯孫并聖賢，一身雙美古無前。',32,'全唐诗/poet.song.124000.json','["禹子湯孫并聖賢，一身雙美古無前。", "願陳萬國元良句，不用金昭玉粹篇。"]'),
('37399ea5-aa22-46ca-9624-fb723418ea7b','壽皇太子  其七','趙彥端','宋','宋诗','song-poetry','','[]','少陽拜賜少陽旁，黄菊紅茱滿壽觴。',32,'全唐诗/poet.song.124000.json','["少陽拜賜少陽旁，黄菊紅茱滿壽觴。", "陽德重重在初四，不須九日是重陽。"]'),
('e67124db-5a92-4665-ad5c-11e49f473242','壽張守  其一','趙彥端','宋','宋诗','song-poetry','','[]','堂堂天上張公子，龍劍分光自斗牛。',64,'全唐诗/poet.song.124000.json','["堂堂天上張公子，龍劍分光自斗牛。", "海上忽歸槎萬里，雲間未放月中秋。", "才爲漢殿無雙手，恩到閩山第一州。", "亦有人言識仙骨，只看何日議封留。"]'),
('9cc82106-bc72-4156-b17a-59de51ee4bd4','壽張守  其二','趙彥端','宋','宋诗','song-poetry','','[]','鵷班新謁紫宸回，魚佩初迎幕府開。',64,'全唐诗/poet.song.124000.json','["鵷班新謁紫宸回，魚佩初迎幕府開。", "百里故鄉同晝錦，一年和氣自春臺。", "甘棠政美無留頌，泮水功成有異才。", "他日聽傳公不老，定知曾見武夷來。"]'),
('2c27b7d8-9a0a-4293-9363-15dd327d5cab','翠微山居八首  其一','趙彥端','宋','宋诗','song-poetry','','[]','閒來石上卧長松，百衲袈裟破又縫。',32,'全唐诗/poet.song.124000.json','["閒來石上卧長松，百衲袈裟破又縫。", "今日不愁明日飯，生涯只在鉢盂中。"]'),
('1899668b-7676-4025-911a-8d7d1b2fe9f4','翠微山居八首  其二','趙彥端','宋','宋诗','song-poetry','','[]','臨溪草草結茆堂，靜坐安然一炷香。',32,'全唐诗/poet.song.124000.json','["臨溪草草結茆堂，靜坐安然一炷香。", "不是息心除妄想，都緣無事可思量。"]'),
('35cb5d38-d76b-4f61-baab-266d81a31f35','翠微山居八首  其三','趙彥端','宋','宋诗','song-poetry','','[]','老老山僧不下階，雙眉恰似雪分開。',32,'全唐诗/poet.song.124000.json','["老老山僧不下階，雙眉恰似雪分開。", "世人若問枯松樹，我作沙彌親見栽。"]'),
('e8298a49-0692-4299-9d4d-73c2814e66f3','翠微山居八首  其四','趙彥端','宋','宋诗','song-poetry','','[]','幼入空門絕是非，老來學道轉精微。',32,'全唐诗/poet.song.124000.json','["幼入空門絕是非，老來學道轉精微。", "鉢中貧富千家飯，身上寒暄一衲衣。"]'),
('d17d06da-c059-4dc6-9983-3aef2086e583','翠微山居八首  其五','趙彥端','宋','宋诗','song-poetry','','[]','一池荷葉衣無盡，數樹松花食有餘。',32,'全唐诗/poet.song.124000.json','["一池荷葉衣無盡，數樹松花食有餘。", "却被世人知住處，更移茆舍作深居。"]'),
('a97eebd2-b2de-4e7c-8f6e-e529492c71b8','翠微山居八首  其六','趙彥端','宋','宋诗','song-poetry','','[]','茆簷靜坐千山月，竹戶閒棲一片雲。',32,'全唐诗/poet.song.124000.json','["茆簷靜坐千山月，竹戶閒棲一片雲。", "莫送往來名利客，階前踏破綠苔紋。"]'),
('a50ccb7f-fb5a-4c1c-8d66-e1481b1d4983','翠微山居八首  其七','趙彥端','宋','宋诗','song-poetry','','[]','爐中無火已多時，早起惟將一衲披。',32,'全唐诗/poet.song.124000.json','["爐中無火已多時，早起惟將一衲披。", "莫怪山僧常冷淡，夜深無處拾松枝。"]'),
('80d7865b-ac9b-42d9-a7d6-20a65201deac','翠微山居八首  其八','趙彥端','宋','宋诗','song-poetry','','[]','豈是栽松待茯苓，且圖山色鎮長青。',32,'全唐诗/poet.song.124000.json','["豈是栽松待茯苓，且圖山色鎮長青。", "他年行脚不歸去，留與人間作畫屏。"]'),
('19cfffe3-0c1e-4177-8188-f4d387da9bc8','句  其一','趙彥端','宋','宋诗','song-poetry','','[]','新梢漸變鵝黄色，淺水遥添鴨綠紋。',16,'全唐诗/poet.song.124000.json','["新梢漸變鵝黄色，淺水遥添鴨綠紋。"]'),
('c56da495-5fde-4848-a19e-de457235b6e3','句  其二','趙彥端','宋','宋诗','song-poetry','','[]','水暖池塘閒睡鴨，烟深村落自鳴鷗。',16,'全唐诗/poet.song.124000.json','["水暖池塘閒睡鴨，烟深村落自鳴鷗。"]'),
('4c30ee7d-b5e7-4ed6-88d7-c501ceb4a01f','句  其三','趙彥端','宋','宋诗','song-poetry','','[]','來日泥香催燕子，歸時桑老趁蠶收。',16,'全唐诗/poet.song.124000.json','["來日泥香催燕子，歸時桑老趁蠶收。"]'),
('5ce363f4-eb1c-41fe-910e-3bac0545f1b6','句  其四','趙彥端','宋','宋诗','song-poetry','','[]','微風蹙水魚鱗浪，薄日烘雲卵色天。',16,'全唐诗/poet.song.124000.json','["微風蹙水魚鱗浪，薄日烘雲卵色天。"]'),
('ab643567-8bf8-4fcb-8547-f5af21479e9f','友賢堂','蔡洸','宋','宋诗','song-poetry','','[]','築堂傍西廡，非悅輪奐美。',72,'全唐诗/poet.song.124000.json','["築堂傍西廡，非悅輪奐美。", "公餘竟何之，行行輒至止。", "紛紜屏玩好，周遭羅經史。", "晤對今偉人，尚論古君子。", "擇善固毋倦，勝良自自喜。", "衛公骨雖朽，妙語猶在耳。"]'),
('c76856e0-3ca2-4646-84ee-ca8300f93b85','臞庵  其一','何偁','宋','宋诗','song-poetry','','[]','多羨王居士，心閒事事幽。',48,'全唐诗/poet.song.124000.json','["多羨王居士，心閒事事幽。", "山從天末見，江近枕邊流。", "春圃千葩秀，霜林百果收。", "更能窮物理，濠上看魚游。"]'),
('c876018b-e4cc-4d48-a8ea-622b9e184dbf','臞庵  其二','何偁','宋','宋诗','song-poetry','','[]','地占松江勝，爲園不種瓜。',48,'全唐诗/poet.song.124000.json','["地占松江勝，爲園不種瓜。", "幽深清磬響，高下石欄斜。", "花密蜂隨蝶，林深雀啅蛇。", "勝如摩詰畫，不是季鷹家。"]'),
('b3618c7e-d61c-4cba-96ed-48ac7974f2e7','臞庵  其三','何偁','宋','宋诗','song-poetry','','[]','柳外長虹卧，江邊小市圓。',48,'全唐诗/poet.song.124000.json','["柳外長虹卧，江邊小市圓。", "水摇千嶂影，窗納五湖天。", "隔岸誰家圃，開帆何處船。", "非關臺榭好，此地最堪憐。"]'),
('81955bdb-b036-44d0-9f3f-96525df757bc','臞庵  其四','何偁','宋','宋诗','song-poetry','','[]','霜落川原淡，風高木葉丹。',48,'全唐诗/poet.song.124000.json','["霜落川原淡，風高木葉丹。", "雲垂千頃白，月墮一江寒。", "禮佛因成塔，焚香旋築壇。", "竹聲過小院，雜珮響珊珊。"]'),
('b74c10c4-4187-4d98-83b9-de5d2912fa0a','臞庵  其五','何偁','宋','宋诗','song-poetry','','[]','沙暖鴛鴦困，江寒翡翠愁。',48,'全唐诗/poet.song.124000.json','["沙暖鴛鴦困，江寒翡翠愁。", "紅蓮秋的歷，短櫂晚夷猶。", "處世長無累，端居百不憂。", "時時明月下，橫笛倒騎牛。"]'),
('8b11272c-69d8-4527-9fbb-e567a51be3f9','籍桂堂','何偁','宋','宋诗','song-poetry','','[]','清溪一百曲，洗我心無塵。',48,'全唐诗/poet.song.124000.json','["清溪一百曲，洗我心無塵。", "日影上汀渚，桂香襲衣巾。", "露零芳更潤，山沃葉長春。", "種德長如昔，他年更幾人。"]'),
('58d996c7-9805-434c-a177-ec56a8882f60','新亭  其一','史正志','宋','宋诗','song-poetry','','[]','龍盤虎踞阻江流，割據由來起仲謀。',32,'全唐诗/poet.song.124000.json','["龍盤虎踞阻江流，割據由來起仲謀。", "從此但誇佳麗地，不知西北有神州。"]'),
('a673337c-9faa-45ab-84ba-1c42e0704ecd','新亭  其二','史正志','宋','宋诗','song-poetry','','[]','忽枉王人六轡馳，新亭有酒便同持。',32,'全唐诗/poet.song.124000.json','["忽枉王人六轡馳，新亭有酒便同持。", "坐中不作南冠歎，江左夷吾是素期。"]'),
('844ece8a-dbd7-4845-9160-bd381c31f701','黄陵題詠  其一','史正志','宋','宋诗','song-poetry','','[]','玉馭蒼梧去不還，淚痕淚竹尚斑斑。',32,'全唐诗/poet.song.124000.json','["玉馭蒼梧去不還，淚痕淚竹尚斑斑。", "空傳朱瑟流幽怨，謾許明珠解佩還。"]'),
('6e0bde70-24d4-4d2d-ba08-5a368b67e5fd','黄陵題詠  其二','史正志','宋','宋诗','song-poetry','','[]','廟塑湘妃少女容，誰知百歲奉重瞳。',32,'全唐诗/poet.song.124000.json','["廟塑湘妃少女容，誰知百歲奉重瞳。", "從今好事詩騷客，莊肅當存念慮中。"]'),
('d751e1ea-d737-4778-8ce0-2373eeb76551','黄陵題詠  其三','史正志','宋','宋诗','song-poetry','','[]','直方誰似退之賢，過廟當時禱亦虔。',32,'全唐诗/poet.song.124000.json','["直方誰似退之賢，過廟當時禱亦虔。", "徼福乞靈旋有助，傾囊十萬出私錢。"]'),
('5316fd29-57f0-4e06-8c63-c766f62a78d0','朝陽巖','趙不息','宋','宋诗','song-poetry','','[]','朝陽山水佳，毫端意無極。',48,'全唐诗/poet.song.124000.json','["朝陽山水佳，毫端意無極。", "發潛十七奇，幻出不盈尺。", "因續漫浪銘，更寫浯溪宅。", "俱作畫圖看，靜對天齊石。"]'),
('006efb7f-79f1-4a08-8240-831fe0d06c44','句','趙不息','宋','宋诗','song-poetry','','[]','魯國筆端昭日月，次山書法得春秋。',16,'全唐诗/poet.song.125000.json','["魯國筆端昭日月，次山書法得春秋。"]'),
('b0df0912-b375-419b-9cd4-dd50e3622084','碧玉軒','鄭丙','宋','宋诗','song-poetry','','[]','長安回首遠如天，解榻祇園百病痊。',64,'全唐诗/poet.song.125000.json','["長安回首遠如天，解榻祇園百病痊。", "身世本來如寄爾，佛僧同住更悠然。", "篔簹千採不受暑，巖桂一枝或自妍。", "長與高人伴幽獨，粥魚齋鼓度流年。"]'),
('8fffdef3-614f-4663-83d9-5bcbc750cf2b','清常寺','謝諤','宋','宋诗','song-poetry','','[]','佛廬塵不到，客枕夢頻驚。',48,'全唐诗/poet.song.125000.json','["佛廬塵不到，客枕夢頻驚。", "淅淅山風響，纖纖隙月明。", "烟雲春漸暖，鐘磬曉逾清。", "蹤跡奔馳裏，飄浮媿此生。"]'),
('30de1bc1-98fb-4c04-aaa1-523d8d2b8a67','龍回院','謝諤','宋','宋诗','song-poetry','','[]','堂殿塵埃外，軒櫺紫翠中。',48,'全唐诗/poet.song.125000.json','["堂殿塵埃外，軒櫺紫翠中。", "凭欄千嶂雨，欹枕半窗風。", "得意何妨僻，尋幽豈易窮。", "分張閒草木，一一見春工。"]'),
('6487cbd6-8535-46da-a80d-d9f8a035e38b','玉山觀','謝諤','宋','宋诗','song-poetry','','[]','微明燈火夜堂幽，聽徹絲桐萬慮休。',32,'全唐诗/poet.song.125000.json','["微明燈火夜堂幽，聽徹絲桐萬慮休。", "骨冷魂清眠不得，竹風蕭瑟滿庭秋。"]'),
('cb3a9d14-5ba9-4ce9-a239-9f684bef06b3','鼇溪  其一','謝諤','宋','宋诗','song-poetry','','[]','數版小橋橫晚晴，兩行古木弄春榮。',32,'全唐诗/poet.song.125000.json','["數版小橋橫晚晴，兩行古木弄春榮。", "不知多少夜來雨，水到岸頭渾欲平。"]'),
('69a8bf27-4ddc-4d7c-928e-cd03c3b79976','鼇溪  其二','謝諤','宋','宋诗','song-poetry','','[]','藹藹煙雲望眼昏，亂紅翻逕綠遮門。',32,'全唐诗/poet.song.125000.json','["藹藹煙雲望眼昏，亂紅翻逕綠遮門。", "一聲啼鳥在何處，山外人家桑柘村。"]'),
('51f5ad12-47ff-4d77-aae8-5194355958e0','追和邵祭酒柬呂太學','謝諤','宋','宋诗','song-poetry','','[]','艱難方見救時在，一介儒生爲國哀。',64,'全唐诗/poet.song.125000.json','["艱難方見救時在，一介儒生爲國哀。", "六豕奸雄千古恨，二龍奔馭幾時迴。", "道州自分填溝壑，天詔何須賁草萊。", "我識先生心似鐵，宸章莫更苦相催。"]'),
('d3d7acb9-936d-4dd7-91be-ab5fe8ddbf74','復朱晦菴','謝諤','宋','宋诗','song-poetry','','[]','笑指長沙擅閫，來向吾鄉假途。',28,'全唐诗/poet.song.125000.json','["笑指長沙擅閫，來向吾鄉假途。", "一段忙中說話，無非孔孟工夫。"]'),
('ae270f00-0604-4b64-97c0-601eef62342e','勸農','謝諤','宋','宋诗','song-poetry','','[]','莫入州衙與縣衙，勸君勤理舊生涯。',64,'全唐诗/poet.song.125000.json','["莫入州衙與縣衙，勸君勤理舊生涯。", "池塘多放聊添稅，田地深耕足養家。", "教子教孫須教義，栽桑栽柘勝栽花。", "閑非閑是都休管，渴飲清泉困飲茶。"]'),
('eb4491ea-33ab-40f6-9e39-c717a3387945','六瑞堂','謝諤','宋','宋诗','song-poetry','','[]','循良天惠海邊頭，波浪澄清宿霧收。',64,'全唐诗/poet.song.125000.json','["循良天惠海邊頭，波浪澄清宿霧收。", "纔把一麾來北闕，便驚六瑞到南州。", "日高雙影亭亭並，風動孤香冉冉浮。", "好作畫圖獻當宁，御屏風上永傳休。"]'),
('8e70f547-7477-4f7f-8220-1dfaaddc3b27','會劉子東夜飲','謝諤','宋','宋诗','song-poetry','','[]','夾江居民萬家邑，朱樓碧瓦炊煙濕。',128,'全唐诗/poet.song.125000.json','["夾江居民萬家邑，朱樓碧瓦炊煙濕。", "筍輿登頓渡飛橋，半曲春梁龍起蟄。", "門前柳葉翻霜風，小驛舊是神仙宮。", "平時對面不得語，一燈從容今夕同。", "呼童急持酒爲帚，掃盡閒愁那更有。", "人生聚散無定期，但知膠漆情如舊。", "君方游戲親戎行，我亦酸寒尉溧陽。", "棄家從官豈得已，相與望雲思故鄉。"]'),
('b252637d-8b0a-4509-bf37-0f756b12d777','至曾田市貽管巡檢  其一','謝諤','宋','宋诗','song-poetry','','[]','一年三過曾田市，春去秋來瞬息間。',32,'全唐诗/poet.song.125000.json','["一年三過曾田市，春去秋來瞬息間。", "安得此身無俗累，清高長似寨前山。"]'),
('7b3ebfed-10d5-4f92-81bc-7f6a00c6db20','至曾田市貽管巡檢  其二','謝諤','宋','宋诗','song-poetry','','[]','將軍齊相夷吾後，不用干戈盜自清。',32,'全唐诗/poet.song.125000.json','["將軍齊相夷吾後，不用干戈盜自清。", "回首江南望江北，故鄉天際暮雲平。"]'),
('f1644d3c-5d2e-42d0-9856-94729e000eb4','南真觀','謝諤','宋','宋诗','song-poetry','','[]','人煙一簇古溪頭，竹樹低昂映碧流。',32,'全唐诗/poet.song.125000.json','["人煙一簇古溪頭，竹樹低昂映碧流。", "曳杖不知山路險，南真觀裏謁浮丘。"]'),
('8c0fb5b2-50de-4f75-8f88-6019242a8ac7','延福寺','謝諤','宋','宋诗','song-poetry','','[]','閲世巖松古，隨人徑蘚斑。',48,'全唐诗/poet.song.125000.json','["閲世巖松古，隨人徑蘚斑。", "樓臺雲冉冉，沙石水潺潺。", "興出崎嶇外，身行杳靄間。", "通天知有路，一笑檻前山。"]'),
('f75b7bef-2299-4bde-b929-dc7b8dddc1bd','嚴隠君九齡適軒','謝諤','宋','宋诗','song-poetry','','[]','陶公勳業在姑蘇，扁舟歸來春水湖。',192,'全唐诗/poet.song.125000.json','["陶公勳業在姑蘇，扁舟歸來春水湖。", "張良亦從赤松子，拋擲兵閒黄石書。", "平吳戮項本無事，所適定非真適意。", "戰酣人境强迴頭，晚乃逍遥脫塵累。", "先生之適真天然，浩氣養得歸林泉。", "一生袖却奪標手，名利過眼如雲煙。", "清風丈室數椽足，幕天席地月爲燭。", "徑有幽花杖履香，窗延野竹縹緗綠。", "天邊白雲不可呼，空中野鶴隨所如。", "延年美意復誰解，拂麈岸巾聊自娛。", "松紋簟滑琉璃色，卧展南華書一帙。", "先生之適真天然，不速還嗔叩門客。"]'),
('f1c219b1-46b0-4c7e-a08f-bbe7e0652c1e','讀書臺','謝諤','宋','宋诗','song-poetry','','[]','莓苔點點路層層，此地分明勝概增。',64,'全唐诗/poet.song.125000.json','["莓苔點點路層層，此地分明勝概增。", "天上樓臺山上寺，雲邊鐘鼓月邊僧。", "青松鶴夢生秋吹，寶塔星華見夜燈。", "消盡塵襟三萬斛，石床閒倚古蘿藤。"]'),
('382674bd-3ee7-4358-8550-e53ca575d758','送子峴之官萍鄉  其一','謝諤','宋','宋诗','song-poetry','','[]','聖主除官本爲民，吾兒何幸到簪紳。',32,'全唐诗/poet.song.125000.json','["聖主除官本爲民，吾兒何幸到簪紳。", "但須因此行方便，不必爲冬更學春。"]'),
('465b5317-ce48-4987-9fcc-faf508de97e2','送子峴之官萍鄉  其二','謝諤','宋','宋诗','song-poetry','','[]','吏師吾昔得三賢，回首思之幾許年。',32,'全唐诗/poet.song.125000.json','["吏師吾昔得三賢，回首思之幾許年。", "屈指利名多少事，其間廉節最爲先。"]'),
('783e94ae-bd54-45e8-99a1-5cdb3e6604dc','句','謝諤','宋','宋诗','song-poetry','','[]','金房開達皆名州，盛山更在天上頭。',16,'全唐诗/poet.song.125000.json','["金房開達皆名州，盛山更在天上頭。"]'),
('ebb78890-1a6f-4681-93e0-597bd839340e','溈山問仰山臨濟得大愚力得黄蘗力頌','釋德光','宋','宋诗','song-poetry','','[]','黄蘗山頭遭痛棒，大愚肋下報寃讎。',32,'全唐诗/poet.song.125000.json','["黄蘗山頭遭痛棒，大愚肋下報寃讎。", "當機一喝驚天地，直得曹溪水逆流。"]'),
('d93c2e86-d2a2-47f4-9f0c-4b439e3a9f67','興化打克賓克賓如此答頌','釋德光','宋','宋诗','song-poetry','','[]','罰錢出院揚家醜，興化聱頭遇克賓。',32,'全唐诗/poet.song.125000.json','["罰錢出院揚家醜，興化聱頭遇克賓。", "父子不傳真秘訣，棒頭敲出玉麒麟。"]'),
('25799d3f-5590-41af-8a51-1c04fde09c0f','答御製頌','釋德光','宋','宋诗','song-poetry','','[]','當陽一句子，平地步青雲。',24,'全唐诗/poet.song.125000.json','["當陽一句子，平地步青雲。", "踏翻關棙處，便是主家春。"]'),
('5ef7a531-2af1-42fc-b478-a0f944b5c928','進即心即佛非心非佛頌','釋德光','宋','宋诗','song-poetry','','[]','即心即佛無蹊徑，非佛非心有變通。',32,'全唐诗/poet.song.125000.json','["即心即佛無蹊徑，非佛非心有變通。", "直下兩頭俱透脫，新羅不在海門東。"]'),
('e4a27127-7afd-4a87-8d02-38ab5f69375e','答御製頌','釋德光','宋','宋诗','song-poetry','','[]','一句截流心路絕，千差萬別豁然通。',32,'全唐诗/poet.song.125000.json','["一句截流心路絕，千差萬別豁然通。", "等閑更進竿頭步，莫問西來及與東。"]'),
('ba6df336-682f-4878-bc49-42ae06cab80e','捧賜佛照禪師號敕黄示衆','釋德光','宋','宋诗','song-poetry','','[]','天書親自日邊來，一道神光遍九垓。',32,'全唐诗/poet.song.125000.json','["天書親自日邊來，一道神光遍九垓。", "爲瑞爲祥恩力大，直教枯木解花開。"]'),
('b45312ff-0ed4-4983-9722-82e25e8bba65','舉船子和尚覆船入水而逝頌','釋德光','宋','宋诗','song-poetry','','[]','驀口一橈全殺活，點頭三下鼻遼天。',32,'全唐诗/poet.song.125000.json','["驀口一橈全殺活，點頭三下鼻遼天。", "至今千古風流在，誰道華亭覆却船。"]'),
('c16dcf8e-55ea-4b2c-94b4-7d6f296f8b9e','偈頌十首  其一','釋德光','宋','宋诗','song-poetry','','[]','口似血盆呵佛祖，牙如劍樹駡諸方。',32,'全唐诗/poet.song.125000.json','["口似血盆呵佛祖，牙如劍樹駡諸方。", "而今死入阿鼻獄，看你如何孟八郎。"]'),
('c86403a7-10a2-4c5c-831b-66cf454d707e','偈頌十首  其二','釋德光','宋','宋诗','song-poetry','','[]','機輪轉處，作者猶迷。',20,'全唐诗/poet.song.125000.json','["機輪轉處，作者猶迷。", "祖令當行，魔軍膽喪。"]'),
('e1f0cf6c-9136-4e74-a961-9064153f0c5e','偈頌十首  其三','釋德光','宋','宋诗','song-poetry','','[]','蓬萊有箇李八伯，一對眼睛如漆黑。',24,'全唐诗/poet.song.125000.json','["蓬萊有箇李八伯，一對眼睛如漆黑。", "且莫錯認定盤星。"]'),
('34f8740f-ce40-4670-b513-a13fd7bf63e7','偈頌十首  其四','釋德光','宋','宋诗','song-poetry','','[]','世尊拈花，迦葉微笑。',20,'全唐诗/poet.song.125000.json','["世尊拈花，迦葉微笑。", "一對鐵槌，渾無孔竅。"]'),
('cf5a3116-2247-42ef-88c1-dcdf97712aed','偈頌十首  其五','釋德光','宋','宋诗','song-poetry','','[]','十五日已前，千人萬人把不住。',50,'全唐诗/poet.song.125000.json','["十五日已前，千人萬人把不住。", "十五日已後，漫天網子百千重。", "正當十五日，龍袖拂開全體現，象王行處絕狐蹤。"]'),
('a89f9224-faa2-468b-bb16-6172ef224b09','偈頌十首  其六','釋德光','宋','宋诗','song-poetry','','[]','靈山一句無差別，直截分明爲君决。',32,'全唐诗/poet.song.125000.json','["靈山一句無差別，直截分明爲君决。", "藕絲孔裏騎大鵬，竹篦打落天邊月。"]'),
('7e5fd102-5f48-40a8-84a7-3f3f9bd13d05','偈頌十首  其七','釋德光','宋','宋诗','song-poetry','','[]','說佛說祖，泥中洗土。',46,'全唐诗/poet.song.125000.json','["說佛說祖，泥中洗土。", "談妙談玄，十萬八千。", "現成公案，已落言詮。", "提起衲僧拄杖子，渾家送上渡頭船。"]'),
('246cef44-277f-41d0-87cc-ddc56e11110b','偈頌十首  其八','釋德光','宋','宋诗','song-poetry','','[]','靈隠全提向上機，不知誰是丈夫兒。',32,'全唐诗/poet.song.125000.json','["靈隠全提向上機，不知誰是丈夫兒。", "嶺梅漏泄春消息，雪裏橫開三四枝。"]'),
('ba45b332-8543-452c-ab83-783da3527a19','偈頌十首  其九','釋德光','宋','宋诗','song-poetry','','[]','趙州南，石橋北，觀音院裏有彌勒。',32,'全唐诗/poet.song.125000.json','["趙州南，石橋北，觀音院裏有彌勒。", "祖師遺下一隻履，直至而今尋不得。"]'),
('3f1fd908-9190-4921-ae75-899de40ed96c','偈頌十首  其一○','釋德光','宋','宋诗','song-poetry','','[]','一月普現一切水，一切水月一月攝。',42,'全唐诗/poet.song.125000.json','["一月普現一切水，一切水月一月攝。", "諸佛法身入我性，我性同共如來合。", "大小永嘉，和屎合尿。"]'),
('f4b687e7-f1a4-4476-86db-b6fe0a6e8870','偈頌十首  其一一','釋德光','宋','宋诗','song-poetry','','[]','一法不明，翳汝眼睛。',20,'全唐诗/poet.song.125000.json','["一法不明，翳汝眼睛。", "眼睛不明，世界崢嶸。"]'),
('7481d77e-e05c-4248-8778-56441a7f2ae7','布袋和尚贊','釋德光','宋','宋诗','song-poetry','','[]','拊背乞錢成漏泄，回頭轉腦昧真機。',32,'全唐诗/poet.song.125000.json','["拊背乞錢成漏泄，回頭轉腦昧真機。", "可憐閙裏無人識，空自肩擔布袋歸。"]'),
('dd53b236-5364-4f2e-944b-3916ae6b53f4','圜悟和尚贊','釋德光','宋','宋诗','song-poetry','','[]','纔呼小玉便知歸，撞破天關碎鐵圍。',32,'全唐诗/poet.song.125000.json','["纔呼小玉便知歸，撞破天關碎鐵圍。", "拈出東山暗號子，至今千古峭巍巍。"]'),
('e300cd93-318c-42fd-a618-74c3ef8ee48c','示建彌陀會','釋德光','宋','宋诗','song-poetry','','[]','了得惟心是道場，彌陀元不在西方。',32,'全唐诗/poet.song.125000.json','["了得惟心是道場，彌陀元不在西方。", "面門出入無人薦，剎剎塵塵迸寶光。"]'),
('4bc91706-06dc-45d7-af05-b5e6c9441cb1','示僧鄮郭建接待','釋德光','宋','宋诗','song-poetry','','[]','玉几峯高難措足，行人多向半途休。',32,'全唐诗/poet.song.125000.json','["玉几峯高難措足，行人多向半途休。", "無棲泊處開門戶，箇箇教伊到地頭。"]'),
('27b53981-d604-4d73-a1f7-f4dc8b48c376','自贊','釋德光','宋','宋诗','song-poetry','','[]','辭九重，歸東越。',24,'全唐诗/poet.song.125000.json','["辭九重，歸東越。", "聽松風，對江月。", "冷笑老胡得一橛。"]'),
('aec9d509-f417-49c4-ba97-954f9693d618','偈','釋德光','宋','宋诗','song-poetry','','[]','七手八脚，三頭兩面。',46,'全唐诗/poet.song.125000.json','["七手八脚，三頭兩面。", "耳聽不聞，眼覷不見。", "苦樂逆順，打成一片。", "路逢死蛇莫打殺，無底籃子盛將歸。"]'),
('553aeca2-815c-4f89-8f93-e837e5230256','頌古十三首  其一','釋德光','宋','宋诗','song-poetry','','[]','出得山來早是遲，却於世上討便宜。',32,'全唐诗/poet.song.125000.json','["出得山來早是遲，却於世上討便宜。", "直饒一念超三界，好與拳頭劈面椎。"]'),
