('31f5ccd4-833d-4107-a91d-03878160dd1a','頌古十三首  其六','釋德光','宋','宋诗','song-poetry','','[]','喪盡生涯賣笊籬，白拈火裏討便宜。',32,'全唐诗/poet.song.125000.json','["喪盡生涯賣笊籬，白拈火裏討便宜。", "看來伎倆只如此，也道心空及第歸。"]'),
('70506e27-a5c3-4232-85c6-d300e5fee3dc','頌古十三首  其七','釋德光','宋','宋诗','song-poetry','','[]','趙州勘婆，百發百中。',20,'全唐诗/poet.song.125000.json','["趙州勘婆，百發百中。", "趁得老鼠，打破油甕。"]'),
('c6dc27a1-ca03-41f0-94d8-d1aa4ab90c29','頌古十三首  其八','釋德光','宋','宋诗','song-poetry','','[]','苦中樂，樂中苦，趙州這僧俱欠悟。',30,'全唐诗/poet.song.125000.json','["苦中樂，樂中苦，趙州這僧俱欠悟。", "直饒頓徹根源，也是泥中洗土。"]'),
('a9c2837f-9e65-444c-b171-6ab595c2f3d4','頌古十三首  其九','釋德光','宋','宋诗','song-poetry','','[]','黄蘗棒頭曾不顧，高安拳下錯商量。',32,'全唐诗/poet.song.125000.json','["黄蘗棒頭曾不顧，高安拳下錯商量。", "從茲徧界生荆棘，佛法初無一寸長。"]'),
('80b84c55-40fe-4a02-a637-8b0835364fdd','頌古十三首  其一○','釋德光','宋','宋诗','song-poetry','','[]','入門便喝絕商量，空奮雙拳立紀綱。',32,'全唐诗/poet.song.125000.json','["入門便喝絕商量，空奮雙拳立紀綱。", "反轉殺人三角眼，叢林千古受災殃。"]'),
('8d456a59-c88e-4f55-8777-c0b454ab0e62','頌古十三首  其一一','釋德光','宋','宋诗','song-poetry','','[]','師之一字見還難，直下應須透祖關。',32,'全唐诗/poet.song.125000.json','["師之一字見還難，直下應須透祖關。", "縱使祖關開正眼，前頭更有萬重山。"]'),
('467a234f-6481-4360-bf9e-bcfc1821ce48','頌古十三首  其一二','釋德光','宋','宋诗','song-poetry','','[]','親到龍潭不見龍，紙燈吹滅眼頭空。',32,'全唐诗/poet.song.125000.json','["親到龍潭不見龍，紙燈吹滅眼頭空。", "一條白棒掀天地，滅却西來達磨宗。"]'),
('61d5396c-159f-424a-b170-fc222cb3b2ea','頌古十三首  其一三','釋德光','宋','宋诗','song-poetry','','[]','法出姦生，垛生招箭。',32,'全唐诗/poet.song.125000.json','["法出姦生，垛生招箭。", "三脚馿子，是誰親見。", "若親見，釋迦老子那吒面。"]'),
('69a7b412-ac3a-41cb-b096-1c5da2b46c60','女真進千手千眼觀音像頌','釋德光','宋','宋诗','song-poetry','','[]','一手動時千手動，一眼觀時千眼觀。',32,'全唐诗/poet.song.125000.json','["一手動時千手動，一眼觀時千眼觀。", "自是太平無一事，何須弄出幾多般。"]'),
('7bfbe934-6a77-4bef-b5b5-9141e164923c','次韵張伯子餉柑','崔敦禮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','儒官窗戶寒，恇怯日出光。',144,'全唐诗/poet.song.125000.json','["儒官窗戶寒，恇怯日出光。", "獨冷不可耐，大杓傾鵝黄。", "洞庭隔烟波，忽驚風露香。", "開門問誰與，知君念荒凉。", "芳包照盤新，硬句摩天揚。", "山中千頭奴，丹黄麗秋陽。", "騷人巧採摘，燦燦簡冊方。", "君詩追古作，語壯韵轉彊。", "屬和郢中人，凋零不成行。", "臨風詠玉臺，噀霧開蜜房。", "殷勤此珍餽，玩味媿莫當。", "但酌潘公醽，一舉累十觴。"]'),
('9ae182b1-d939-4097-b537-65395ac47d09','對竹有感','崔敦禮','宋','宋诗','song-poetry','','[]','庭前抱節君，五年不見汝。',48,'全唐诗/poet.song.125000.json','["庭前抱節君，五年不見汝。", "去時雙玉槊，枝葉稀可數。", "歸來兒孫多，已滿寸金土。", "竹盛人凋零，攀枝淚如雨。"]'),
('7360195e-03b7-47e5-8832-a6a955ea1e5a','還孟郎中詩卷用元韻  其一','崔敦禮','宋','宋诗','song-poetry','','[]','吟哦兩夫子，濯濯春月柳。',48,'全唐诗/poet.song.125000.json','["吟哦兩夫子，濯濯春月柳。", "金石相擊撞，論文自爲友。", "我欲和陽春，高調不容口。", "披玩若爲稱，朝酣玉臺酒。"]'),
('cd64eb52-22e7-4415-b0d8-72608c42a1ed','還孟郎中詩卷用元韻  其二','崔敦禮','宋','宋诗','song-poetry','','[]','富貴邯鄲夢，齒髮金城柳。',48,'全唐诗/poet.song.125000.json','["富貴邯鄲夢，齒髮金城柳。", "附炎非吾事，因心即我友。", "得意自忘言，咸脢豈滕口。", "幸有君子交，淡成非醴酒。"]'),
('df203099-5b2e-4795-b50b-6482245fc4d3','嚴子文用范至能韻見贈再和','崔敦禮','宋','宋诗','song-poetry','','[]','燈花昨夜喜，詩成果符吉。',84,'全唐诗/poet.song.125000.json','["燈花昨夜喜，詩成果符吉。", "長跪讀新詩，繡筵鳴寶瑟。", "天公怪多取，未老雪滿櫛。", "出門會臞仙，戴笠卓午日。", "我無作詩工，而許編杜帙。", "珷玞混圭璋，蓬艾間粟秫。", "鷗社媿相從，敬行順風膝。"]'),
('8425f63f-6a33-478e-88a8-358efb997831','前用吉字韻問嚴子文疾再和問疾之詩不工甚矣既辱和章又承用吉字韻爲貺率爾繼作敬問起居公自謂平生不服溫劑此寡慾之驗也何恙不愈詩以見意','崔敦禮','宋','宋诗','song-poetry','','[]','日來間何闊，坐見月初吉。',84,'全唐诗/poet.song.125000.json','["日來間何闊，坐見月初吉。", "欲往扣齋扉，政恐勞取瑟。", "聞公清凈緣，巧笑却銀櫛。", "露骨秀寒松，烘晹嚥暖日。", "鍾乳無千兩，牙籤堆萬帙。", "愛詩屢忘餐，愛酒勤種秫。", "心安身自輕，却老非牛膝。"]'),
('1bf333db-11b1-4182-b082-7c77c3a0c19b','再訊問嚴子文疾','崔敦禮','宋','宋诗','song-poetry','','[]','清心止淵水，養性順杞柳。',48,'全唐诗/poet.song.125000.json','["清心止淵水，養性順杞柳。", "不信造物兒，能妨莫逆友。", "我當誦七發，瀾翻傾辯口。", "據几遂霍然，何辭未能酒。"]'),
('fd9212be-e646-4e71-aea4-4692ef037a63','泊福山港','崔敦禮','宋','宋诗','song-poetry','','[]','我舟欲渡風伯嗔，卷帆夜泊滄江津。',112,'全唐诗/poet.song.125000.json','["我舟欲渡風伯嗔，卷帆夜泊滄江津。", "江聲拍枕冷不寐，起看河漢無纖塵。", "須臾風定水波伏，江妃湧起明月輪。", "船頭把酒問明月，瓜丘枌社難忘情。", "狼山咫尺望可到，一水隔我三家村。", "明月問之寂無語，寒光耿耿如相親。", "明朝轉柂好風色，月暈北開箕有靈。"]'),
('c877c6d2-1e42-4432-9dfc-bccba6edceac','喜晴','崔敦禮','宋','宋诗','song-poetry','','[]','我貧可厭迴腸煎，負郭近有桑麻田。',160,'全唐诗/poet.song.125000.json','["我貧可厭迴腸煎，負郭近有桑麻田。", "入春十日九霪雨，夜聽瀧瀧愁不眠。", "雨師欺壓春無力，勾引頑陰朝復夕。", "丹杏夭桃凍不開，來牛去馬昏無色。", "曉來鼓舞耕桑民，長天洗凈清無雲。", "羲和鞭日從海底，照出浩蕩郊原春。", "呼兒買酒聚笑語，門前且無吏呼怒。", "今年麥飯滑流匙，更趁新蠶理襦袴。", "江頭烟樹晚戎戎，江南嬰笋春事豐。", "我亦行拋簪綬去，飽帆西上趁東風。"]'),
('45cf6cda-54b4-4e3c-b682-6f81fc5ea008','九日','崔敦禮','宋','宋诗','song-poetry','','[]','虎踞城邊九日臺，前年黄花何盛哉。',128,'全唐诗/poet.song.125000.json','["虎踞城邊九日臺，前年黄花何盛哉。", "去年今日瀨陽山，三徑荒蕪手自刪。", "今年到此百愁有，物情改盡花依舊。", "花不能言心自知，嚼蘂徘徊淚盈袖。", "黄花時節年年好，我生浩蕩何時了。", "櫛沐從教飽風雨，只恐飄零人易老。", "客中霜風吹我衣，隴頭白雲呼我歸。", "江湖僻處好歸隠，月上三更聞子規。"]'),
('5e33ac7b-818e-4772-844e-07b5beb86deb','送梁倅二首  其一','崔敦禮','宋','宋诗','song-poetry','','[]','盛德宜時用，屏星久此留。',48,'全唐诗/poet.song.125000.json','["盛德宜時用，屏星久此留。", "中和凝秬鬯，溫潤瑩天球。", "太府多材會，清名萬口流。", "亨塗應好在，端的上瀛洲。"]'),
('9d899627-25bf-4724-8d5e-8efe06b3b14e','送梁倅二首  其二','崔敦禮','宋','宋诗','song-poetry','','[]','一尉千官底，公無勢位分。',48,'全唐诗/poet.song.125000.json','["一尉千官底，公無勢位分。", "門牆時與進，道義得親熏。", "去矣難留佩，時哉盍致君。", "南風秣陵路，征旆卷行雲。"]'),
('f84d31e1-8b38-4acc-81aa-033401a7fa9b','喜晴','崔敦禮','宋','宋诗','song-poetry','','[]','頑雲收四野，皎日麗千門。',48,'全唐诗/poet.song.125000.json','["頑雲收四野，皎日麗千門。", "水響魚龍落，雲高鸛鶴翻。", "近陽書幌暖，遶室篆煙昏。", "擬欲尋春去，梅花水際村。"]'),
('1a21b8e9-0b07-4793-bc9c-7442b1dfe804','過三塔','崔敦禮','宋','宋诗','song-poetry','','[]','妙墨人間寶，千金紙上鷖。',48,'全唐诗/poet.song.125000.json','["妙墨人間寶，千金紙上鷖。", "頻來湖上寺，三復柱間題。", "鶴化辭遼海，鴻飛印雪泥。", "人豪今不見，凝佇夕陽西。"]'),
('c4d013ad-1f71-4850-98ef-98b7c4b94203','固城湖','崔敦禮','宋','宋诗','song-poetry','','[]','舟泊楚城下，當風十頃灣。',48,'全唐诗/poet.song.125000.json','["舟泊楚城下，當風十頃灣。", "凉生冰鑑面，人在玉壺間。", "隠見雲端樹，低昂枕上山。", "江湖有如此，一笑白鷗閒。"]'),
('0896624d-238d-4bdf-baba-6f308d0b737d','東壩','崔敦禮','宋','宋诗','song-poetry','','[]','前夜湖山月，今朝瀨水船。',48,'全唐诗/poet.song.125000.json','["前夜湖山月，今朝瀨水船。", "飄零良自苦，浩蕩有誰憐。", "雲合前村雨，風收別浦煙。", "乘凉趣歸櫂，咫尺是金淵。"]'),
('63a16a5d-b8c1-48d4-94be-5cd3fae04f0b','客枕','崔敦禮','宋','宋诗','song-poetry','','[]','客枕愁無寐，悠悠夜未分。',48,'全唐诗/poet.song.125000.json','["客枕愁無寐，悠悠夜未分。", "誰同對床雨，惟想太行雲。", "黄犬行應健，飛鴻過亦勤。", "如何萬金信，別久寂無聞。"]'),
('2480420c-00dd-417b-8a0f-5e9ddc379334','邵智卿挽章  其一','崔敦禮','宋','宋诗','song-poetry','','[]','列宿郎官帳，高風隠士廬。',48,'全唐诗/poet.song.125000.json','["列宿郎官帳，高風隠士廬。", "歲寒知勁柏，日暮厭輕車。", "德齒周三老，身名漢二疏。", "回頭八男子，玉立照階除。"]'),
('3bfa393a-2e6f-4134-a725-d4420796aa44','邵智卿挽章  其二','崔敦禮','宋','宋诗','song-poetry','','[]','未識嵇中散，聞詩孔伯魚。',48,'全唐诗/poet.song.125000.json','["未識嵇中散，聞詩孔伯魚。", "謂當從几杖，何意作丘墟。", "有道齊生死，無心任卷舒。", "斯人吾不見，遺恨淚沾裾。"]'),
('9c8964cf-963f-4ea4-af21-80282fb64b24','趙提官挽章  其一','崔敦禮','宋','宋诗','song-poetry','','[]','典型前輩近，問學古人深。',48,'全唐诗/poet.song.125000.json','["典型前輩近，問學古人深。", "有道祇藏韞，無言自陸沉。", "憂民空白首，愛主只丹心。", "遠矣平生志，松風掃墓林。"]'),
('dd5b735c-3259-482a-82c0-aa01805e1f9e','趙提官挽章  其二','崔敦禮','宋','宋诗','song-poetry','','[]','誠身古君子，耆德老先生。',48,'全唐诗/poet.song.125000.json','["誠身古君子，耆德老先生。", "言行純無玷，經書富滿籯。", "蘭階群玉秀，桂苑一枝榮。", "有後誰公比，文盟壓世英。"]'),
('8f7f6c3a-5be3-4549-90b2-e864e7d424d3','九月二十九日邇英開講忝預末班講退小集玉堂之廬即留宿直因賦唐律呈諸講官','崔敦禮','宋','宋诗','song-poetry','','[]','五雲扶輦下清廂，寶帙初開第一章。',64,'全唐诗/poet.song.125000.json','["五雲扶輦下清廂，寶帙初開第一章。", "旋卷班聯回廣殿，稍留笑語萃公堂。", "紫霄近侍連鑣過，黄髮元臣照座光。", "顧我自慚陪勝會，酒清人散卧斜陽。"]'),
('33f324b8-9b41-43a4-a0de-d06a8b830954','殿廬紀懷敬用右史舍人韻','崔敦禮','宋','宋诗','song-poetry','','[]','官柳陰陰密著行，飛來黄鳥忽成雙。',64,'全唐诗/poet.song.125000.json','["官柳陰陰密著行，飛來黄鳥忽成雙。", "身沾仙露香猶在，眼飽珍羞賜即扛。", "酒量不多容我醒，詩魔無奈得君降。", "官閒睡足春風幕，紅日三竿看上窗。"]'),
('25fc0557-f20f-4ee0-83b8-c939600bbb59','東宮壽章  其一','崔敦禮','宋','宋诗','song-poetry','','[]','少陽騰耀毓青宮，玉裕淵沖穆睟容。',64,'全唐诗/poet.song.125000.json','["少陽騰耀毓青宮，玉裕淵沖穆睟容。", "主鬯克承宸極重，問安勤致寢門恭。", "溫文齒胄全三善，暉潤登歌備四重。", "幼海光浮天序永，珠源衮衮日朝宗。"]'),
('970a9cd1-16e7-4864-bed5-a5da09c5b58e','東宮壽章  其二','崔敦禮','宋','宋诗','song-poetry','','[]','吹銅和氣集佳祥，鬰鬰葱葱震色蒼。',64,'全唐诗/poet.song.125000.json','["吹銅和氣集佳祥，鬰鬰葱葱震色蒼。", "山嶽東明開寶禁，星辰南極注瑶觴。", "龍樓照日浮秋曉，象輅朝天馥御香。", "分土莫陪班賀末，詠歌惟祝壽無疆。"]'),
('6e9a2e4f-c455-4ca2-8d75-12dd5d2fa349','至清口聞水閲甚盛邊人言辛巳歲敵騎逼淮劉信叔軍南岸欲載神勁弩至中流射之求數舟不可得今戰艦之盛前未有也因成四韻','崔敦禮','宋','宋诗','song-poetry','','[]','曉日旌旗錦滿川，阿童初試漢樓船。',64,'全唐诗/poet.song.125000.json','["曉日旌旗錦滿川，阿童初試漢樓船。", "露橈天與神機秘，擊楫人同壯志堅。", "行恐黄河冰可渡，已聞青海箭先傳。", "佛貍莫夢淮邊樹，看攬長蛟下沒淵。"]'),
('e4b1774d-2d77-477c-baea-3d19e51b1b5c','題婺州仁風堂寄韓侍郎  其一','崔敦禮','宋','宋诗','song-poetry','','[]','丹扆憂勤德意通，使君元侍玉皇宮。',64,'全唐诗/poet.song.125000.json','["丹扆憂勤德意通，使君元侍玉皇宮。", "親傳天上舜琴曲，散作人間莊籟風。", "已喜清微消滯鬰，亦知委曲到鰥窮。", "騷人休復雌雄問，千里而今樂事同。"]'),
('ed5911fd-73a4-4352-9192-6549308b6348','題婺州仁風堂寄韓侍郎  其二','崔敦禮','宋','宋诗','song-poetry','','[]','公餘燕寢但凝香，稍退朝來雁鶩行。',64,'全唐诗/poet.song.125000.json','["公餘燕寢但凝香，稍退朝來雁鶩行。", "政譽已爭銅嶺峻，恩波仍带繡川長。", "未應尚布春風詔，會許重賡夏日章。", "皎皎東陽嘉話在，到公端類發天藏。"]'),
('498c9388-30c3-4bff-b9f7-eeaea82fd805','江行迓憲使遇風','崔敦禮','宋','宋诗','song-poetry','','[]','星使乘槎勢若飛，微官奔走遂忘危。',64,'全唐诗/poet.song.125000.json','["星使乘槎勢若飛，微官奔走遂忘危。", "扁舟掀舞身如葉，短棹欹斜命綴絲。", "亂眼雲山疑醉夢，拍天波浪意蛟螭。", "西風送我歸漁浦，落日銜山未晚炊。"]'),
('cb6fcd26-fbb3-4dc8-9b00-924ee91c3c34','次韻孫撫幹二首  其一','崔敦禮','宋','宋诗','song-poetry','','[]','疏狂自許次公醒，冷淡無勞沸玉笙。',64,'全唐诗/poet.song.125000.json','["疏狂自許次公醒，冷淡無勞沸玉笙。", "滿屋文章天下樂，多情燈火夜深明。", "交情問我何清苦，世路愁人已飽更。", "好趁東風動行色，瀨陽煙雨趣春耕。"]'),
('139103cc-7d66-4942-97e9-553a75579148','次韻孫撫幹二首  其二','崔敦禮','宋','宋诗','song-poetry','','[]','繞几黄雲爇水沉，得詩閒讀契余心。',64,'全唐诗/poet.song.125000.json','["繞几黄雲爇水沉，得詩閒讀契余心。", "文章叔夜廣陵散，句法武侯梁甫吟。", "且喜空囊收趙璧，不慙擊壤混唐音。", "請君便入鷗鳴社，飯顆相從始自今。"]'),
('768a1280-f2ef-4de7-962b-3e6795498ac3','次陸倅韻三首  其一','崔敦禮','宋','宋诗','song-poetry','','[]','欲將從事到青州，酩酊鄉中便可侯。',64,'全唐诗/poet.song.125000.json','["欲將從事到青州，酩酊鄉中便可侯。", "此樂正須君領略，疏狂還許我追遊。", "一年好處都能幾，四序難并去莫留。", "痛飲且圖連夜醉，清歡何必錦纏頭。"]'),
('00f389d2-7d89-41c8-bce7-657054b0fbc8','次陸倅韻三首  其二','崔敦禮','宋','宋诗','song-poetry','','[]','煖烟和氣滿西州，載酒當輕萬戶侯。',64,'全唐诗/poet.song.125000.json','["煖烟和氣滿西州，載酒當輕萬戶侯。", "官事不知何日了，風光宜及早春遊。", "簿書叢裏偷閒去，景物妍時到處留。", "莫被虛名苦拘束，野梅官柳暗江頭。"]'),
('65d65cee-1178-47d0-ad17-8bce635b1e7c','次陸倅韻三首  其三','崔敦禮','宋','宋诗','song-poetry','','[]','文章光艷壓蘇州，照乘何勞詫魏侯。',64,'全唐诗/poet.song.125000.json','["文章光艷壓蘇州，照乘何勞詫魏侯。", "鳩杖欲尋江左勝，鷗盟相約社中遊。", "囊空自喜陶朱得，詩拙還因杜集留。", "把玩日吟心似醉，定須論月廢梳頭。"]'),
('1b111965-3136-4220-b336-aac675dbf47a','再次韻一首','崔敦禮','宋','宋诗','song-poetry','','[]','催花腰鼓徹凉州，午枕驚回蟻夢侯。',64,'全唐诗/poet.song.125000.json','["催花腰鼓徹凉州，午枕驚回蟻夢侯。", "頼有江山餘古意，可教詩酒負春遊。", "登亭舉酒休論晉，借筯成功合繼留。", "慷慨浩歌風日暖，萬山佳處接吳頭。"]'),
('3e22b9c5-ece3-4eac-9dfb-09b3d5dbe7a8','和沈商卿','崔敦禮','宋','宋诗','song-poetry','','[]','一官奔走倦幽尋，來向江山好處吟。',64,'全唐诗/poet.song.125000.json','["一官奔走倦幽尋，來向江山好處吟。", "過眼風光花又落，關情勳業鏡頻侵。", "到頭春事都無幾，飛蓋長郊早趁今。", "鷗鳥莫驚車馬過，我來搜句亦無心。"]'),
('33326991-d108-44d0-ba43-64890cf76d58','和章冠之','崔敦禮','宋','宋诗','song-poetry','','[]','光陰轉眼去如飛，閙過清遊正及時。',64,'全唐诗/poet.song.125000.json','["光陰轉眼去如飛，閙過清遊正及時。", "春事到今難著語，鳥聲無奈只催詩。", "日烘花氣侵軒戶，風晃江光入酒巵。", "回意總將西子看，對山終日未成癡。"]'),
('453e1284-e4e1-4b8e-8dda-7a785402082f','狼山','崔敦禮','宋','宋诗','song-poetry','','[]','裹了青衫簪了纓，此身便是一浮萍。',64,'全唐诗/poet.song.125000.json','["裹了青衫簪了纓，此身便是一浮萍。", "五年客路春風熟，千里鄉關夜月明。", "華鶴歸來驚物變，白狼依舊逼人清。", "山中老宿爭迎我，輯杖相呼問甲庚。"]'),
('8cdb3ba3-4ba6-4651-80f5-b5fb54933b38','龜山','崔敦禮','宋','宋诗','song-poetry','','[]','當年王氣擁神州，衮衮朝宗此地由。',64,'全唐诗/poet.song.125000.json','["當年王氣擁神州，衮衮朝宗此地由。", "自昔好山猶故色，只今清泗漫安流。", "蒼烟鎖合神仙府，宿蘚封深魍魎囚。", "病眼不堪重北望，西風揮淚下扁舟。"]'),
('27709074-69b7-47d7-aaf4-4bed9a79cc88','遊龜山','崔敦禮','宋','宋诗','song-poetry','','[]','舟行十日困拘拳，到此登臨意氣掀。',64,'全唐诗/poet.song.125000.json','["舟行十日困拘拳，到此登臨意氣掀。", "山斷蜂腰盤漢表，水分燕尾入淮門。", "石埋萬古英豪筆，洞鎖千年魍魎魂。", "懷昔感今無限意，夕陽人去亂鴉翻。"]'),
('75cd831d-bfba-4c3d-a1a7-123f728709ab','何家港捨舟步至新河口','崔敦禮','宋','宋诗','song-poetry','','[]','潮來白浪卷平沙，漸見菰蒲沒兩涯。',64,'全唐诗/poet.song.125000.json','["潮來白浪卷平沙，漸見菰蒲沒兩涯。", "會欲燃犀鞭魍魎，可能結網羨鱨鯋。", "三千水擊鵾鵬上，百萬軍行將士譁。", "驚歎漁人何活計，扁舟掀舞寄全家。"]'),
('140700ae-77df-498e-aea8-c39568e8acf3','聞嚴子文納妾孟守有詩輒次韻','崔敦禮','宋','宋诗','song-poetry','','[]','春市笙歌興已闌，儒宮牢落分投閒。',64,'全唐诗/poet.song.125000.json','["春市笙歌興已闌，儒宮牢落分投閒。", "不知列屋傾城蔡，自笑微官繫觸蠻。", "赤脚有年供侍側，青鸞無夢到人間。", "傳聞謫墮行雲侶，想像高唐鬢欲斑。"]'),
('7fa42695-a998-486a-a7df-e33fdba35ab5','挽太尉王權章','崔敦禮','宋','宋诗','song-poetry','','[]','將軍名字著華戎，露甲曾收不戰功。',64,'全唐诗/poet.song.125000.json','["將軍名字著華戎，露甲曾收不戰功。", "馬革裹尸忠貫日，虎頭食肉氣如虹。", "雲屯欲倚金城重，星隕俄驚玉帳空。", "好象祁連築新冢，鼓鼙遺恨意何窮。"]'),
('0b365a68-8453-4ce8-afd9-4cce3b330b5e','送芋酥與宿齋三學士','崔敦禮','宋','宋诗','song-poetry','','[]','酥盤薦酒迎春壽，芋火談禪數夜更。',32,'全唐诗/poet.song.125000.json','["酥盤薦酒迎春壽，芋火談禪數夜更。", "雲脚四垂天欲雪，爲君兩計破愁城。"]'),
('ec33dca2-701a-4b56-bcc5-09be9eb7195e','何家港捨舟步至新河口  其一','崔敦禮','宋','宋诗','song-poetry','','[]','夾岸蘆蒿障日微，拍堤波浪濺人衣。',32,'全唐诗/poet.song.125000.json','["夾岸蘆蒿障日微，拍堤波浪濺人衣。", "隔江喚得漁船過，貫柳雙鱸自買歸。"]'),
('0174d48e-2cea-4381-a3be-26e925c29c94','何家港捨舟步至新河口  其二','崔敦禮','宋','宋诗','song-poetry','','[]','郭公勾喚鰣浮水，閒客招要鷗上灘。',32,'全唐诗/poet.song.125000.json','["郭公勾喚鰣浮水，閒客招要鷗上灘。", "岸斷溪橫人不到，樹頭依約見桅竿。"]'),
('cd3bd7e5-0b9a-4185-be36-e3d6748ab5f6','何家港捨舟步至新河口  其三','崔敦禮','宋','宋诗','song-poetry','','[]','北岸行人南岸山，去年人在亂山間。',32,'全唐诗/poet.song.125000.json','["北岸行人南岸山，去年人在亂山間。", "山如相識須相笑，底事區區未得閒。"]'),
('a2f2ad6d-b942-48d1-b4d3-0f20a961c855','狼山  其一','崔敦禮','宋','宋诗','song-poetry','','[]','日日懷歸今得歸，舊時風物未全非。',32,'全唐诗/poet.song.125000.json','["日日懷歸今得歸，舊時風物未全非。", "江邊鷗鳥應相笑，底事塵埃滿客衣。"]'),
('839b4e7c-c643-4f46-b121-3745d9e4666d','狼山  其二','崔敦禮','宋','宋诗','song-poetry','','[]','貪戀微官未得閒，二年鄉夢遶狼山。',32,'全唐诗/poet.song.125000.json','["貪戀微官未得閒，二年鄉夢遶狼山。", "如今真箇山中去，不是尋常杳靄間。"]'),
('e9e2730a-58b1-4b9a-adda-0f8510dbfdb2','狼山  其三','崔敦禮','宋','宋诗','song-poetry','','[]','行携三尺虎臂杖，歸飲十分魚枕蕉。',32,'全唐诗/poet.song.125000.json','["行携三尺虎臂杖，歸飲十分魚枕蕉。", "飲罷招船歌一曲，馮夷亦合泣潛綃。"]'),
('c2d44dd9-af1f-4dca-9a37-9285310de8c3','狼山  其四','崔敦禮','宋','宋诗','song-poetry','','[]','夜靜無風水自波，隔江燈火數陵坡。',32,'全唐诗/poet.song.125000.json','["夜靜無風水自波，隔江燈火數陵坡。", "消樽不屬今宵事，奈此一江明月何。"]'),
('39c4b82d-f714-4cd5-9d18-388f9283f28a','狼山  其五','崔敦禮','宋','宋诗','song-poetry','','[]','五載龍蟠虎踞間，峯頭日月望狼山。',32,'全唐诗/poet.song.125000.json','["五載龍蟠虎踞間，峯頭日月望狼山。", "歸來筋力猶强健，野屐登臨莫厭艱。"]'),
('70db8986-3007-426d-963a-a571fe9cea6b','題得妙亭','崔敦禮','宋','宋诗','song-poetry','','[]','行見山橫坐見縱，山隨意好日無窮。',32,'全唐诗/poet.song.125000.json','["行見山橫坐見縱，山隨意好日無窮。", "朝來爽氣誰能會，渾在先生隠几中。"]'),
('ab0654eb-e658-4770-81e7-7d06599b7a27','探潮閣','崔敦禮','宋','宋诗','song-poetry','','[]','天留孤巘岌青冥，約束淮流入汴京。',32,'全唐诗/poet.song.125000.json','["天留孤巘岌青冥，約束淮流入汴京。", "往事不堪回首望，倚欄斜日看潮生。"]'),
('3252f48e-0e49-4916-96b0-9cb2071185ac','題避俗軒','崔敦禮','宋','宋诗','song-poetry','','[]','地僻便知城市隔，心清自愛水雲閒。',32,'全唐诗/poet.song.125000.json','["地僻便知城市隔，心清自愛水雲閒。", "障塵不用西風扇，香篆溟濛正下關。"]'),
('8fa93340-2f14-4010-b92f-d40b2ce042fb','題汗青軒','崔敦禮','宋','宋诗','song-poetry','','[]','地禁官清靜不譁，日長時試小團茶。',32,'全唐诗/poet.song.125000.json','["地禁官清靜不譁，日長時試小團茶。", "一生只用如椽筆，細爲君王紀正邪。"]'),
('d756cf4f-1d15-467a-81c1-d4242910b8a9','大閲回馬口號','崔敦禮','宋','宋诗','song-poetry','','[]','前驅小隊立元戎，一點台星喜氣濃。',32,'全唐诗/poet.song.125000.json','["前驅小隊立元戎，一點台星喜氣濃。", "凱奏歸來鈴閣靜，精神端已折遐衝。"]'),
('a018d360-847c-4d63-b740-b9b5901442ff','芸香亭','崔敦禮','宋','宋诗','song-poetry','','[]','竹間當日一亭幽，瀹茗焚香向此留。',32,'全唐诗/poet.song.125000.json','["竹間當日一亭幽，瀹茗焚香向此留。", "丹碧只今俱化出，獨來戀戀憶前遊。"]'),
('c2bfcdc5-2ed8-4534-8789-e967f7b97f99','密雲亭','崔敦禮','宋','宋诗','song-poetry','','[]','落花摇曳水溶溶，金現兜綿世界容。',32,'全唐诗/poet.song.125000.json','["落花摇曳水溶溶，金現兜綿世界容。", "只恐水流雲不見，桃源歸路却無蹤。"]'),
('366bba92-8d02-4023-b9e5-f904e70ed6d8','傲霜亭','崔敦禮','宋','宋诗','song-poetry','','[]','霜風吹慘入園林，零落階前滿地金。',32,'全唐诗/poet.song.125000.json','["霜風吹慘入園林，零落階前滿地金。", "頼有翠蕤堪採摘，伴人猶守歲寒心。"]'),
('18ff71f6-6a54-4d18-a843-95ac2510662e','丁亥歲予留建康夢登大橋仰視霄漢有金書閣字北斗落落布列其側昨夕夜直坐石渠橋忽見七星低昂正倚秘閣而金書大字儼然夢中所見信知世事皆有定分非偶然也  其一','崔敦禮','宋','宋诗','song-poetry','','[]','祕宇涵風寒淰淰，虛廊侵月靜冥冥。',32,'全唐诗/poet.song.125000.json','["祕宇涵風寒淰淰，虛廊侵月靜冥冥。", "寶章玉座神深地，應想誰何會百靈。"]'),
('12c495e1-30d3-425a-82dd-69d8e4eb1ed2','丁亥歲予留建康夢登大橋仰視霄漢有金書閣字北斗落落布列其側昨夕夜直坐石渠橋忽見七星低昂正倚秘閣而金書大字儼然夢中所見信知世事皆有定分非偶然也  其二','崔敦禮','宋','宋诗','song-poetry','','[]','青冥風露飛簷外，黄道星辰企翼邊。',32,'全唐诗/poet.song.125000.json','["青冥風露飛簷外，黄道星辰企翼邊。", "獨倚梧陰心自省，十年清夢故依然。"]'),
('6ab6ccdd-e4bc-4e1f-a30e-4302cdc6ff31','枕上','崔敦禮','宋','宋诗','song-poetry','','[]','輾轉孤燈夢不成，念家憂國總關情。',32,'全唐诗/poet.song.125000.json','["輾轉孤燈夢不成，念家憂國總關情。", "月明定到棠梨上，時有啁嘈格磔聲。"]'),
('c46a55a6-7a31-47a5-a9ae-caf7423f9c31','太祖皇帝師次陳橋受天命協人情爲聖皇武','崔敦禮','宋','宋诗','song-poetry','','[]','聖皇武，憺顯幽。',88,'全唐诗/poet.song.125000.json','["聖皇武，憺顯幽。", "震逾恭，翼微周。", "帝下顧，民噢咻。", "糜沸鼎，汎橫流。", "否其復，飛龍秋。", "挽天弧，建神矛。", "振汩陳，遏虔劉。", "漭然施，鴻祐休。", "熯以濡，羸者瘳。", "御皇極，凝前旒。", "徧臚歡，蕩岱丘。"]'),
('6b89ff7c-5750-436e-af77-76a5d42a6d24','劉鋹僭號嶺南虐其民潘美伐之俘以獻爲猛虎攫','崔敦禮','宋','宋诗','song-poetry','','[]','猛虎攫，噬海隅。',89,'全唐诗/poet.song.125000.json','["猛虎攫，噬海隅。", "跨嶠綿嶺，環爲鑪。", "流膏解節，民畢屠。", "帝怒惠顧，思往蘇。", "授以虣將，施天誅。", "長驅無垠，抵其郛。", "手援炎歊，吹以濡。", "長纓繫頸，來纍纍。", "撐骸膾肉，窮凶徒。", "觀城告社，咸嗟歔。"]'),
('7e33f0c6-7866-4db5-a3c9-66d749b72676','李煜不朝伐之煜降江南平爲震雷薄矣','崔敦禮','宋','宋诗','song-poetry','','[]','震雷薄矣，胡蠅之營。',134,'全唐诗/poet.song.125000.json','["震雷薄矣，胡蠅之營。", "彌江負淮，隩天險矣。", "寧曰我盡臣度，肅恭威靈。", "宇宙混同，一方阻。", "皇明建靈旗，下巨舳。", "震威而懷，靡事戕戮。", "王師如翰，至則速。", "風漰雷磕，奄其覆。", "哀哀逆儔，維喙乞降。", "欙車青蓋，朝帝鄉。", "妖氛殺翳，旋披攮。", "膏痿腥䐿，德澤滂。", "凱旋金聲，奏洋洋。", "煇燿萬國，俱向方。"]'),
('017c7290-4ecb-4cf2-a200-63ecb4d64754','太白遠遊','崔敦禮','宋','宋诗','song-poetry','','[]','人間不可以託兮，信長風而雲行。',371,'全唐诗/poet.song.125000.json','["人間不可以託兮，信長風而雲行。", "浩漫其將何之兮，悵飄忽而徂征。", "天生材以有用兮，思逢時而經綸。", "苦恩疏而媒勞兮，坐長歎以撫膺。", "雞聚族以爭食兮，鳳孤飛而無隣。", "璚草隠於深谷兮，層丘蔽以蒼榛。", "驊騮拳跼而不得食兮，蹇馿得志以鳴春。", "蝘蜓嘲龍兮魚目混珍，嫫母衣錦兮西施負薪。", "世道有此翻覆兮，誰察余之堅貞。", "塊獨處此幽默兮，乃龜息而虬蟠。", "不曠蕩以縱適兮，何拘攣以守常。", "將倚劍乎天外兮，欲掛弓於扶桑。", "以倥傯而爲巢兮，以虛無而爲場。", "運以大風之舉兮，假以摩天之翔。", "前期浩乎漫漫兮，浮四海而橫八荒。", "赤玉舄以東上兮，烟蒼蒼其逢山。", "逢羽人於天門兮，方瞳好其容顔。", "遺我書以鳥跡兮，讀不閒而三嘆。", "偶然值乎青童兮，綠髮雙雙其雲鬟。", "笑我學仙之晚兮，蹉跎凋乎朱顔。", "玉女飄飄而下兮，遺我以流霞之杯。", "稽首拜而自媿兮，棄世何其悠哉。", "隨風恣其飄揚兮，不知東走之迷。", "忽撫己而自笑兮，問南登之路岐。"]'),
('8d0b742b-d7f6-4fb8-be6e-97f7bc98e075','太白招魂','崔敦禮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','予爲謫仙兮，薄遊人間。',325,'全唐诗/poet.song.125000.json','["予爲謫仙兮，薄遊人間。", "傲岸不諧兮，世路艱難。", "折芳洲之瑶華兮，採瓊蘂入乎崑山。", "愁長安之不見兮，坐拂劍而長嘆。", "魂一去而欲斷兮，與春風而飄揚。", "飄揚其竟何託兮，造化爲之悲傷。", "於是帝命巫陽，若有一人。", "神氣黯然，精魂飛散。", "遲爾歸旋，乃下招曰，魂兮歸徠，無東無西，無南無北些。", "碧海之東，長鯨濆湧，不可以涉些。", "揚波噴雲，蔽天鬐鬛些。", "齒若雪山，掛骨於其間些。", "歸徠，去無還些。", "魂兮無南，南山白額窮奇貙貒些，牙若劍錯鬣如叢竿些。", "口吞殳鋋，目極槍櫓些。", "歸徠，飼豺虎些。", "魂兮無西，西當太白，橫絕峨嵋些。", "地崩山摧，天梯鈎連些。", "崢嶸崔嵬，朝虎夕蛇些。", "磨牙吮血，殺人如麻些。", "歸徠，行路難些。", "魂兮無北，北緣太行，嶝道峻盤些。", "馬足蹶側，車輪摧岡些，氣毒劍戟，嚴風裂裳些。", "歸徠，北上苦些。"]'),
('3d313a2a-4c3d-405c-91b9-9249be10bddd','九序','崔敦禮','宋','宋诗','song-poetry','','[]','春日兮繁鮮，車闐闐兮句曲天。',154,'全唐诗/poet.song.125000.json','["春日兮繁鮮，車闐闐兮句曲天。", "緪瑟兮拊鼓，滿芳菲兮瓊筵。", "朝霞爲羞兮沆瀣爲醴，瑶華玉饌兮錯雜而陳前。", "靈之來兮赤城空，駕白鶴兮御清風。", "群仙從兮哆哆，雲晻曖兮車隆隆。", "靈之去兮返太清，騎日月兮朝紫皇。", "下視九州兮塵泱茫，五嶽俎豆兮四溟杯觴。", "製瓊琚兮余衣，集芳蓀兮余裳。", "荷佩兮離離，蘭旌兮揚揚。", "欲往從兮未得，望夫君兮彷忀。"]'),
('22a62dd9-3f41-4764-8bb1-d0e1b3bb19d0','正曜','崔敦禮','宋','宋诗','song-poetry','','[]','若有人兮水中央，魚鱗衣兮白蜺裳。',144,'全唐诗/poet.song.125000.json','["若有人兮水中央，魚鱗衣兮白蜺裳。", "荃橈兮桂旗，欲女迎兮風薄之。", "神之駕兮兩龍，驂白黿兮蛟螭從。", "朝余陟兮三山，夕濟兮牛渚。", "神不來兮夷猶，使我心兮苦復苦。", "濯纓兮姑溪，結佩兮采石。", "誠不已兮幽通，信不墜兮物格。", "若有臨兮風颾颾，作莫雨兮愁江臯。", "神交兮意接，來不言兮去無迹。", "倏雨歇兮雲收，山青青兮水悠悠。"]'),
('b9d12ec6-5758-415b-82f0-76564f030f5a','華陽洞天','崔敦禮','宋','宋诗','song-poetry','','[]','雲冥冥兮疊嶂，君獨立兮山之上。',161,'全唐诗/poet.song.125000.json','["雲冥冥兮疊嶂，君獨立兮山之上。", "石嶝險兮水道寒，思夫君兮未敢言。", "無言兮皇皇，山阿之人兮告我以不難。", "木樛蔚兮下俯，石避礙兮行旁。", "余冠兮巍巍，余步兮逶遲。", "俛首非吾之願兮，斜徑其將安之。", "朝騁望兮昭亭，夕宿兮雙溪。", "網蕙茝兮爲蓋，葺蓀蘅兮爲車。", "欲騰駕兮高翔，恍導余兮上隮。", "揭北斗兮奠椒漿，簸南箕兮羞瓊蘂。", "靈欣欣兮顧余，亶正直兮爲神予。"]'),
('d64d493c-1c90-45ba-b7b2-c0977b098202','中水府','崔敦禮','宋','宋诗','song-poetry','','[]','汎汎兮吾舟，沛吾乘兮東流。',151,'全唐诗/poet.song.125000.json','["汎汎兮吾舟，沛吾乘兮東流。", "東流兮何之，有美人兮天一涯。", "烟杳杳兮南徐，雲連連兮北固。", "海何爲兮清明，江何爲兮流注。", "彼美人兮山之曲，鎮龍關兮轉陰軸。", "約束海若兮呵水馮，夏不苦雨兮冬不疾風。", "汙邪穰穰兮海沂阜豐，我民報事兮罔有不恭。", "采秀實兮山巔，擷芳馨兮澗底。", "霜秈兮水芒，蕙肴羞兮椒糈。", "神之格兮樂享，惚蜿蜿兮來止。"]'),
('59805fc8-3f31-44a5-b11c-2ad2b1b557b1','下水府','崔敦禮','宋','宋诗','song-poetry','','[]','鍾山崒兮江之湄，葯爲祀兮辛夷祠。',186,'全唐诗/poet.song.125000.json','["鍾山崒兮江之湄，葯爲祀兮辛夷祠。", "神乘白馬兮執素羽，朝與日出兮莫雲歸。", "噫嗟兮明神，烈烈兮用光。", "生乎疾盜兮奮不顧死，死焉助順兮赫然發靈。", "湛清尊兮明水，揚玉桴兮扣雷鼓。", "扣鼓兮如何，我欲言兮淚滂沱。", "懭有妖兮蟠中土，雜蘅臯兮穢蘭宇。", "豺豕兮人居，猰貐兮室廬。", "願神我福兮我祥，舉長矢兮射天狼。", "使河洛兮回波，令岱華兮還光。", "山蒼蒼兮水湯湯，神之威兮儼不忘。", "刳肝爲辭兮瀝血，陳神之聽兮聞不聞。"]'),
('512243c0-5c76-4390-aba1-dd1131ea208f','田間辭三首  其一','崔敦禮','宋','宋诗','song-poetry','','[]','朝余往兮東疇，景翳翳兮雲油油。',63,'全唐诗/poet.song.125000.json','["朝余往兮東疇，景翳翳兮雲油油。", "牛驅耕兮載泥重，鞭不前兮挽犁用。", "歲云暮兮暮維何，倉庚鳴兮布穀和。", "疾吾耜兮固吾耒，趣甘澤兮及時播。"]'),
('52b432cd-b5a0-411b-998f-d90531a3eb99','田間辭三首  其二','崔敦禮','宋','宋诗','song-poetry','','[]','我耕兮我田，雨浪浪兮雷填填。',76,'全唐诗/poet.song.125000.json','["我耕兮我田，雨浪浪兮雷填填。", "水漫漫兮種不下，出門見水兮淚滂沱。", "惠我晴兮疾耕而耨，螟敗之兮穎弗得秀。", "嗚呼，我無時違兮時不我予。", "時不予兮奈何，蹇無忘兮吾事。"]'),
('6f70b548-6e54-4c33-afc0-9e9c8e80361f','田間辭三首  其三','崔敦禮','宋','宋诗','song-poetry','','[]','數稻兮登場，牽牛兮入屋。',93,'全唐诗/poet.song.125000.json','["數稻兮登場，牽牛兮入屋。", "噭咷兮田家，歡迎兮稚子。", "三年力耕兮今逢年，庾則實兮庖有鮮。", "草藉兮陶盤，豳吹兮土鼓。", "握牛兮誰歌，和之兮余舞。", "樂復樂兮歲晏，冰雪集兮堂下。", "時亹亹兮不再，蓀何爲兮田野。"]'),
('f2d03c8c-1c40-4fa7-bd55-a0ecf46a9d6e','北山之英','崔敦禮','宋','宋诗','song-poetry','','[]','强敵驕兮晉多壘，忽登山兮望廷尉。',143,'全唐诗/poet.song.125000.json','["强敵驕兮晉多壘，忽登山兮望廷尉。", "風霾兮殺氣昏，突槍櫑兮亂鈎陳。", "予君麾兮從君鉞，戰陵西兮捍溪柵。", "虹食壘兮火焚旂，公之死兮去如歸。", "公有子兮憤爭先，勇沒地兮羞戴天。", "父死忠兮子死孝，令名揚兮日月照。", "物有始兮豈無終，得所歸兮孰如公。", "喜幸生兮畏義死，語昵昵兮顧妻子。", "草木盡兮糞土委，聞高風兮汗流趾。"]'),
('1ce32aed-bb96-4bb0-b8b3-e74b3818a8f3','楚州龍廟迎享送神辭  其一','崔敦禮','宋','宋诗','song-poetry','','[]','君之來兮殊廷，雷隆隆兮雨冥冥。',79,'全唐诗/poet.song.125000.json','["君之來兮殊廷，雷隆隆兮雨冥冥。", "從天吳兮罔象，紛萬怪兮如雲。", "若有妖兮震奔沛，吹逆浪兮揚羶腥。", "授天矛兮下討，披蒙霧兮祥氛。", "地平天靜兮日月清夷，我民蒙福兮萬年報事。"]'),
('3339c510-e15f-426b-b88d-d6e3bf5613b6','楚州龍廟迎享送神辭  其二','崔敦禮','宋','宋诗','song-poetry','','[]','辛楣兮葯房，蘭枅兮桂楹。',99,'全唐诗/poet.song.125000.json','["辛楣兮葯房，蘭枅兮桂楹。", "翼翼兮新宮，穆將進兮芳馨。", "柏實兮松液，芝華兮若英。", "奠瓊斚兮清酤，玉俎析兮嘉牲。", "雅聲兮遠姚，鏘和平兮鼓鐘紛。", "繁會兮竽笙，靈連蜷兮須摇。", "儐暗藹兮紛紜，潔我心兮恭事，靈欣欣兮燕寧。"]'),
('d1b33109-8b6e-4ae2-ba53-7772adc4d342','楚州龍廟迎享送神辭  其三','崔敦禮','宋','宋诗','song-poetry','','[]','君之去兮朱宮，乘飛雲兮御迴風。',111,'全唐诗/poet.song.125000.json','["君之去兮朱宮，乘飛雲兮御迴風。", "貝闕兮豐敞，金臺鬰兮穹隆。", "珠胎兮炫耀，周玉樹兮青葱。", "天琛兮水碧，衆寶萃兮玲瓏。", "良辰兮高燕，命馮夷兮展舞。", "鳴𪛌兮海童，群仙兮良待。", "君肯臨兮尚舂容，君不我留兮我心忡忡。", "眇清思兮眑眑，惠我民兮盍終。"]'),
('bc2f74fc-510f-457c-b59d-c59c56d966fa','擬津人歌','崔敦禮','宋','宋诗','song-poetry','','[]','吾之舟兮常虛以遊，哀樂喜怒兮一毫不留。',48,'全唐诗/poet.song.125000.json','["吾之舟兮常虛以遊，哀樂喜怒兮一毫不留。", "不與物涉兮駕空以浮，萬方覆却兮無觸吾舟。", "吾之舟兮常虛以遊。"]'),
('e35fb093-1c74-4505-a63a-f3ac0e7f4239','平江府餞丘知府致語口號','崔敦禮','宋','宋诗','song-poetry','','[]','薰風捲旆趣歸程，十萬兒啼滿路聲。',64,'全唐诗/poet.song.125000.json','["薰風捲旆趣歸程，十萬兒啼滿路聲。", "別恨江楓烟雨暝，愁雲沙草曉波平。", "毀鞭莫遂留行意，開宴聊伸戀德情。", "從此吳人頌遺愛，棠陰千里日敷榮。"]'),
('0003410a-4d12-4817-852d-94110f7b971b','宰餘杭游洞霄','趙公碩','宋','宋诗','song-poetry','','[]','野服蕭蕭款翠微，虛亭高敞射晴暉。',64,'全唐诗/poet.song.125000.json','["野服蕭蕭款翠微，虛亭高敞射晴暉。", "仙歸洞府雲煙冷，春入名山笋蕨肥。", "緩引壺觴聊自適，暫捐朱墨便忘歸。", "會須結屋山中住，始悟人閒萬事非。"]'),
('52357b2b-f117-4f76-8a41-cc378513ae00','慶元四年五月再游','趙公碩','宋','宋诗','song-poetry','','[]','舊時曾此覓仙緣，一別于今四十年。',64,'全唐诗/poet.song.125000.json','["舊時曾此覓仙緣，一別于今四十年。", "白髮重來嗟老矣，青山九鎖故依然。", "肩輿直入松閒路，洗耳還聽澗底泉。", "幽興未闌吟未就，半峯斜日下平川。"]'),
('15b36a63-70d2-4581-8035-9523f50c60b5','積雨初霽乘興邀王和叟趙久成二監郡遊南山飲於雲間閣因成一詩醉書於石壁','趙公碩','宋','宋诗','song-poetry','','[]','雲間飛閣倚崢嶸，煙外寒江墜鏡清。',64,'全唐诗/poet.song.125000.json','["雲間飛閣倚崢嶸，煙外寒江墜鏡清。", "絕巘高頭惟古木，斷崖直下只孤城。", "二年謾結巴南恨，萬里空縣楚客情。", "鼓吹不須催我去，夕陽猶傍遠山明。"]'),
('9d0e028a-c79f-430c-8ae6-3a5977459bf4','奉和郭使君遊光福寺雲閒閣二十韻','趙公碩','宋','宋诗','song-poetry','','[]','南龕幾百年，古木闞雲掩。',240,'全唐诗/poet.song.125000.json','["南龕幾百年，古木闞雲掩。", "崖傾千仞垂，路縣一線險。", "飛𤜴喜曾巔，羸驂怯虛塹。", "楓葉紅斕斑，松□翠摇颭。", "石皴風雨剝，殿古木□□。", "拂拭坐空巖，□□□□琰。", "江勢從何來，斗然不□□。", "憑危意欲飛，□□□□□。", "鳥鳴山更幽，□□翠□染。", "煙際漾漁舠，風前亂□檿。", "緩賞有餘歡，高懷無一□。", "尺璧非所寶，白圭焉受玷。", "入蜀莫言□，得郡亦云忝。", "□□長安□，猶勝山陽貶。", "平生足疎曠，寧復事拘檢。", "佳時方一來，薄日已半晻。", "雨餘□□深，月墮山樓黶。", "□重□□高，□護神光閃。", "□樂樂□□，君憂憂歲歉。", "□□□吳□，□□不□點。"]'),
('93d42ecf-468e-40ff-af03-8be9d98a5a82','持憲節登戴溪亭賦詩','芮煇','宋','宋诗','song-poetry','','[]','溪山之興無時盡，興盡名亭意可知。',64,'全唐诗/poet.song.125000.json','["溪山之興無時盡，興盡名亭意可知。", "出岫孤雲含細雨，投林宿鳥愛深枝。", "風流已是千年事，公案今成七字詩。", "短棹悠然隨所適，人生出處要如斯。"]'),
('4ada9601-e513-400f-b1f1-6851afd2ed8b','頌','葛郯','宋','宋诗','song-poetry','','[]','非心非佛亦非物，五鳳樓前山突兀。',32,'全唐诗/poet.song.125000.json','["非心非佛亦非物，五鳳樓前山突兀。", "艷陽影裏倒翻身，野狐跳入金毛窟。"]'),
('03b632e2-e796-4206-a872-ce245619c2ce','臨終偈','葛郯','宋','宋诗','song-poetry','','[]','大洋海裏打鼓，須彌山上聞鐘。',28,'全唐诗/poet.song.125000.json','["大洋海裏打鼓，須彌山上聞鐘。", "業鏡忽然撲破，翻身透出虛空。"]'),
('d09dd16a-6fe7-4c6f-ba8b-e9d9eca6ea30','偈','釋中仁','宋','宋诗','song-poetry','','[]','九十春光已過半，養花天氣正融和。',32,'全唐诗/poet.song.125000.json','["九十春光已過半，養花天氣正融和。", "海棠枝上鶑聲好，道與時流見得麽。"]'),
('d15044cc-8cac-4977-b638-d35833f241ad','舉狗子無佛性話頌','釋中仁','宋','宋诗','song-poetry','','[]','二八佳人刺繡遲，紫荆花下囀黄鸝。',32,'全唐诗/poet.song.125000.json','["二八佳人刺繡遲，紫荆花下囀黄鸝。", "可憐無限傷春意，盡在停針不語時。"]'),
('5f32d027-95e5-4b0a-b002-e840139536a1','舉與萬法爲侶因緣頌','釋中仁','宋','宋诗','song-poetry','','[]','秤鎚搦出油，閑言長語休。',24,'全唐诗/poet.song.125000.json','["秤鎚搦出油，閑言長語休。", "腰纏十萬貫，騎鶴上揚州。"]'),
('1ff807b6-d5ea-401c-8027-c3b82bd944cb','題江國錄先生石室','陳尚文','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','海甯邑屋千山環，幽人更愛山中山。',184,'全唐诗/poet.song.125000.json','["海甯邑屋千山環，幽人更愛山中山。", "山城已遠人烟寒，江君石室深巑岏。", "聞君十載棲長安，焉能斂翼縈巖巒。", "卧龍要自南陽蟠，東山不爲携紅顔。", "邇來側身天地間，不如一室中寬閒。", "探書禹穴萬卷完，養成霧豹非一斑。", "素琴無絃心自彈，泰山高高水潺潺。", "山中閴兮誰往還，雲無心兮抱幽關。", "青山白雲足爲侶，無心胡爲戀君宇，冷君衣裳潤君礎。", "人間歲月易今古，傅說一去不可佇。", "蒼梧何如出飛雨，不崇朝兮蘇九土。"]'),
('c64cb651-fe00-4d5b-9fed-987ea8d93847','試劍石','陳景肅','宋','宋诗','song-poetry','','[]','將軍大寶劍，磨久蒼崖斑。',48,'全唐诗/poet.song.125000.json','["將軍大寶劍，磨久蒼崖斑。", "一日試利刃，斷石倚兩山。", "倒枕泉水碧，生光斗牛丹。", "至今胡虜過，目顧骨先寒。"]'),
('cddcc4d0-baa8-4010-9a4a-3452ef8797f6','懷高東溪二首  其一','陳景肅','宋','宋诗','song-poetry','','[]','鑿泉莫太深，太深井難汲。',48,'全唐诗/poet.song.125000.json','["鑿泉莫太深，太深井難汲。", "登山莫太高，太高頂難立。", "山頂仰可觀，井淵俯可挹。", "那知鴻鵠飛，海杳無消息。"]'),
('5d105d2f-eeb5-46e1-bfeb-9fb5cf1c6839','懷高東溪二首  其二','陳景肅','宋','宋诗','song-poetry','','[]','諤諤東溪士，吹簫澗谷春。',60,'全唐诗/poet.song.125000.json','["諤諤東溪士，吹簫澗谷春。", "一別阻雲水，相思勞夢魂。", "五湖秋夜月，三島春空雲。", "璚標月夜見，玉唾雲閒聞。", "何當一返駕，吟弄終乾坤。"]'),
('95678d93-2442-4289-96cd-7dfdce8aa6f7','江左驛舍寄文湖','陳庸','宋','宋诗','song-poetry','','[]','雲水蒼蒼日欲闌，郵亭遥憶舊家山。',32,'全唐诗/poet.song.125000.json','["雲水蒼蒼日欲闌，郵亭遥憶舊家山。", "故人兩地分南北，幾度相思鬢爲斑。"]'),
('41546939-ba37-45f2-8069-5638464b3b1e','洪氏浴室院','陸楠','宋','宋诗','song-poetry','','[]','我聞色相本來空，人鏡須知在箇中。',64,'全唐诗/poet.song.125000.json','["我聞色相本來空，人鏡須知在箇中。", "已把太虛爲丈室，却將明月照心宮。", "浮雲翳掃三更後，素彩光流萬里同。", "休詫此堂能坐進，藩籬打破意無窮。"]'),
('17d4ea16-b91f-499e-92eb-5159dd173c0b','題妙庭觀','陸楠','宋','宋诗','song-poetry','','[]','聞說瑶池事渺然，那知此地有飛仙。',64,'全唐诗/poet.song.125000.json','["聞說瑶池事渺然，那知此地有飛仙。", "玉皇妙曲人何在，金鼎靈丹世莫傳。", "漫寫風姿□俗眼，空餘窟室奉爐烟。", "何時了却公家事，一洗塵襟訪洞天。"]'),
('b3ba885d-6d9c-48bd-bdfd-c5a3e4b20271','致爽軒','劉焞','宋','宋诗','song-poetry','','[]','團團竹色遶郊居，勾引清風百畝餘。',32,'全唐诗/poet.song.125000.json','["團團竹色遶郊居，勾引清風百畝餘。", "憶昔敲門蘇內翰，而今下馬范中書。"]'),
('7df257bb-5906-401d-a98b-8c150b129694','咏家史','羅杞','宋','宋诗','song-poetry','','[]','蔭資嘉木當知本，水餘甘泉必究源。',32,'全唐诗/poet.song.125000.json','["蔭資嘉木當知本，水餘甘泉必究源。", "憶昔東昭分以後，相傳瓜瓞世緜緜。"]'),
('fb7e9713-8017-41cf-a87a-da7156ccf410','在金陵宦邸別鄉友宋碧溪司訓','羅杞','宋','宋诗','song-poetry','','[]','十年顔範此睽違，邂逅郵亭亦解頤。',64,'全唐诗/poet.song.125000.json','["十年顔範此睽違，邂逅郵亭亦解頤。", "春滿臯皮君徹早，塵蒙章甫我歸遲。", "雲龍嘉會逢今日，雞黍真情憶舊時。", "明發愁爲江上別，依然回首各天涯。"]'),
('f30407a2-0427-439f-8c9a-e9aac9ee9b37','李白書堂','林桷','宋','宋诗','song-poetry','','[]','江風朝暮半晴陰，紺宇飛甍接翠岑。',64,'全唐诗/poet.song.125000.json','["江風朝暮半晴陰，紺宇飛甍接翠岑。", "手摘匏瓜曾未遍，身從鷗鷺得相尋。", "千年舞袖雲崖冷，幾度桃花春水深。", "猶有門前舊詩句，松風萬壑老龍吟。"]'),
('48304224-91d0-47bb-a99c-7c28c23f1ba9','題太白五松書堂  其一','林桷','宋','宋诗','song-poetry','','[]','翰林最愛五松山，長說千年未擬還。',32,'全唐诗/poet.song.125000.json','["翰林最愛五松山，長說千年未擬還。", "而我抗塵良自愧，來游只得片時閒。"]'),
('3d00dc60-250b-4130-9917-aa14658663bc','題太白五松書堂  其二','林桷','宋','宋诗','song-poetry','','[]','千載名山樂有餘，功名常愧十年書。',32,'全唐诗/poet.song.125000.json','["千載名山樂有餘，功名常愧十年書。", "英風凜凜無今古，醉草明光一夢如。"]'),
('171f5491-b94a-437f-8433-0052104adb96','題太白五松書堂  其三','林桷','宋','宋诗','song-poetry','','[]','蕩漾清溪兩槳飛，趨行不及到斜暉。',32,'全唐诗/poet.song.125000.json','["蕩漾清溪兩槳飛，趨行不及到斜暉。", "無人跪進雕胡飯，只學盧仝啜茗歸。"]'),
('6f734e6d-3e1b-48b1-b7e4-ab5b2b9024d6','題太白五松書堂  其四','林桷','宋','宋诗','song-poetry','','[]','爲儒爲吏兩無功，采石銅官邂逅同。',32,'全唐诗/poet.song.125000.json','["爲儒爲吏兩無功，采石銅官邂逅同。", "四見清明今一換，歸歟我欲片帆東。"]'),
('c43d068d-fe13-454a-a8a9-e3b56924200b','贈汪孝子','林桷','宋','宋诗','song-poetry','','[]','事死如生實至難，古來不獨數丁蘭。',64,'全唐诗/poet.song.125000.json','["事死如生實至難，古來不獨數丁蘭。", "遺骸已逐干戈盡，刻木難忘菽水歡。", "天地一身難養育，子孫百口復團圓。", "吾皇德澤將何報，忠孝垂名兩不刊。"]'),
('0ff2c458-a329-43c6-8fde-4794481328b5','贈汪孝子  其一','孟益','宋','宋诗','song-poetry','','[]','刻木爲親古亦稀，汪生天性自無違。',32,'全唐诗/poet.song.125000.json','["刻木爲親古亦稀，汪生天性自無違。", "十年奉養如生日，回視丁蘭更有輝。"]'),
('6cf3ccab-33fe-4ea8-80a4-92312a9db4fa','贈汪孝子  其二','孟益','宋','宋诗','song-poetry','','[]','循善無疑報自天，一身耆艾子孫蕃。',32,'全唐诗/poet.song.125000.json','["循善無疑報自天，一身耆艾子孫蕃。", "好將姓字聞朝著，旌市居爲孝弟村。"]'),
('0b0af89d-6377-42f1-9194-0015ec169dfa','挽李制幹','黄芻','宋','宋诗','song-poetry','','[]','先生雲卧在梅峰，胸飽珠璣貌自豐。',64,'全唐诗/poet.song.125000.json','["先生雲卧在梅峰，胸飽珠璣貌自豐。", "端坐渾如喬嶽象，傳經足並化工同。", "門前桃李春長在，身後勳名遠更通。", "見說義兵扶社稷，千年國史紀元功。"]'),
('347306c1-b777-4d21-9f94-6491fac349c6','南雁西洞','葉群','宋','宋诗','song-poetry','','[]','石門深窅鎖丹霞，倚馬西風日欲斜。',64,'全唐诗/poet.song.125000.json','["石門深窅鎖丹霞，倚馬西風日欲斜。", "幽境已無塵俗氣，白雲尚有翠微家。", "林間摘句書紅葉，澗底烹泉带落花。", "向晚且從西洞息，碧山明月正堪賒。"]'),
('115a9683-74ff-45e4-bfaf-f772f6b75f63','萬州湖灘寄王夔州','查籥','宋','宋诗','song-poetry','','[]','滿目暮山平遠，一池雲錦清酣。',28,'全唐诗/poet.song.125000.json','["滿目暮山平遠，一池雲錦清酣。", "忽有鐘聲林際，直疑夢到江南。"]'),
('7d2c07ef-1205-4949-86e7-06b89f5e82c4','題卧龍山','查籥','宋','宋诗','song-poetry','','[]','山顛祠貌儼丹青，千載懷人爲一登。',64,'全唐诗/poet.song.125000.json','["山顛祠貌儼丹青，千載懷人爲一登。", "隠隠故營連白帝，茫茫恨水向西陵。", "石根蘭芷香無價，雲頂松杉翠作層。", "人事天機古難料，詩成試語定中僧。"]'),
('86b94a24-bccf-4f80-9ecb-050684d5556f','訪蘇黄遺墨','查籥','宋','宋诗','song-poetry','','[]','檻外滔滔水，巖前冉冉雲。',48,'全唐诗/poet.song.125000.json','["檻外滔滔水，巖前冉冉雲。", "行人舟似葉，題墨蘚生紋。", "歲月帆檣去，山川楚蜀分。", "十年三艤棹，永愧北山文。"]'),
('71cd6e42-2fa0-4bca-949b-d0718929a172','句','查籥','宋','宋诗','song-poetry','','[]','浪痕自記岑彭□，岡勢云依陸抗城。',16,'全唐诗/poet.song.125000.json','["浪痕自記岑彭□，岡勢云依陸抗城。"]'),
('c5145f0b-2a79-468b-91e9-fb8020b6a029','挽薛艮齋','何伯謹','宋','宋诗','song-poetry','','[]','剴切憂時論，慈祥濟物心。',48,'全唐诗/poet.song.125000.json','["剴切憂時論，慈祥濟物心。", "賈生年尚少，平子慮何深。", "徒抱經綸志，俄聞訃告音。", "朔風傳薤挽，誰不淚霑襟。"]'),
('dd14cdf3-6fe0-425b-9b8b-db72495f5f26','庚子冬夜宿郡館懷白從古','章綸','宋','宋诗','song-poetry','','[]','高館天寒霜露濃，思君深隠翠微重。',64,'全唐诗/poet.song.125000.json','["高館天寒霜露濃，思君深隠翠微重。", "月華繞樹無飛鵲，雲氣蟠泥有蟄龍。", "石鼎賦詩猶脫略，銀燈看劍每從容。", "孤懷展轉不成寐，爲發城頭半夜鍾。"]'),
('36eabbf2-aaf4-4aa3-a0ec-76fc79ed6e52','句','廖挺','宋','宋诗','song-poetry','','[]','餘波下作雙溪水，只欠休文八詠樓。',16,'全唐诗/poet.song.125000.json','["餘波下作雙溪水，只欠休文八詠樓。"]'),
('e7096caf-da4c-4929-ad46-96851c7d9f73','高士峰','沈希尹','宋','宋诗','song-poetry','','[]','淡淡梨花寂寂春，一聲啼鳥隔花聞。',32,'全唐诗/poet.song.125000.json','["淡淡梨花寂寂春，一聲啼鳥隔花聞。", "高峰影轉金鷄月，渤海晴橫碧嶠雲。"]'),
('64ab7c09-85ad-4f7b-9486-301d7d55d98f','亦愛堂','童宗說','宋','宋诗','song-poetry','','[]','吾家小院千里駒，眉宇照人自秀整。',32,'全唐诗/poet.song.125000.json','["吾家小院千里駒，眉宇照人自秀整。", "平生尚友康山陶，拔俗翩翩有高騁。"]'),
('b550fbdb-8b7d-40b7-bbea-96cd75db1088','句','蔣雝','宋','宋诗','song-poetry','','[]','入寺門圍玉带水。',8,'全唐诗/poet.song.125000.json','["入寺門圍玉带水。"]'),
('45713126-1394-4a56-86a9-be48e5f2c4e7','姜山','任三傑','宋','宋诗','song-poetry','','[]','天風吹我登姜山，前巖後巖相封間。',64,'全唐诗/poet.song.125000.json','["天風吹我登姜山，前巖後巖相封間。", "已從積雨得深澗，更趁浮雲同往還。", "世外空青覆茅屋，屋外凉風吹紫竹。", "挂冠何日賦歸來，煮石篝燈洞中宿。"]'),
('70ea70f2-1c87-42f8-bd85-5dde4d7befd0','登岳陽樓  其一','蕭德藻','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','不作蒼茫去，真成浪蕩遊。',48,'全唐诗/poet.song.125000.json','["不作蒼茫去，真成浪蕩遊。", "三年夜郎客，一柁洞庭秋。", "得句鷺飛處，看山天盡頭。", "猶嫌未奇絕，更上岳陽樓。"]'),
('fa2a7b09-4b62-41d6-ba5e-c5555f019a1d','登岳陽樓  其二','蕭德藻','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','荒村三月不肉味，併與瓜茄倚閣休。',32,'全唐诗/poet.song.125000.json','["荒村三月不肉味，併與瓜茄倚閣休。", "造物於人相補報，問天賒得一山秋。"]'),
('94b74380-216b-4065-95df-9554460f78bf','呂公洞','蕭德藻','宋','宋诗','song-poetry','','[]','復此經過三十年，唯應巖石故依然。',64,'全唐诗/poet.song.125000.json','["復此經過三十年，唯應巖石故依然。", "城南老樹朽爲土，簷外稚松青拂天。", "枕上功名祗擾擾，指端變化又玄玄。", "刀圭乞與起衰病，稽首秋空一劍仙。"]'),
('9f673ecd-8fd5-42b3-aa3a-9e51585307cc','樵夫','蕭德藻','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u5199\u4eba", "\u751f\u6d3b", "\u5b8b\u8bd7"]','一擔乾柴古渡頭，盤纏一日頗優游。',32,'全唐诗/poet.song.125000.json','["一擔乾柴古渡頭，盤纏一日頗優游。", "歸來澗底磨刀斧，又作全家明日謀。"]'),
('0689398b-2e74-4277-8179-ec39e5e92125','立春','蕭德藻','宋','宋诗','song-poetry','','[]','半夜新春入管城，平明銅雀綠苔生。',32,'全唐诗/poet.song.125000.json','["半夜新春入管城，平明銅雀綠苔生。", "浮澌把斷東風路，訴與青州借援兵。"]'),
('f0e4edfe-c145-4d39-95d5-7f17fd6d71b9','古梅二絕  其一','蕭德藻','宋','宋诗','song-poetry','','[]','湘妃危立凍蛟背，海月冷挂珊瑚枝。',32,'全唐诗/poet.song.125000.json','["湘妃危立凍蛟背，海月冷挂珊瑚枝。", "醜怪驚人能嫵媚，斷魂只有曉寒知。"]'),
('97698daa-2a74-4cfc-8480-da5be95a2a94','古梅二絕  其二','蕭德藻','宋','宋诗','song-poetry','','[]','百千年蘚著枯樹，一兩點春供老枝。',32,'全唐诗/poet.song.125000.json','["百千年蘚著枯樹，一兩點春供老枝。", "絕壁笛聲那得到，直愁斜日凍蜂知。"]'),
('e4a27814-f1cb-4785-9c12-ad1d73d7722a','采蓮曲二首  其一','蕭德藻','宋','宋诗','song-poetry','','[]','清曉去采蓮，蓮花带露鮮。',24,'全唐诗/poet.song.125000.json','["清曉去采蓮，蓮花带露鮮。", "溪長須急槳，不是趁前船。"]'),
('f6dd7c61-7bc3-466f-ab9b-b0b7d8f79686','采蓮曲二首  其二','蕭德藻','宋','宋诗','song-poetry','','[]','相隨不覺遠，直到暮煙中。',24,'全唐诗/poet.song.125000.json','["相隨不覺遠，直到暮煙中。", "恐嗔歸得晚，今日打頭風。"]'),
('e0ca3cda-3320-43e0-a5dd-4ddcb35222a4','詠虞美人草','蕭德藻','宋','宋诗','song-poetry','','[]','魯公死後一抔荒，誰與竿頭薦一觴。',32,'全唐诗/poet.song.125000.json','["魯公死後一抔荒，誰與竿頭薦一觴。", "妾願得生墳土上，日翻舞袖向君王。"]'),
('9722195e-519f-4182-ac6b-f0387232ea83','次韻傅惟肖','蕭德藻','宋','宋诗','song-poetry','','[]','竹根蟋蟀太多事，喚得秋來籬落間。',64,'全唐诗/poet.song.125000.json','["竹根蟋蟀太多事，喚得秋來籬落間。", "又過暑天如許久，未償詩債若爲顔。", "肝腸與世苦相反，巖壑嗔人不早還。", "八月放船飛樣去，蘆花叢外數青山。"]'),
('ee92ebcf-9566-45e3-a507-c82ebe182a2f','臺城','蕭德藻','宋','宋诗','song-poetry','','[]','六朝舊事知多少，盡在天禧塔上層。',32,'全唐诗/poet.song.125000.json','["六朝舊事知多少，盡在天禧塔上層。", "高處只應添淚眼，老僧語客莫來登。"]'),
('a9e80104-0fe2-459d-bdfb-7eb3220ef0c6','句  其一','蕭德藻','宋','宋诗','song-poetry','','[]','信脚到太古。',22,'全唐诗/poet.song.125000.json','["信脚到太古。", "《誠齋集》卷一一四《詩話》ff。"]'),
