('e453a6d9-1ca4-4a84-9c11-748ed2d4cb33','句  其一二','蕭德藻','宋','宋诗','song-poetry','','[]','直須冰雪作梯媒。',8,'全唐诗/poet.song.125000.json','["直須冰雪作梯媒。"]'),
('f7741a36-83e8-4da6-9a84-1573f1b5befb','句  其一三','蕭德藻','宋','宋诗','song-poetry','','[]','不隨桃李待春回。',8,'全唐诗/poet.song.125000.json','["不隨桃李待春回。"]'),
('79da72ed-cc47-48ee-8f1d-1292d47737b1','待潮顧浦宿耕者張欽舍','顔發','宋','宋诗','song-poetry','','[]','海近雲氣昏，禹跡開茫茫。',144,'全唐诗/poet.song.125000.json','["海近雲氣昏，禹跡開茫茫。", "晴林列障邏，什伍屯平岡。", "頃遭七年旱，驟見九秋黄。", "腰鐮喜復悲，泥水新圃場。", "縣侯初下教，官賦無豐荒。", "錯揮製錦刀，戲作編氓創。", "身上催租瘢，短褐愁蓋藏。", "課爲五縣最，薦飛十剡章。", "逡巡掌邦計，跬步封侯王。", "江淮十萬師，待飼正頡吭。", "禾麥今已登，婦子戒勿嘗。", "行俟天雨粟，飽食均四方。"]'),
('8ec3b2fd-fb9d-4723-9867-6bfd0948af42','和蓋謙老遊馬鞍山','顔發','宋','宋诗','song-poetry','','[]','青鞋來踏馬鞍山，小徑縈紆便往還。',64,'全唐诗/poet.song.125000.json','["青鞋來踏馬鞍山，小徑縈紆便往還。", "眺望雙明窮晻靄，登臨終日得餘閒。", "冥搜直到風埃外，逸興徐來筆硯閒。", "錢挂杖頭堪一醉，歸來隨例带酡顔。"]'),
('62c94b57-ff1c-4d83-ab16-8560c596da93','題靈山壁','顔發','宋','宋诗','song-poetry','','[]','遊塵野馬皛晴光，僧舍無營日正長。',32,'全唐诗/poet.song.125000.json','["遊塵野馬皛晴光，僧舍無營日正長。", "看罷一枰天欲暮，不知何處起漁榔。"]'),
('b90800df-3af0-48af-845f-9078bbee839e','和山間壁上陳子忠  其一','顔發','宋','宋诗','song-poetry','','[]','路轉山根草木香，天容水色兩茫茫。',32,'全唐诗/poet.song.125000.json','["路轉山根草木香，天容水色兩茫茫。", "漁人風裏數聲笛，飛過蘆花幽興長。"]'),
('59f2d64d-b002-4020-ac9e-c1da0c7f3f2f','和山間壁上陳子忠  其二','顔發','宋','宋诗','song-poetry','','[]','風蒲水荇度清香，兩兩飛鳬墮渺茫。',32,'全唐诗/poet.song.125000.json','["風蒲水荇度清香，兩兩飛鳬墮渺茫。", "目送征帆掠波去，碧天無際暮雲長。"]'),
('4c4a7b65-806f-4edc-887f-7d1d667089a2','和陳尉春日行山','顔發','宋','宋诗','song-poetry','','[]','公餘春日長，亭午吏已退。',60,'全唐诗/poet.song.125000.json','["公餘春日長，亭午吏已退。", "山行步晴碧，松影踏鮮翠。", "杖移苔點穿，蜂抱花鬚墜。", "酒琖釋春愁，楸枰醒晝睡。", "行樂須及時，誰能六經醉。"]'),
('41a24aa2-59a6-4941-b2cd-f2091db2f325','登四明山','黄巨澄','宋','宋诗','song-poetry','','[]','會稽東南秀，四明名更佳。',156,'全唐诗/poet.song.125000.json','["會稽東南秀，四明名更佳。", "蜿蜒三百里，慘淡青蓮花。", "伊昔天地初，山川始萌芽。", "六丁揮神斧，斲削如人家。", "四牖遺古制，玲瓏吐雲霞。", "側聞劉樊徒，於此鍊丹砂。", "耕烟種青櫺，結實大如瓜。", "揮手謝衆士，身登鳳凰車。", "至今石窗底，青天守龍蛇。", "玉女四五人，綠鬢垂鬖髿。", "時來聽潺湲，意態靜不嘩。", "我夜闖其勞，月黑星如麻。", "顧慚無靈氣，悵望空咨嗟。"]'),
('e555fdb6-d6c9-4e3e-8eb8-29aaa9cdc1dc','題國清寺','劉知過','宋','宋诗','song-poetry','','[]','野人遊徧天台寺，究竟招提此最奇。',64,'全唐诗/poet.song.125000.json','["野人遊徧天台寺，究竟招提此最奇。", "十里遠排清蔭入，五峯如按畫圖窺。", "隋初便有高僧傳，火後都亡過客詩。", "重到定知非遠約，岸巾高處立多時。"]'),
('46997ee7-6094-4407-8bbb-c6e818e7505a','春日','劉知過','宋','宋诗','song-poetry','','[]','濃起香塵十里晴，晚來烟雨忽斜橫。',64,'全唐诗/poet.song.125000.json','["濃起香塵十里晴，晚來烟雨忽斜橫。", "花開花落清明候，山北山南杜宇聲。", "追念舊遊渾是夢，退思良計不如耕。", "人中喜有彌天釋，時吐清文慰此情。"]'),
('d0c2ab50-5dbc-41bb-b51d-423ecc1c4941','登泰山  其一','陳夢良','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','一躋尼父更誰登，扶日捫參紫翠層。',64,'全唐诗/poet.song.125000.json','["一躋尼父更誰登，扶日捫參紫翠層。", "四海兒孫向羅立，萬方稚子走香燈。", "獨將渾噩留天地，幾爲滄桑紀廢興。", "長嘯一聲空八表，恍疑鵬背坐來曾。"]'),
('a273b764-a082-4f79-99ac-95f710496b79','登泰山  其二','陳夢良','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','何處鸞笙鳳管清，覺來身世在蓬瀛。',64,'全唐诗/poet.song.125000.json','["何處鸞笙鳳管清，覺來身世在蓬瀛。", "龜蒙鳬嶧爭趨勢，恒霍嵩華共仰兄。", "封禪幸無書獻納，洞天尚有路通名。", "自慚游興非司馬，不扣天門空此生。"]'),
('0133fba0-f569-4f73-88fc-3b5068d4569f','句','陳輝','宋','宋诗','song-poetry','','[]','根枝不入靈和殿，枉爲人間拂馬蹄。',16,'全唐诗/poet.song.125000.json','["根枝不入靈和殿，枉爲人間拂馬蹄。"]'),
('7d2b1326-a62d-4916-b640-921139f413ac','題琴堂','孫祖德','宋','宋诗','song-poetry','','[]','一曲重彈子賤琴，三年風月總知音。',32,'全唐诗/poet.song.125000.json','["一曲重彈子賤琴，三年風月總知音。", "休言無補公家事，留得堂前竹樹陰。"]'),
('5526e7e1-7edd-4964-8661-bbd4f7df24d1','絳溪','鄭城某','宋','宋诗','song-poetry','','[]','一带波光遶翠屏，森森萬木擁幽清。',32,'全唐诗/poet.song.125000.json','["一带波光遶翠屏，森森萬木擁幽清。", "小臣已作□□想，願賦中興頌聖明。"]'),
('8d6905fa-5b7c-477b-b334-6ccbbee72388','碧落洞','陳煥子弟','宋','宋诗','song-poetry','','[]','碧落他年訪舊遊，摩挲蒼蘚又從頭。',32,'全唐诗/poet.song.125000.json','["碧落他年訪舊遊，摩挲蒼蘚又從頭。", "懸崖縱有詩千首，直許蘇陳占上流。"]'),
('443a90e8-581f-4326-9eb1-53eb0fedde21','帥潭日勸駕詩','劉珙','宋','宋诗','song-poetry','','[]','十載湘江守，重來白髮垂。',48,'全唐诗/poet.song.125000.json','["十載湘江守，重來白髮垂。", "初無下車教，再賦食苹詩。", "天闊摶鵬翼，春融長桂枝。", "功名儻來事，大節要堅持。"]'),
('20af9ab9-4782-4c60-82bb-1068b141c3a2','送元晦','劉珙','宋','宋诗','song-poetry','','[]','翩翩雙黄鶴，結巢相因依。',132,'全唐诗/poet.song.125000.json','["翩翩雙黄鶴，結巢相因依。", "一爲天風便，矯翮西北飛。", "歲華及晼晚，霜露侵征衣。", "此行亦良苦，千里以爲期。", "堂上玄髮親，榮祿當及茲。", "人生會有役，不復情凄洏。", "徘徊都門道，欲語行且遲。", "念子抱孤桐，窈窕弦古詞。", "清商奮逸響，激烈有餘悲。", "不辭彈者勞，正恐知音稀。", "知音何足貴，我顧不可追。"]'),
('914c609b-35ea-45b7-b212-3e31f96c21da','紹興辛巳秋過浯溪誦簡齋詩因用其韻','陳從古','宋','宋诗','song-poetry','','[]','浯溪一股寒流碧，聳起雙峰如削壁。',96,'全唐诗/poet.song.125000.json','["浯溪一股寒流碧，聳起雙峰如削壁。", "兩公文墨照溪津，到今草木增顔色。", "想當忠憤欲吐時，盡把江山供筆力。", "我來弔古不勝情，豈但登臨愛泉石。", "漁陽舊事忍再論，僅頼令公安反側。", "書生百感夜不眠，起讀新詩轉悽惻。"]'),
('d517e687-033c-4cd2-bc9c-7bb81c03c59c','重過浯溪','陳從古','宋','宋诗','song-poetry','','[]','小憩𢈪亭上，悠然倚一枝。',48,'全唐诗/poet.song.125000.json','["小憩𢈪亭上，悠然倚一枝。", "雲埋漫郎宅，水落魯公碑。", "興廢悲前古，登臨記昔時。", "重來頭已白，忍看舊題詩。"]'),
('8d5e3951-9749-4cac-afd1-76b5b95f60e1','句  其一','陳從古','宋','宋诗','song-poetry','','[]','多情今夜月，送我到衡州。',12,'全唐诗/poet.song.125000.json','["多情今夜月，送我到衡州。"]'),
('a0b707f5-b005-4d49-9f22-4b639e6b481f','句  其二','陳從古','宋','宋诗','song-poetry','','[]','半夜打篷風雨惡，平明已失繫船痕。',16,'全唐诗/poet.song.125000.json','["半夜打篷風雨惡，平明已失繫船痕。"]'),
('a507c091-2448-47d6-b71a-54f8071f885b','句  其三','陳從古','宋','宋诗','song-poetry','','[]','禮部又開南省榜，賣花羞聽叫文官。',16,'全唐诗/poet.song.125000.json','["禮部又開南省榜，賣花羞聽叫文官。"]'),
('6457943a-e5c0-48b1-bdc8-cb6e3552096c','詩一首','葉衡','宋','宋诗','song-poetry','','[]','東家屋被西家蓋，仔細思量無利害。',32,'全唐诗/poet.song.125000.json','["東家屋被西家蓋，仔細思量無利害。", "他時折屋別陳詞，如今且以壁爲界。"]'),
('7b6207b3-bff5-4a36-a6e4-4d065037c01a','寶乘寺','葉衡','宋','宋诗','song-poetry','','[]','巍巍畫棟插晴空，時有芳馨四面通。',64,'全唐诗/poet.song.125000.json','["巍巍畫棟插晴空，時有芳馨四面通。", "好爲高禪參鼻觀，未應公子闘薰籠。", "簾前一炷沉檀暈，窗外數番蘭蕙風。", "信道杜陵佳句在，心清渾賦此堂中。"]'),
('1ef1706b-68da-4ab5-a12c-cf1f2c390d82','鹿田寺集杜五言','葉衡','宋','宋诗','song-poetry','','[]','水花分塹弱，山木抱雲稠。',24,'全唐诗/poet.song.125000.json','["水花分塹弱，山木抱雲稠。", "更宿招提境，還同惠遠遊。"]'),
('2f90aa30-2fdc-4b74-8803-d526b93c999e','崑山呂正之三男子連中神童科蓋奇事也次嚴別駕韻','葉衡','宋','宋诗','song-poetry','','[]','三秀標姿穎不凡，姓名聯列紫微間。',64,'全唐诗/poet.song.125000.json','["三秀標姿穎不凡，姓名聯列紫微間。", "已知鳳穴梧棲穩，誰謂鵬程雲路艱。", "孔釋當年親抱送，由莊逸駕定追攀。", "發揮更有文章伯，高壓淮南大小山。"]'),
('410ea1e0-e2b6-401f-bcc2-26d494543661','題君山愛松軒','李呂','宋','宋诗','song-poetry','','[]','青青窗外松，高下如羽蓋。',72,'全唐诗/poet.song.125000.json','["青青窗外松，高下如羽蓋。", "不論霜雪晨，屹立風雨外。", "深根養茯苓，千歲坐可待。", "世情苦炎凉，一日幾變態。", "此物獨堅貞，雅志在久耐。", "清聲萬壑傳，時奏莊生籟。"]'),
('7435cb5c-3d80-44bf-902b-f6cb08e418bb','陪晦翁遊玉澗','李呂','宋','宋诗','song-poetry','','[]','夜琴響空山，臨流水方折。',36,'全唐诗/poet.song.125000.json','["夜琴響空山，臨流水方折。", "老仙何處來，欣賞共清絕。", "不知盧仝家，還有許風月。"]'),
('cc48a880-9ed6-481d-a020-5a2c179ee9a9','抱膝庵','李呂','宋','宋诗','song-poetry','','[]','青山不世情，終日獨我顧。',120,'全唐诗/poet.song.125000.json','["青山不世情，終日獨我顧。", "修竹歲寒姿，不受纖塵污。", "開窗寄數椽，良以二者故。", "出門欲求益，擿埴未識路。", "屠酤難與語，餘子安足數。", "豈無王侯家，摇尾覬一遇。", "自分踈懶性，初非俳優具。", "由來勢利交，朝且不保暮。", "何如翳環堵，靜對古人語。", "從渠不我與，聊復吟梁甫。"]'),
('31c6536d-4da6-49cd-94d9-f2d202416cd5','送高丞別','李呂','宋','宋诗','song-poetry','','[]','君侯七閩英，學問早有餘。',255,'全唐诗/poet.song.125000.json','["君侯七閩英，學問早有餘。", "年時猶未冠，鼓篋游上都。", "文成筆五色，四海仰名譽。", "調丞尉江邑，有實不願圖。", "朅來對二松，清襟映冰壺。", "粹然眉睫間，未變庠序儒。", "胸中浩然氣，固已雄萬夫。", "我窮卧洲渚，江鷗以爲徒。", "屢枉高軒過，峩冠講唐虞。", "馳騁文史樂，時得陪卷舒。", "瓜代遽及期，此情將焉如。", "恥作兒女態，揮淚沾衣裾。", "虎溪豈限我，足創方趦趄。", "悵望不遠送，搔首空躊躇。", "所覬善行李，早達三山隅。", "安居未容久，快作朝省趨。", "用賢世所急，君才應時需。", "願補仲山衮，再矢皋陶謨。", "勿以得失慮，行當翱天衢。", "愧乏折箠贈，短篇見區區。", "他時舊交念，闊{門扁}寄樵漁。"]'),
('346b624e-b10c-46f8-a675-b15157661c8e','乙巳四月比屋多疹痘瘧痢間作五月盡猶未已病者延綿在寢治療不獲其法往往失生理殊可憫痛乃作民病書事一首以紀之','李呂','宋','宋诗','song-poetry','','[]','去年秋冬交，白晝雷虺虺。',288,'全唐诗/poet.song.125000.json','["去年秋冬交，白晝雷虺虺。", "隆冬忽暄燠，青紅開百卉。", "雨澤不時下，快雪傾復霽。", "井泉傍射鮒，澗水通一遂。", "春風二月前，行人汗流背。", "倏來夏初中，遽變素商氣。", "稻穀已三布，時過未鍼水。", "複衣日猶寒，重衾夜增被。", "燮理失其節，老弱生疵癘。", "疹痘無間然，否則得痎痢。", "十室聞九病，顔色非人類。", "明晨溫風屆，風候尚云爾。", "祇愁淫雨歇，炎威火爭熾。", "爍石更流金，暴烈摧萬彙。", "皇天本至仁，長懷好生意。", "恢網踈不漏，蓋高卑聽視。", "夫誰執其柄，悖謬乃倒置。", "感召厥有由，下民亦何罪。", "我欲借扶摇，剖心叩玉陛。", "九關羣虎守，未許凡骨詣。", "願天回光鑒，肅正天之紀。", "甲庚先後三，寒暑無驟至。", "春榮不妄施，秋斂仍合義。", "四序蔑侵陵，功成順常理。"]'),
('394426ce-4006-4717-9e6e-fc6e977dc7d3','和許尉仙田舍野老有可憐之態壁間之什','李呂','宋','宋诗','song-poetry','','[]','乞糴民宵征，出糶官夙駕。',156,'全唐诗/poet.song.125000.json','["乞糴民宵征，出糶官夙駕。", "艱食間填壑，災星未退舍。", "七閩况多山，厥田惟中下。", "年登穀粟賤，逐末貪白話。", "一逢歲不稔，大半爲饑者。", "公私久匱乏，誰歟可資藉。", "哀哉南畝農，長年服耕稼。", "傾囷了租賦，僅逃吏胥駡。", "東作已無糧，貪賒寧論價。", "負逋罄産償，求售忘早夜。", "逡巡生計盡，失所安足訝。", "尉仙明達人，出語補風化。", "咄彼兼并家，斂衽當愧謝。"]'),
('711e2a4b-e54b-4729-9975-5dfcd6bec1e1','喜入杉嶺','李呂','宋','宋诗','song-poetry','','[]','行盡山嶺頭，歡喜入鄉關。',288,'全唐诗/poet.song.125000.json','["行盡山嶺頭，歡喜入鄉關。", "憶昨冒雨去，寒澀亦多端。", "自登糧綱船，出入狗竇寬。", "水漲泊無岸，水落淺湊灘。", "直待風水順，摇艣離江灣。", "虺蜴微細物，託龍逞神姦。", "篙工精禱罷，頃刻過千山。", "脫或小不契，風波生坐間。", "竄身輙拘滯，伍噲仍比頑。", "疑慮狐涉冰，進退羊觸藩。", "僅得黄義叟，可與話歲寒。", "論文消永日，長歌當夜闌。", "傳聞白水發，川途阻瀰漫。", "余益動歸心，掉首辭彎跧。", "悵懷陶靖節，不肯效一官。", "况爲太倉鼠，蠶食殊未安。", "肩輿走泥塗，僕夫愁險艱。", "附舟計已左，且復行路難。", "見幾恨不早，興盡而知還。", "明朝得善達，那假生羽翰。", "稚子爭候門，細君捲簾看。", "真樂未渠央，茅簷共團圞。", "尚論數千歲，窺管才一斑。", "稍定理殘編，補綴令可觀。"]'),
('10fdee16-3832-41fb-bd46-27abc33ff968','題吳微仲常齋','李呂','宋','宋诗','song-poetry','','[]','人心非無常，自爲外物禁。',96,'全唐诗/poet.song.125000.json','["人心非無常，自爲外物禁。", "喜怒烈火熾，寵辱銛鋒森。", "從茲失本然，至理而浮沉。", "達人解其會，魔軍詎能侵。", "盤石可轉移，明月猶晴陰。", "卓然有所立，此道古與今。", "顔淵無終食，孟子不動心。", "充君名齋志，前修端可尋。"]'),
('0cb73ff2-bc47-4a2c-afa0-00f64799a614','題伯丈人黄待制歸來堂','李呂','宋','宋诗','song-poetry','','[]','君子重進退，大節貴能全。',48,'全唐诗/poet.song.125000.json','["君子重進退，大節貴能全。", "厥志在冥鴻，耳非聞杜鵑。", "縣車示優寵，揮金樂耆年。", "高風激貪懦，千載要齊肩。"]'),
('79c1b6a0-905d-4aed-8433-e7cab20b75b3','送吳晦叔赴廷試','李呂','宋','宋诗','song-poetry','','[]','我昔遊白鶴，山川氣雄深。',168,'全唐诗/poet.song.125000.json','["我昔遊白鶴，山川氣雄深。", "邂逅識吾子，戛然唳孤音。", "日日望飛鳴，洄洑迺至今。", "玉美出堅璞，木老生喬林。", "書生未足道，聊用慰苦心。", "始駕百斛船，掛帆發江潯。", "破浪當自茲，意象殊駸駸。", "天方拓王度，清問虛宸襟。", "調毫寫胸臆，氣力戈鋋森。", "荷衣縛異時，恐爲寒蟬瘖。", "江城惜此別，風雪作晝陰。", "何以託遠懷，酌酒拊劍鐔。", "湖海氣摇薄，激烈愁端侵。", "唯應白雲夢，夜夜飛遥岑。"]'),
('1915a757-6ab5-4fb9-b943-38469f6305b1','勉諸子','李呂','宋','宋诗','song-poetry','','[]','孔子昔當戹，良以桓魋故。',204,'全唐诗/poet.song.125000.json','["孔子昔當戹，良以桓魋故。", "韓信伏胯下，將壇起徒步。", "聖賢昔未遇，未免失常度。", "固知天地寬，出門多齟齬。", "貧賤勢易陵，動息要衡慮。", "綈袍戀故人，進食哀漂母。", "小人不及夕，焉知鴻鵠舉。", "桃花倚春風，零落隨夜雨。", "流螢曳殘光，未省羲和馭。", "君子並松柏，挺幹傲寒暑。", "昭然揭日星，進與衆瞻睹。", "群兒勤修讀，文行師邃古。", "莫學小兒輩，啾啾燕雀語。", "顔淵犯不校，萬世共尊許。", "孟子善養氣，策功不下禹。", "潢潦無根源，勿用遽歆慕。", "吾言可書紳，審思宜在汝。"]'),
('415b6bce-fece-40ac-86a9-4240a805d434','遣興','李呂','宋','宋诗','song-poetry','','[]','生人無喜怒，喜怒由外觸。',48,'全唐诗/poet.song.125000.json','["生人無喜怒，喜怒由外觸。", "平地有風波，安居多鴆毒。", "緬懷先哲士，每用此理燭。", "顔子不貳遷，所樂一瓢足。"]'),
('3c9f7486-d272-4ffa-af65-ef35c3d04cca','題少室故居','李呂','宋','宋诗','song-poetry','','[]','拾遺舊隠居，一畝長蓬蒿。',72,'全唐诗/poet.song.125000.json','["拾遺舊隠居，一畝長蓬蒿。", "在昔考槃初，擇勝得無勞。", "羊腸罕人迹，丘壑方自豪。", "鳳凰景星覩，奔走紛兒曹。", "屈伸固相感，舒卷隨所遭。", "莫言從此去，索價遽能高。"]'),
('4f7bf712-7bb5-492f-ae01-f038659b760b','近世飲者尊尚苦味有感成詩','李呂','宋','宋诗','song-poetry','','[]','悠悠古先酒，麴糵化爲醴。',264,'全唐诗/poet.song.125000.json','["悠悠古先酒，麴糵化爲醴。", "適口固匪他，詩人詠其旨。", "岐黄作本草，甘辛味所紀。", "惟清香滑辣，四事世云爾。", "孟詵注爲苦，自不燭厥理。", "至今蔑公論，遂以詵爲是。", "乖僻隨躭嗜，不爾遽遭詆。", "氣稟炎上作，無與諸膽比。", "人情素弗食，嘗者爲雪恥。", "柳家集衆葯，意在勗諸子。", "未聞無其故，反以彼爲美。", "一呷三掉頭，强嚥身聳起。", "從來好歡伯，可畏非可喜。", "孤負太和名，翻作攪腸水。", "因思俗顛倒，類此蓋多矣。", "大路指爲迂，曲徑偏踐履。", "鄭聲既可惡，滿市更盈耳。", "憔悴間姬姜，一蕕雜蘭芷。", "貪濁和者衆，獨清競萋菲。", "善惡久相淆，何特酒而已。", "至當終難掩，豈必隨風靡。", "革弊會有時，周道本如砥。"]'),
('46209b97-36ff-47a0-9ae2-848e4bb65e2d','見諸公古風有感而和','李呂','宋','宋诗','song-poetry','','[]','吾慕嚴子陵，躬耕寄事外。',84,'全唐诗/poet.song.125000.json','["吾慕嚴子陵，躬耕寄事外。", "弗聽有道舉，安得從郭泰。", "恥因粟五斗，陶令腰束带。", "三賢甘寂寞，舉世惜機會。", "是心本通明，忍把客塵蓋。", "洗耳潁陽水，要使聞清籟。", "紛紛難與言，簡篇猶可頼。"]'),
('11178c64-1186-497b-946b-08da2ee4cd82','適見諸公詠梅之什因用其韻率作者同賦','李呂','宋','宋诗','song-poetry','','[]','影落林塘凹，斜入茅簷角。',48,'全唐诗/poet.song.125000.json','["影落林塘凹，斜入茅簷角。", "月黑縞袂逢，天寒翠袖薄。", "世無杜陵人，清吟久零落。", "詩魂不可招，遠水誰當酌。"]'),
('5fe7b4a1-bee3-46ca-85c0-4e2a86dc6576','復次韻二首  其一','李呂','宋','宋诗','song-poetry','','[]','首出萬物表，翠芳誰與角。',48,'全唐诗/poet.song.125000.json','["首出萬物表，翠芳誰與角。", "正色淡無邪，天香清不薄。", "舊時對花飲，寧恨霜月落。", "老作花下僧，瀹茗當杯酌。"]'),
('f4c66b07-1d88-43b3-afad-5f055eb06058','復次韻二首  其二','李呂','宋','宋诗','song-poetry','','[]','元是第一花，何用爭頭角。',48,'全唐诗/poet.song.125000.json','["元是第一花，何用爭頭角。", "桃李待春風，妖嬈恣輕薄。", "幽人似歸鴻，浩氣胸磊落。", "感此歲寒枝，悠然成獨酌。"]'),
('0ecc7477-75ac-4251-8fbe-6d05a35ae9af','追挽游大夫','李呂','宋','宋诗','song-poetry','','[]','大夫古君子，不可今人求。',48,'全唐诗/poet.song.125000.json','["大夫古君子，不可今人求。", "蠅營鄙世態，貪吟口不休。", "一朝膺事任，卓爾茂勳猷。", "此道今已遠，天乎公首丘。"]'),
('f130afcb-3162-40cb-a7f8-16dc7feba11a','戒蠅','李呂','宋','宋诗','song-poetry','','[]','我夙造惡業，半生苦瘡癤。',132,'全唐诗/poet.song.125000.json','["我夙造惡業，半生苦瘡癤。", "蠅喙利如針，秉箑倦揮滅。", "彼蠅業更深，曾不慕香潔。", "乘間恣飛舞，嗜此穢膿血。", "我雖以慈受，汝愧寧可雪。", "狂念儻不悛，善計有一說。", "海上逐臭夫，正是汝儔埒。", "速往從之游，從容度歲月。", "貪癡志願足，人害永除絕。", "相汝下劣軀，不過藉炎熱。", "徼倖豈可常，肅霜防凜冽。"]'),
('bb3d1746-47e3-4de0-abf0-679da7842ad2','家有含笑花開因成三首  其一','李呂','宋','宋诗','song-poetry','','[]','山花弄春妍，紫霧巧映带。',48,'全唐诗/poet.song.125000.json','["山花弄春妍，紫霧巧映带。", "凝羞香乍吐，顰蹙有餘態。", "芍藥畏陽艷，愁紅爭斂黛。", "幽姿小嫣然，已復傾下蔡。"]'),
('939ea4d0-d2e9-4517-8cfa-a62126965333','家有含笑花開因成三首  其二','李呂','宋','宋诗','song-poetry','','[]','正色巧遮藏，天香清可带。',48,'全唐诗/poet.song.125000.json','["正色巧遮藏，天香清可带。", "若爲忍一噱，恥效嬛薄態。", "奴紅春事退，絕意矜粉黛。", "質素本任真，藻梲鄙居蔡。"]'),
('5e745f62-0dfc-42f0-befa-920ae455db95','家有含笑花開因成三首  其三','李呂','宋','宋诗','song-poetry','','[]','花開哂群芳，葉密相映带。',48,'全唐诗/poet.song.125000.json','["花開哂群芳，葉密相映带。", "根移下岩谷，本無塵俗態。", "紫萼半含羞，翻嫌污香黛。", "我欲譜此花，法書今乏蔡。"]'),
('823f99c5-2048-4f9f-894a-1403ef70ed6a','送江宰別','李呂','宋','宋诗','song-poetry','','[]','行李在門外，駕言歸帝都。',288,'全唐诗/poet.song.125000.json','["行李在門外，駕言歸帝都。", "三年宰杭州，警敏材有餘。", "檢身不容玷，清冰瑩玉壺。", "遇事有所立，風雨信不渝。", "吐哺出延客，懸榻時待儒。", "雅量不遺物，狙詐嗤庸奴。", "胸中水鑑明，黑白分兩途。", "慈良恤民瘼，嚴憚戢黠胥。", "去夏忽大饑，米粒貴比珠。", "農民既無蓄，官廩素乏儲。", "君以身任責，詢謀及樵蘇。", "聲威聳鄰寇，日贍幾萬夫。", "一一勞措畫，晨飯常至晡。", "惜哉當路者，訪問亦已踈。", "此功肩古人，反與泛泛俱。", "要當公論定，會有聞天衢。", "我衰耕谷口，屹然如枯株。", "他人不著眼，屢辱顧草廬。", "脫略時輩禮，待以國士徒。", "臨別難爲懷，欲贈將焉如。", "但願益磨礪，器宇恢遠圖。", "貴富皆分內，青氈君豈無。", "力疾出送別，酸風生道隅。", "征旆不容駐，搔首空躊躇。"]'),
('61ced0a2-4e74-4f35-b9bf-5ef082e8d221','丙辰夏和周宰','李呂','宋','宋诗','song-poetry','','[]','愛公北堂幽，背郭出塵外。',84,'全唐诗/poet.song.125000.json','["愛公北堂幽，背郭出塵外。", "登臨攬萬象，氣宇自怡泰。", "目寄孤歸鴻，道存不下带。", "山水含清暉，况復總其會。", "隔岸列喬松，亭亭若車蓋。", "雲過矯虬龍，風來聽竽籟。", "於此省借留，饑民斯有頼。"]'),
('1e619ece-e435-42d5-947a-979b6589129d','讀太白集','李呂','宋','宋诗','song-poetry','','[]','吾宗老太白，俊逸自幼年。',180,'全唐诗/poet.song.125000.json','["吾宗老太白，俊逸自幼年。", "學成喜任俠，長劍辭三川。", "無心馴鳥雀，急義散金錢。", "曳裾半天下，所至驚四筵。", "筆陣掃强敵，詩情快湧泉。", "一朝見賀監，薦鶚君王前。", "金馬得供奉，酒徒同醉眠。", "從駕方連召，扶頭得十篇。", "奴視高力士，風期魯仲連。", "青蠅工點玉，錦袍棹迴船。", "自謂天地臣，浪稱平地仙。", "志大雖難揜，身危幸保全。", "江陵欲難作，彭澤見幾先。", "仍喜宮詞句，渾如諷諫篇。", "至今讀青史，終始無間然。"]'),
('bd264575-1283-4ae9-9321-ea489d725dff','貞婦','李呂','宋','宋诗','song-poetry','','[]','婉彼鄒氏女，其父嘗籍兵。',288,'全唐诗/poet.song.125000.json','["婉彼鄒氏女，其父嘗籍兵。", "嫁作耕夫妻，婦道以勤稱。", "厥夫惰農業，居肆寄郊坰。", "薪爨不時給，貯粟未滿缾。", "行年三十餘，臉白兩鬢青。", "誰家馬上郎，一見願目成。", "留連不忍去，斜紅挂日鉦。", "携籃夫偶出，次第陳私情。", "示以篋中金，持贈固不輕。", "正色叱走之，郎馬不及乘。", "未幾老狂生，襆被問宿程。", "百計稍與語，酌酒欲同傾。", "窗前理殘麻，不顧空丁寧。", "復出綺香囊，藉以五花繒。", "擎來通鄭重，雖受心不平。", "收之置敝篋，生意正經營。", "託言姑少待，反把柴門扃。", "長聲呼四鄰，悲切不忍聽。", "逡巡夫亦歸，縶縛訴縣庭。", "縣官頗嫉惡，慰遣壯其能。", "撫几三嘆息，恨今無肉刑。", "吾聞秋胡妻，死有不朽名。", "又聞昔羅敷，語直理甚明。", "人生各有偶，勿用行兼并。"]'),
('abde10a1-088f-4b49-9e60-5aa83420c77a','胡程寺二首  其一','李呂','宋','宋诗','song-poetry','','[]','上天一何慘，盛夏忽霜飛。',48,'全唐诗/poet.song.125000.json','["上天一何慘，盛夏忽霜飛。", "竟奪慈母去，焉用此身爲。", "空餘白雲念，無復彩戲時。", "一恨一灑血，何以報春暉。"]'),
('1ad3466b-86ce-4c62-bdd2-96514ab25ab0','胡程寺二首  其二','李呂','宋','宋诗','song-poetry','','[]','忽逢劬勞旦，兒女拜我前。',48,'全唐诗/poet.song.125000.json','["忽逢劬勞旦，兒女拜我前。", "低頭勿頌壽，迺公實不天。", "東南西北去，日月時序遷。", "目斷烏江麓，高墳鎖暝煙。"]'),
('e620d29e-4f94-4272-84c8-c1dcfa3ac452','改過','李呂','宋','宋诗','song-poetry','','[]','顔子趣高遠，改過不待形。',204,'全唐诗/poet.song.125000.json','["顔子趣高遠，改過不待形。", "子路雖未及，有聞思欲行。", "庸人過莫知，心目任盲騰。", "縱復覺其然，如醉不願醒。", "幽顯孰可欺，徒自蔽聰明。", "直待形迹著，巧飾漫經營。", "辭屈既無益，斂翼如凍蠅。", "豫貴介于石，安取冥豫成。", "訟要免終凶，謀始那用爭。", "頤養知節慎，損疾在窒懲。", "下交儻不凟，惡習難薰蒸。", "師誨當佩服，勝己求友朋。", "過言與過行，點檢莫暫停。", "粗能遵此戒，無忝爾所生。", "海鷗識機深，良馬認鞭聲。", "爾過勿憚改，豈知禽獸情。", "善惡審取舍，勿用苦叮嚀。"]'),
('b3c4acd4-13bd-439a-b13d-e44a92015489','泊雷公步涉豫章境江流淼漫煙村夾岸景色橫出顧挹不暇舟中偶獲古風一首','李呂','宋','宋诗','song-poetry','','[]','我昔閲畫圖，酷暑江天景。',144,'全唐诗/poet.song.125000.json','["我昔閲畫圖，酷暑江天景。", "是行不作難，巨艦寄萍梗。", "柁樓一放目，合付詩管領。", "煙雨山出沒，浦溆林逾靜。", "水行三四家，蓑篷事畦町。", "閑牛負烏鵲，散牧無人境。", "淼淼萬頃波，撇掠小漁艇。", "南風吹霽月，碧玉兼天浄。", "清絕迺如許，獨恨句非警。", "强作捧心顰，語出輙肯綮。", "共載多騷人，解頤埒匡鼎。", "模寫入新詩，敢憚再三請。"]'),
('fa9cfa73-6856-4f06-b55b-dc7239d8ea8c','贈上官法師','李呂','宋','宋诗','song-poetry','','[]','法官道家流，修奉有年所。',288,'全唐诗/poet.song.125000.json','["法官道家流，修奉有年所。", "靈驗感人多，時賢贈詩句。", "一日來訪予，三揖進賓廡。", "函袖出異書，雷文加釋注。", "滌手徧披閲，因果皆有據。", "紛紛秦漢後，死者畧可覩。", "權量巧心計，悖道忘君父。", "貪淫蔑仁義，往往涴斤斧。", "質經吾聖人，有理無其故。", "迨乎震夷伯，隠慝才顯露。", "嗟乎三代前，樸實猶近古。", "後者業雖熾，日甚造罪苦。", "不然子之書，何迺遽有許。", "自居田野間，茲事聞亦屢。", "又知今視昔，已復不勝數。", "蠢彼無知輩，徒誦孝悌語。", "人貌犬彘心，埋頭入穢污。", "俯仰多厚顔，劬勞忍深負。", "目前恣爲樂，遑恤盈墨簿。", "願子持此書，鑱石置通衢。", "比屋得大誡，毋致煩天誅。", "下愚終不移，自取任從渠。", "有能用斯言，僊籍登不誣。", "脫或秘弗示，與道終懸殊。"]'),
('d536f7b1-bf3c-4796-b9ad-548a6abd2005','題叢碧亭','李呂','宋','宋诗','song-poetry','','[]','主人厭塵俗，不使居無竹。',48,'全唐诗/poet.song.125000.json','["主人厭塵俗，不使居無竹。", "詩翁愛詩史，詠歌長不足。", "籜龍徧山園，嘉名榜華屋。", "何當乘逸興，倚欄聽戛玉。"]'),
('8cc0566e-ff57-4dce-aee7-5d7b71ffc8e2','聳玉亭','李呂','宋','宋诗','song-poetry','','[]','昔我隠居東，有圃廢不入。',120,'全唐诗/poet.song.125000.json','["昔我隠居東，有圃廢不入。", "平生愛竹心，要與共晨夕。", "種之三二年，小笋生𧥄𧥄。", "歷歲既云久，盤根日以闢。", "環植數百挺，大者欲盈尺。", "直節勢昂霄，瑩潤如玉立。", "邇來苦炎蒸，小亭漫營葺。", "東山舊蒲葵，從此可揮擲。", "爲顧清陰多，更期廣封殖。", "本固待時來，春風易爲力。"]'),
('8e135bb5-9d80-4517-8b10-f4fd85514421','遊青玉峽','李呂','宋','宋诗','song-poetry','','[]','雙劍插銀潢，飛下作驚瀑。',156,'全唐诗/poet.song.125000.json','["雙劍插銀潢，飛下作驚瀑。", "奔流兩山間，峽石峙青玉。", "大聲殷其雷，餘響亂琴筑。", "澄泓神龍居，穢濁不敢觸。", "派別入危亭，湍激如轉轂。", "亭前石磴斜，快瀉皺明縠。", "我來濯塵纓，一覽駭心目。", "霧罩香爐峯，龜鶴舞見腹。", "山尖應更好，恨不騎黄鵠。", "老坡五字句，斂袵三敬讀。", "是翁久已僊，鯤鯨隨絕足。", "猶有出塵語，與世作軌躅。", "援筆記姓名，良慚學貂續。"]'),
('bd1214c7-62ab-4e55-b442-37795320baeb','答官仲儒','李呂','宋','宋诗','song-poetry','','[]','風俗去古遠，人僞日敗常。',240,'全唐诗/poet.song.125000.json','["風俗去古遠，人僞日敗常。", "故知取士法，時焉立紀綱。", "設科發自漢，糊名始於唐。", "前輩務實學，倡道頼歐陽。", "當世所得盛，登用多俊良。", "倒指幾百年，講求屢更張。", "邇來取進士，輕快好文章。", "唾手鑱雁塔，轉身簉鴛行。", "莫論稽古力，所貴時學長。", "自顧本迂拙，下語愁肺腸。", "雖云事場屋，浪逐槐花忙。", "竟如卞和璧，三獻足已傷。", "既然違好尚，敢不知括囊。", "釀渚溪之泉，可以供酒漿。", "拾東園之果，可以資餱糧。", "耦語古聖賢，曝背傲羲黄。", "義命要不媿，胡爲乎皇皇。", "故人弗予棄，妙句深激昂。", "清逸庾謝迫，風騷屈宋旁。", "報言乏瓊琚，微吟頻寒螿。"]'),
('db19c10d-a7a6-4ed6-9317-66c5db662a5a','寄題余氏桂亭','李呂','宋','宋诗','song-poetry','','[]','主人開傑檻，懶種洛中魏。',48,'全唐诗/poet.song.125000.json','["主人開傑檻，懶種洛中魏。", "諸郎請嘉名，笑指亭下桂。", "根分月暈寒，花染天香細。", "珍重青雲梯，籯金未爲貴。"]'),
('14672f87-4109-4bee-a760-738824505549','古意','李呂','宋','宋诗','song-poetry','','[]','鴟鴞嘲鳳凰，飛鳴競啾啾。',180,'全唐诗/poet.song.125000.json','["鴟鴞嘲鳳凰，飛鳴競啾啾。", "鳳兮問彼鴞，見憎何因由。", "我居在丹穴，下瑞暫來遊。", "梧桐與竹實，食息無外求。", "爾本挾妖怪，隠身向陰幽。", "所至興禍事，觜爪藏戈矛。", "晝伏作鼠態，白日照可羞。", "臭腐適其願，惡類自與儔。", "志尚素不同，何殊風馬牛。", "嗟予月旦評，豈論汝劣優。", "汝道自取薄，安得妄怨尤。", "自古盜憎主，何異鴟輩流。", "有如夫子聖，武叔非宿仇。", "臧倉沮孟氏，豈爲魯君謀。", "但當礪風節，汝自曲如鈎。"]'),
('21f32624-762d-4280-b0df-c932fdbca1b7','某伏蒙丈人僉判出示嘗與侍郎鄭公淺沙泉唱酬詩軸率爾次韻','李呂','宋','宋诗','song-poetry','','[]','在昔紹聖初，群英萃朝紳。',288,'全唐诗/poet.song.125000.json','["在昔紹聖初，群英萃朝紳。", "道鄉鼓諫舌，勁氣排天閽。", "雷霆固難犯，鵷鷺皆喪神。", "獨一黄右轄，從容爲奏陳。", "主聖臣則直，攀檻古所聞。", "龍顔爲稍霽，投荒貸斧斤。", "公亦坐此去，剖符漫朱輪。", "斯人下世久，藹然播清芬。", "袁盎當漢代，引却慎夫人。", "用舍雖異致，萬世嫡庶分。", "向使李勣輩，將順恨無門。", "但謂此家事，一言陷其君。", "陸贄得罪唐，不測幾隕身。", "陽城以死爭，久之理頗伸。", "不如漢汲黯，同朝有公孫。", "約議尋即背，巧辭間其臣。", "於惟我聖宋，涵養士氣振。", "世代有忠鯁，漢唐何足云。", "且如唐子方，指摘椒房親。", "繼論燈籠錦，將貶嶺外春。", "君謨立殿坳，開救蒙寬恩。", "宛陵風雅手，長篇紀詠存。", "嗟嗟此鄒黄，袁陽畧同群。", "近則唐與蔡，輩出有弟昆。"]'),
('1227c3de-97f6-4b14-9e72-c227c83fe4b8','酬令裕見寄之什','李呂','宋','宋诗','song-poetry','','[]','伯才不鼓琴，良爲知音撤。',288,'全唐诗/poet.song.125000.json','["伯才不鼓琴，良爲知音撤。", "淵明琴無絃，荆扉晝常閉。", "吾道傳滄洲，初不待識別。", "叔孫志諧俗，禮樂用綿蕝。", "子陵持正論，阿諛腰領絕。", "寧可負鑿方，枉尺未應屑。", "郊居本寂寞，况乃生計拙。", "食指日益繁，資用時告竭。", "客至坐無氈，竊與鄭公埒。", "天隨拾杞菊，焉能饜餔餟。", "平生所厚人，過門或電掣。", "嘗聞貴易交，一命已變節。", "包苴既無魚，裋褐倦造謁。", "闊遠故人書，誰復訪衰苶。", "有燄手可炙，其如火不熱。", "聞酸蚋必聚，其如醯不冽。", "向來出肺肝，生死語虛設。", "醇風恣澆漓，仁義從蕩滅。", "江湖足相忘，何苦怨離別。", "黄君忘年友，歲寒我輩列。", "抗志忌詭隨，講究亦可悅。", "高堂甘旨奉，敢以貧故闕。", "姑從斆學半，俯首棲林樾。", "近枉寄贈篇，用意尤清切。"]'),
('72982724-951b-41d6-9c0e-31157f412c71','題焦山寺','李呂','宋','宋诗','song-poetry','','[]','水輪依風負坤輿，百川東流同灌輸。',208,'全唐诗/poet.song.125000.json','["水輪依風負坤輿，百川東流同灌輸。", "掀巾之陂莽吞受，沃焦之山初不濡。", "雲根終古插江湖，狂瀾滔天隨卷舒。", "空神迴飈避突兀，海門排霄岌相扶。", "僧居蠔山迷向背，佛宇蜃氣成吹噓。", "昔游玄冬崖壑枯，洪濤濺雨吹裳裾。", "風來駕潮愁海若，溟漲跋浪飜鯨魚。", "羽淵咸池相蕩潏，月阿日窟漂方隅。", "此身浮漚一緣聚，四大濕相瀰空虛。", "鍼鋒懸持妙善住，蚊睫坐睨焦螟居。", "山中老禪眼於菟，香飯遣化分雕胡。", "重淵垂涎舞蛟首，方丈宴寢凝薰爐。", "夜寒黑月照濁水，乞取壞衲摩尼珠。"]'),
('8bd4945a-5789-4af0-bd59-028b3745ea51','題宋德器致爽軒','李呂','宋','宋诗','song-poetry','','[]','將軍嘯咤風雷生，一諾之寵千金輕。',128,'全唐诗/poet.song.125000.json','["將軍嘯咤風雷生，一諾之寵千金輕。", "仰頭看山默不應，此段王郎真絕人。", "人言爽氣定何物，面目儼然君不識。", "非氛非祲非烟雲，可以意了難口說。", "子猷拄笏人笑癡，先生作齋人愈疑。", "但知談河不救渴，豈信秀色能充饑。", "千峯橫青朝過雨，折簡招歸入詩句。", "儻有俗客來叩門，爲道我眠卿且去。"]'),
('8cfde9ae-272f-4733-b16f-9d85b1d0c140','滄海行','李呂','宋','宋诗','song-poetry','','[]','滄海有船不可渡，癡人求仙死不悟。',97,'全唐诗/poet.song.125000.json','["滄海有船不可渡，癡人求仙死不悟。", "兒郎斷乳能幾時，忍令萬里投蛟螭。", "兒牽母衣抱父泣，文書催行星火急。", "樓船一去更不歸，至今思家朝夜啼。", "人生不禁別離苦，但得生存猶一處。", "君不見咸陽百萬家，長城白骨埋泥沙。"]'),
('3dd2e4e4-0371-47ad-b420-cc95674c6810','宿游伯均裕齋夜無蚊蚋熟寐達旦','李呂','宋','宋诗','song-poetry','','[]','處處如雷針在舌，咂膚成群難撲滅。',64,'全唐诗/poet.song.125000.json','["處處如雷針在舌，咂膚成群難撲滅。", "主人作官重膏血，未勞揮拂蚊自絕。", "荆棘不産茅山旁，天台有菌皆可嘗。", "期君守此化民術，異類盡令回善良。"]'),
('1ccd2bee-c586-4544-91f2-be5c5f72d464','寄題張道士招真閣','李呂','宋','宋诗','song-poetry','','[]','君成道，去何許，寂寂空山號行府。',190,'全唐诗/poet.song.125000.json','["君成道，去何許，寂寂空山號行府。", "自從漢末人相值，因循今莫覩。", "凄凉古廟落嵓隈，水遶閒庭縈嫩苔。", "敕令立觀奉香火，屈指三十年中來。", "道士張君見奇古，精力强明奈寒暑。", "從前觀心力勤苦，經畫一新舊堂廡。", "嘗聞仙者好樓居，傑閣翬飛接雲衢。", "往來世外隠君子，萬一鶴馭停須臾。", "我勸張君更磨練，莫遣光陰隨物轉。", "一朝平步玉皇前，何慮群仙不相面。", "多少紛紛塵世人，夢中說夢元非真。", "妙處工夫如會了，千百世界現全身。"]'),
('f066538b-9985-4c15-b488-44f1c3557777','寄贈天台石橋京行人','李呂','宋','宋诗','song-poetry','','[]','無心曾看石橋雲，有耳曾聽石橋水。',192,'全唐诗/poet.song.125000.json','["無心曾看石橋雲，有耳曾聽石橋水。", "俗塵未盡難重留，飯麻纔竟歸心起。", "自從一別五春風，夢繞橋庵西復東。", "雀噪亭前聽茶鼓，蛇蟠砌外護瓜叢。", "更憶依人兩烏鵲，朝朝飛下映真閣。", "樹鵝土菌恣登盤，林麓素無蟲獸惡。", "江湖迢遞皆畏途，誰知世上有華胥。", "五百開士去雖久，猶餘一老能清癯。", "幾年脅背不著席，棟宇增新間金碧。", "風月忽寄盈尺書，約我重來共晨夕。", "恨不速駕鵂鶹皮，屈伸臂項款山扉。", "相逢定作解垢衣，水邊石上同茹芝。"]'),
('e7cc1671-4ba0-4a03-82f2-80d2ac1dbf9f','送趙彥修','李呂','宋','宋诗','song-poetry','','[]','六月紅塵如火烈，朝來一雨炎威歇。',176,'全唐诗/poet.song.125000.json','["六月紅塵如火烈，朝來一雨炎威歇。", "漸看蘋末起凉颸，推上冰輪作清絕。", "王孫叱馭欲何之，直向銓曹射佳闕。", "天生良才必有用，豈應付與噲等埒。", "幾載低頭丐祠祿，歲寒頗獲固窮節。", "儻逢佳士重薦論，平視朝紳可頏頡。", "顧我幽居苦羞縮，却掃柴門學藏拙。", "每向水邊狎鷗鳥，未遑郊外習綿蕝。", "君能脫略時從遊，嘗鼎一臠端可別。", "臨行尚作半日留，滿泛青甆話離別。", "秋風若遇南飛鴻，好寄一聲慰騷屑。"]'),
('8f58d8fe-9362-40dd-88f2-231fc0640262','承德功仙尉出示直翁感興之作輒次其韵','李呂','宋','宋诗','song-poetry','','[]','蠅頭蝸角使人愁，貪先務勝如爭舟。',144,'全唐诗/poet.song.125000.json','["蠅頭蝸角使人愁，貪先務勝如爭舟。", "隠心空逐市朝樂，著眼未省林泉幽。", "塵埃平時正汩沒，出處與世相沉浮。", "由徑反誚澹臺子，拔葵仍笑公儀休。", "懷哉古道久寂寞，鳳鳥不至三千秋。", "孰知名教真樂地，徒以得失爲己憂。", "騎馬四馳失其馭，放豚一去何當求。", "羨君淵源得所自，結交道義相追遊。", "箇中有路儻深造，直與古人爲輩流。"]'),
('914122ce-64ed-4cb4-ac66-d3b232d3513c','賀吳守被召','李呂','宋','宋诗','song-poetry','','[]','吳公骨秀如天人，胸襟落落皆經綸。',320,'全唐诗/poet.song.125000.json','["吳公骨秀如天人，胸襟落落皆經綸。", "少年固已富家學，筮仕聊稱梅子真。", "挽弓馳馬特餘事，智勇未減飛將軍。", "向者長汀初擁節，寇攘聚集驚鄉村。", "誰知撫定有長策，不戮一夫令自新。", "稚耋讙呼弛兵革，至今妥貼無叛民。", "移帥贛川尤鎮靜，宿姦褫魄胥崩奔。", "往年群盜號淵藪，一旦荒壟安鋤耘。", "錢流地上非橫索，鈴齋坐嘯生陽春。", "踐更盤錯威望著，素秉公廉政有神。", "貪吏望風爭解去，冤民在處皆獲伸。", "還家坐席曾未煖，迅召連催已在門。", "或人未免巧求譽，我公特立天下聞。", "厥今器識兼文武，倒指誰歟當此舉。", "江淮百萬屯邊兵，轉輸饋餉傾吳楚。", "中原荆棘今幾年，師老不試漫貔虎。", "陛下翻然采輿論，天意可見公宜處。", "裴度指日平蔡州，充國先零豈難取。", "唾手燕雲會有時，佇看大將建旗鼓。", "勒功異域鄙班超，歸佐熙朝作申甫。"]'),
('be9e552e-90c0-471f-9ff0-9e0f7072f1a8','送黄仲甄赴廷試','李呂','宋','宋诗','song-poetry','','[]','我昔嘗爲東南行，煩君載酒送城閾。',224,'全唐诗/poet.song.125000.json','["我昔嘗爲東南行，煩君載酒送城閾。", "酒闌上馬意惻愴，似歎飛沉異鱗翮。", "我言君豈噲等伍，霜蹄偶蹶未爲失。", "整銜易轡便千里，寧比駑駘才寸尺。", "轉頭日月曾幾何，君已聲名滿蟾窟。", "笑呼扁舟下吳會，去意猛作秋鷹掣。", "君家藝德知何年，弟兄頭角俱突兀。", "仙枝萬丈不供折，人家生子嘆豚犢。", "春歸洲渚波面肥，江神爲君好風日。", "君王正御紫宸朝，蜀士半居青瑣闥。", "牽聯即日九天上，判司卑凡等廝役。", "向來於我作魚羨，吾今洗眼看鵬擊。", "人生行止特未定，遇坎乘流聽造物。", "唯有名節不可汙，與君相期保黄髮。"]'),
('7692c584-9758-47b6-97a2-d7da10b0261a','和韓羲仲主簿古巖韻','李呂','宋','宋诗','song-poetry','','[]','君不見版築當年胥靡徒，貌象忽與帝夢符。',246,'全唐诗/poet.song.125000.json','["君不見版築當年胥靡徒，貌象忽與帝夢符。", "卧龍抱膝吟梁甫，霸主不憚三顧廬。", "又不見形模苦遭婦女笑，袖手不解世俗書。", "碧山幽棲載典籍，銀魚焚棄甘林居。", "出處雖云蘭菊異，道則一貫無二途。", "要之窮通有定分，所學豈以世俗拘。", "一旦風雲合際會，坐令四海如唐虞。", "不用山林並容爾，胸中經濟常自如。", "世間餘子真碌碌，得失交病言囁嚅。", "生前雅志一飽足，趨時嫵媚忘遠圖。", "夫君承平相家子，典刑自與今人殊。", "青春已負老成器，白日兀坐聖賢俱。", "腹笥兼收線五色，準擬補衮膺時須。", "豹變要是有毛質，鵬飛九萬看摶扶。", "古巖風月鎮長好，請著斯名鑱座隅。"]'),
('0096ccc4-eaf0-4404-bb0b-00f718bbe2ae','登賦堂','李呂','宋','宋诗','song-poetry','','[]','紫雲之山幾千丈，勢壓岷峩欲爭長。',224,'全唐诗/poet.song.125000.json','["紫雲之山幾千丈，勢壓岷峩欲爭長。", "茫茫巨浸擘山開，萬穴魚龍寄深廣。", "眼明遥見使君家，華堂夜魄栖簷牙。", "手釣峽流揖峯翠，裾珮縹緲凌雲霞。", "仲宣登樓炫能賦，字字悲啼嘆飄寓。", "他人有心予忖之，魏奪劉傾渠不顧。", "使君胸著萬卷書，向來游戲從魚符。", "拂衣歸卧喚不出，但有憂國心鬰紆。", "日落未落飛鳥滅，却立闌干思橫發。", "一川樵牧歌太平，萬古關河感亡國。", "麗詞落紙煥黼裳，細研物變窮天藏。", "憑誰薦之九天上，我無羽翮不得將。", "公乎豈久榛棘下，狗監猶能援司馬。", "子虛大人何足云，願賦蒸民追大雅。"]'),
('8aed6805-d99f-423a-9579-8b911061d76f','次韻令裕言詩','李呂','宋','宋诗','song-poetry','','[]','寓形宇宙有感發，無一不可供詩眸。',96,'全唐诗/poet.song.125000.json','["寓形宇宙有感發，無一不可供詩眸。", "風花浩蕩百變態，草木榮悴皆窮搜。", "渾成功括造化窟，未辭斧鑿孰爲優。", "要當險易隨地出，或平或激如水流。", "不才正自困譏駡，白璧爲贈非所求。", "自憐不具正法眼，解頤安足論賡酬。"]'),
('f94a67e0-2267-40ea-b3fe-2e9e2bbd132d','自臨州還題杉嶺舖','李呂','宋','宋诗','song-poetry','','[]','自西徂東三百里，還閩入浙半月期。',64,'全唐诗/poet.song.125000.json','["自西徂東三百里，還閩入浙半月期。", "人生奔走遽如許，世路險夷當自知。", "造化密移真戲爾，富貴時來則爲之。", "盱盱睢睢亦何益，磊磊落落真大奇。"]'),
('9b97e871-dd56-44da-a6b3-4b1aee52fe94','送仲秉赴廷試五首  其一','李呂','宋','宋诗','song-poetry','','[]','亂石搜琮璧，修梧待鳳凰。',48,'全唐诗/poet.song.125000.json','["亂石搜琮璧，修梧待鳳凰。", "地靈真間闊，世眼但尋常。", "我友更誰子，平生唯此郎。", "連城不當價，容易莫商量。"]'),
('6e065232-9a5d-42e4-a39e-f0abb99ea7bd','送仲秉赴廷試五首  其二','李呂','宋','宋诗','song-poetry','','[]','霧豹文章異，淵鯨爪角雄。',48,'全唐诗/poet.song.125000.json','["霧豹文章異，淵鯨爪角雄。", "荒陂寒泣露，空谷暮號風。", "突起能無意，平沉未分窮。", "不知貂冕地，冷硯破窗中。"]'),
('3b4fa1ba-040e-4d88-baa2-d67ae6bd3e2a','送仲秉赴廷試五首  其三','李呂','宋','宋诗','song-poetry','','[]','欲獻琅玕腹，君詩有宿盟。',48,'全唐诗/poet.song.125000.json','["欲獻琅玕腹，君詩有宿盟。", "雲天宸極邃，日月衮衣明。", "太守薦何武，諸公傾賈生。", "三山移步到，寄語問玄卿。"]'),
('ea51b9b2-beb7-4a68-987f-21a7e93d18ed','送仲秉赴廷試五首  其四','李呂','宋','宋诗','song-poetry','','[]','一元誰破碎，河洛漏微芬。',48,'全唐诗/poet.song.125000.json','["一元誰破碎，河洛漏微芬。", "星斗昭乾緯，葩華粲地文。", "班揚渾細事，伊傅有殊勳。", "補履非神劍，相期敬所聞。"]'),
('f315ef2c-0eb5-4674-8b14-35122ecfe250','送仲秉赴廷試五首  其五','李呂','宋','宋诗','song-poetry','','[]','元龍湖海士，可但著茅廬。',48,'全唐诗/poet.song.125000.json','["元龍湖海士，可但著茅廬。", "詩老經從地，禹功疏鑿餘。", "蜀峰帆影隔，郢樹鳥行疎。", "太史行天下，歸來好著書。"]'),
('9be726a8-23b9-427c-ac68-bef49a4c56a5','挽昭懷皇后詩二首  其一','李呂','宋','宋诗','song-poetry','','[]','㡛御還龜洛，禕衣閟鮒隅。',48,'全唐诗/poet.song.125000.json','["㡛御還龜洛，禕衣閟鮒隅。", "光華隨渭水，巡狩隔蒼梧。", "已卜先朝祔，旋聞反寢虞。", "昭懷千載謚，不朽在椒塗。"]'),
('f4a6a26e-72be-4428-a333-4662166880e2','挽昭懷皇后詩二首  其二','李呂','宋','宋诗','song-poetry','','[]','愍冊哀榮絕，鮮原卜兆安。',48,'全唐诗/poet.song.125000.json','["愍冊哀榮絕，鮮原卜兆安。", "世家金穴舊，大隧玉衣寒。", "何意簪花柰，空遺刈畹蘭。", "神游泰陵廟，永護月衣冠。"]'),
('6cb1b7a2-fc71-4eea-a7db-2370337db55a','次涪陵游北巖寺伊川謫居嘗傳易於此有鈎深堂魯直名且書之故寺有四賢像伊川魯直康節尹和靖','李呂','宋','宋诗','song-poetry','','[]','隔江定佳處，放艇得幽尋。',48,'全唐诗/poet.song.125000.json','["隔江定佳處，放艇得幽尋。", "直上雲根徑，盡行霜葉林。", "昔人非避世，此地可鈎深。", "何物能熏染，幽禽亦好音。"]'),
('3a28711c-fadf-46f8-8a82-9673dc251082','癸丑季春上洲頹岸出敗冢冢中有磚云元嘉二十二年七月二十六日余功曹冢後世子孫長興富貴宜賒因題數句','李呂','宋','宋诗','song-poetry','','[]','八百年前窆，功曹身姓余。',48,'全唐诗/poet.song.125000.json','["八百年前窆，功曹身姓余。", "元嘉兩行字，敗甓八分書。", "富貴念猶在，子孫今已無。", "癡人不修省，視此意何如。"]'),
('3fc14b7b-fc6b-4c79-90b6-1d8c2bb7eff9','丁巳三月送周宰行','李呂','宋','宋诗','song-poetry','','[]','中郎宜有後，餘慶在孫枝。',48,'全唐诗/poet.song.125000.json','["中郎宜有後，餘慶在孫枝。", "學術堪時用，公卿半已知。", "五行人鮮儷，四字格尤奇。", "自此官清要，毋忘老布衣。"]'),
('f60114b1-f1a6-4924-87fe-48ebcba7a507','予一病七十日心事牢落作詩自解','李呂','宋','宋诗','song-poetry','','[]','抱病懶巾櫛，自度作黄冠。',48,'全唐诗/poet.song.125000.json','["抱病懶巾櫛，自度作黄冠。", "披褐襟便短，拖鞋步稍安。", "忘機任俗薄，遮眼把書看。", "未必不爲福，善乎能自寬。"]'),
('a39bdcf3-6b8d-470e-8f67-f0e900af4874','多病','李呂','宋','宋诗','song-poetry','','[]','守靜偏多病，爭先素不能。',48,'全唐诗/poet.song.125000.json','["守靜偏多病，爭先素不能。", "材非經世具，分合出家僧。", "利路防深穽，窮居任曲肱。", "息交休擾擾，藏拙要儚儚。"]'),
('15f9d182-6bdb-483c-90f2-73370c0cd22f','遊希夷觀  其一','李呂','宋','宋诗','song-poetry','','[]','祕館白雲邊，來遊記昔年。',48,'全唐诗/poet.song.125000.json','["祕館白雲邊，來遊記昔年。", "黄冠姿槁甚，敗屋意蕭然。", "訪古知僊裔，看碑識漢鎸。", "危欄聊徙倚，風袂欲翩翩。"]'),
('02c88ec5-df5f-44b3-9dd2-970276e78ffb','遊希夷觀  其二','李呂','宋','宋诗','song-poetry','','[]','楓老丹成葉，蘆輕雪作花。',48,'全唐诗/poet.song.125000.json','["楓老丹成葉，蘆輕雪作花。", "晚風何處笛，疏柳欲栖鴉。", "絕壁生虛靄，晴天點片霞。", "莫教殘酒醒，客裏易思家。"]'),
('15d5af64-c8ad-459a-8322-08534c2e9116','遣興','李呂','宋','宋诗','song-poetry','','[]','天浄鳥飛遠，路幽花自香。',48,'全唐诗/poet.song.125000.json','["天浄鳥飛遠，路幽花自香。", "春風吹草木，野水滿池塘。", "事去青山在，人閒白日長。", "興來搔白髮，微意久難忘。"]'),
('ad2db36b-b7c9-4919-90f9-12e3a1b164b6','懷黄令裕二首  其一','李呂','宋','宋诗','song-poetry','','[]','小齋開卷罷，尚友憶黄君。',48,'全唐诗/poet.song.125000.json','["小齋開卷罷，尚友憶黄君。", "語孟能精熟，圖書正討論。", "梅黄風送雨，江漲野連雲。", "何日相尋去，書燈共一尊。"]'),
('ff18e64a-e84e-4dbf-8ee5-35e334b12adf','懷黄令裕二首  其二','李呂','宋','宋诗','song-poetry','','[]','今時求此道，篤志孰如君。',48,'全唐诗/poet.song.125000.json','["今時求此道，篤志孰如君。", "經訓多成誦，疑難喜細論。", "利交甘若醴，世態薄於雲。", "須秉歲寒節，深推孔孟尊。"]'),
('9a1fbd39-f5b8-4733-a56d-e64d8b974c89','有感','李呂','宋','宋诗','song-poetry','','[]','入務市朝念，在家雲水僧。',48,'全唐诗/poet.song.125000.json','["入務市朝念，在家雲水僧。", "善薰妻法喜，敬遠女摩登。", "忙裏且尋靜，熱中須放生。", "時時發深省，結業莫教增。"]'),
('50663ced-1be0-4005-925b-f611066dd25d','觀荷','李呂','宋','宋诗','song-poetry','','[]','適當寒沼上，更在月明中。',48,'全唐诗/poet.song.125000.json','["適當寒沼上，更在月明中。", "露重鮫珠濕，天高奩鏡空。", "參差千蓋綠，淡竚數枝紅。", "華髮秋風裏，持盃屬老翁。"]'),
('bcc70ce1-373d-4e9e-82af-33312d25d838','對竹次韻','李呂','宋','宋诗','song-poetry','','[]','舉世稱三友，無心是此君。',48,'全唐诗/poet.song.125000.json','["舉世稱三友，無心是此君。", "美花何足竝，俗客未應論。", "不忍踈添月，須教勁拂雲。", "晚凉欣對罷，借色入清尊。"]'),
('33c471bc-6a96-4b07-b600-042ce62a3be1','挽上官文季直二首  其一','李呂','宋','宋诗','song-poetry','','[]','蹤跡半天下，聲名落士林。',48,'全唐诗/poet.song.125000.json','["蹤跡半天下，聲名落士林。", "搢紳爭汲引，歲月漫侵尋。", "後輩尊時尚，斯人竟陸沉。", "只言餘慶在，子舍日駸駸。"]'),
('d6498a77-eeeb-4c2d-a8fa-632eea75dee5','挽上官文季直二首  其二','李呂','宋','宋诗','song-poetry','','[]','念昔康强際，頻趨几杖前。',48,'全唐诗/poet.song.125000.json','["念昔康强際，頻趨几杖前。", "交遊推上行，禮遇辱忘年。", "木落雞籠坂，風酸薤露篇。", "空餘兩行淚，飄洒對新阡。"]'),
('d07640fb-45e3-4eb4-9a4d-f021414667c3','晚步','李呂','宋','宋诗','song-poetry','','[]','薄晚憇高林，好風吹我襟。',48,'全唐诗/poet.song.125000.json','["薄晚憇高林，好風吹我襟。", "斜紅翻鷺翅，空碧湛波心。", "雲塢牛羊下，煙汀竹篠深。", "一聲漁笛罷，裊裊送餘音。"]'),
('ef099206-704f-4b27-a3bd-79b27d0e1254','代懷祖上舅氏','李呂','宋','宋诗','song-poetry','','[]','天上玉麒麟，橫秋爽氣新。',48,'全唐诗/poet.song.125000.json','["天上玉麒麟，橫秋爽氣新。", "書癡心篤好，綵戯日長春。", "直去攀丹桂，須爲近紫宸。", "外家多慶事，接武有名人。"]'),
('0788b9b8-f864-483a-8b1b-e24f0e74c4f4','絕塵軒','李呂','宋','宋诗','song-poetry','','[]','昔年陪仲父，杖屨集幽軒。',72,'全唐诗/poet.song.125000.json','["昔年陪仲父，杖屨集幽軒。", "門占蹄輪道，交無市井言。", "池邊對棋酒，胸次有丘園。", "蟬蛻寒雲斷，徑荒春草蕃。", "增新窗戶改，尚喜典刑存。", "結客登臨去，茶瓜勿憚煩。"]'),
('7e821048-b9a1-4b72-a01d-dd3d60108813','歸自南康寄懷朱使君','李呂','宋','宋诗','song-poetry','','[]','過盡重湖復過山，陰凝忽變雪花團。',64,'全唐诗/poet.song.125000.json','["過盡重湖復過山，陰凝忽變雪花團。", "路迷曲折易成遠，風助橫斜巧送寒。", "憶昨片帆離渡口，特煩千騎駐江干。", "如今想在芙蓉觀，獨據胡床爛漫看。"]'),
('d12c4f35-c79d-472b-aaf3-67a6578265ca','弔霍光','李呂','宋','宋诗','song-poetry','','[]','官安胥飲貴仍驕，父子同誅韙孝昭。',64,'全唐诗/poet.song.125000.json','["官安胥飲貴仍驕，父子同誅韙孝昭。", "博陸時方專國柄，濟陰早已被弓弨。", "老妻安得謀靈嫗，劣女剛將冠內貂。", "白去副封奇禍作，後車傾覆更蕭條。"]'),
('edcece5e-a089-4375-aab1-db17450f4af9','七夕次韻','李呂','宋','宋诗','song-poetry','','[]','天上佳期歲一來，人間急管莫相催。',64,'全唐诗/poet.song.125000.json','["天上佳期歲一來，人間急管莫相催。", "鵲橋成後天孫度，雨泣懸知飈馭回。", "兒女歡呼爭乞巧，樓臺羅列賸傳杯。", "欲搜好句陪年少，病士慙無工部才。"]'),
('00db5046-d5bb-4030-9a24-e66e05fcb7cd','送雙峰聖僧遺像還山','李呂','宋','宋诗','song-poetry','','[]','枯木形模酷肖之，祇應鐸落自秦時。',64,'全唐诗/poet.song.125000.json','["枯木形模酷肖之，祇應鐸落自秦時。", "定光爐韛收親子，圓覺門風出自枝。", "韜晦無因觀大用，感通猶得見全提。", "要知取次爲霖去，便是元初利物機。"]'),
('aa146c83-1d0c-4a57-9c66-bfab6ab2e4bd','天章閣成應制次韻','李呂','宋','宋诗','song-poetry','','[]','寶構雲屯珍木才，璇題金榜倚天開。',64,'全唐诗/poet.song.125000.json','["寶構雲屯珍木才，璇題金榜倚天開。", "高連色界非非境，光動星躔兩兩台。", "上帝圖書開玉府，從臣冠佩繼麟臺。", "詔音亦許賡宸唱，榮勝鄒枚後乘陪。"]'),
('a96feb7f-d9e9-4d93-b7aa-f6398ff60660','自題安樂行','李呂','宋','宋诗','song-poetry','','[]','老於世事盡忘機，古廟寒灰閲四時。',64,'全唐诗/poet.song.125000.json','["老於世事盡忘機，古廟寒灰閲四時。", "稟賦舊爲天地貴，遮闌那許鬼神窺。", "無絃綠綺陶彭澤，露地白牛僧大溈。", "只此瞿曇安樂行，從何處覓是和非。"]'),
('2bbaa56d-c2f5-4c24-9c5f-a3dc91ced915','絕塵軒','李呂','宋','宋诗','song-poetry','','[]','生平雅不樂城市，背郭開軒喜再來。',64,'全唐诗/poet.song.125000.json','["生平雅不樂城市，背郭開軒喜再來。", "煙淡山屏青未了，晴曛荷蓋翠相挨。", "倚風柔弱休栽柳，照水橫斜剩種梅。", "乘興祇應清坐好，此懷難向俗人開。"]'),
('30b998c4-8371-42c3-9a20-d547cd9ff717','送許尉子雲二首  其一','李呂','宋','宋诗','song-poetry','','[]','秦望排空插鑑湖，先生氣稟舊東吳。',64,'全唐诗/poet.song.125000.json','["秦望排空插鑑湖，先生氣稟舊東吳。", "胸中今古幾千載，筆下波瀾雄萬夫。", "綵棒垂門姦自肅，土神應夢昔何殊。", "榮歸快作朝天計，臺閣歡傳得巨儒。"]'),
('9478d16f-289c-4cb2-81b7-c94e6f599989','送許尉子雲二首  其二','李呂','宋','宋诗','song-poetry','','[]','濟人曾現斬蛟手，慢學吳門作陸仙。',64,'全唐诗/poet.song.125000.json','["濟人曾現斬蛟手，慢學吳門作陸仙。", "雪月精神資句法，經綸器識得天全。", "評君合在羲皇上，許我難堪叔度賢。", "出處相懸同臭味，寄懷猶望捧來篇。"]'),
('241350c7-c291-4dd2-b234-37d8b3a3c5ce','送陳尉別二首  其一','李呂','宋','宋诗','song-poetry','','[]','奕世雄題雁塔名，于今父子自師生。',64,'全唐诗/poet.song.125000.json','["奕世雄題雁塔名，于今父子自師生。", "詞場魚貫真無敵，慶事蟬聯盡有聲。", "雅興莫追吳市隠，橫飛端繼紫微明。", "從來患盜驚鄰里，且喜三年鼓不鳴。"]'),
('b362d090-fecd-48db-8a31-5f9ef391cc2c','送陳尉別二首  其二','李呂','宋','宋诗','song-poetry','','[]','試吏誰云百寮底，長材元是萬夫雄。',64,'全唐诗/poet.song.125000.json','["試吏誰云百寮底，長材元是萬夫雄。", "錐刀壟斷焉能較，涇渭區分獨至公。", "顧我每慚天下拙，辱君見許古人風。", "明年還憶蓬蒿徑，身在瀛洲雨露中。"]'),
('d1ad7702-df38-4e6d-89be-b855dfeb6d05','天台石橋設茶供','李呂','宋','宋诗','song-poetry','','[]','聞說天台髻未髽，中年方遂此煎茶。',64,'全唐诗/poet.song.125000.json','["聞說天台髻未髽，中年方遂此煎茶。", "不行四十九盤嶺，那見二千餘盞花。", "架壑橫空瘦龍脊，崩雲裂石怒雷車。", "他時乞我三椽地，莫效曇猷滴兩漥。"]'),
('7992fbc2-dfb5-481b-9667-f1f6302a983e','師正堂二首  其一','李呂','宋','宋诗','song-poetry','','[]','物我雖殊理本同，算來身教易爲功。',64,'全唐诗/poet.song.125000.json','["物我雖殊理本同，算來身教易爲功。", "表端豈但日間影，德盛應如草上風。", "作字心君生筆下，照人眸子驗胸中。", "平生得力今拈出，尤見操存合至公。"]'),
('67b678ba-7af8-48f8-8b21-b1eb2878906d','師正堂二首  其二','李呂','宋','宋诗','song-poetry','','[]','頹垣荒蔓幾經霜，今喜崇成背郭堂。',64,'全唐诗/poet.song.125000.json','["頹垣荒蔓幾經霜，今喜崇成背郭堂。", "雅欲援琴追宓子，時從退食詠羔羊。", "溪流碧遶如平篆，山木陰連不斷行。", "祇恐詔公臺省去，空教南國愛甘棠。"]'),
('029a5388-4672-4286-93b4-03d2f1556360','投贈錢侍郎端禮三篇  其一','李呂','宋','宋诗','song-poetry','','[]','人間富貴豈須論，三百年來積慶門。',64,'全唐诗/poet.song.125000.json','["人間富貴豈須論，三百年來積慶門。", "名紀太常高大父，氣鍾仁祖外曾孫。", "心存忠孝源流遠，義薄雲天色笑溫。", "屈指前時功德輩，悠悠誰似典型存。"]'),
('e4b11fae-b5de-496e-886a-3586c942dbbf','投贈錢侍郎端禮三篇  其二','李呂','宋','宋诗','song-poetry','','[]','仙風道骨本飄飄，萬卷詩書樂一瓢。',64,'全唐诗/poet.song.125000.json','["仙風道骨本飄飄，萬卷詩書樂一瓢。", "落筆雲烟盤錦繡，滿腔星斗絕塵囂。", "懸知可使邦風美，豈但能令國計饒。", "四海徯公歸致主，方今天子舜承堯。"]'),
('9fc574ce-15a5-44e6-8389-a768f782c5ea','投贈錢侍郎端禮三篇  其三','李呂','宋','宋诗','song-poetry','','[]','天地生成無用軀，青箱世業一愚儒。',64,'全唐诗/poet.song.125000.json','["天地生成無用軀，青箱世業一愚儒。", "幾同海上屠龍術，空守巖前待兔株。", "自信平生非木石，誰憐半世混泥塗。", "幸逢點鐵爲金手，乞與投身造化爐。"]'),
('7985ebea-558b-4a08-a886-4c9bf7d2a2ab','上元漫興','李呂','宋','宋诗','song-poetry','','[]','天上元宵放月明，張燈何苦浪經營。',64,'全唐诗/poet.song.125000.json','["天上元宵放月明，張燈何苦浪經營。", "一毬積日方呈巧，千片輕綃僅湊成。", "里巷禽呼傾坐去，街衢蟻聚側身行。", "誰人能向循良道，何不留心勸耦耕。"]'),
('b7b90c17-625e-4991-aa63-b663eb35bcb5','上元應制次韻','李呂','宋','宋诗','song-poetry','','[]','華燈不夜照青春，鼇背繒山迥絕塵。',64,'全唐诗/poet.song.125000.json','["華燈不夜照青春，鼇背繒山迥絕塵。", "已遣燭龍啣火炬，更開璧月駐飈輪。", "長疑化國烟霄近，未覺壺天晚日賓。", "知是奎文臨海外，賜章今夕寵光頻。"]'),
('7378ff78-1041-411c-8811-77662a978441','遣興','李呂','宋','宋诗','song-poetry','','[]','丈夫各自有立志，或出或處非一途。',64,'全唐诗/poet.song.125000.json','["丈夫各自有立志，或出或處非一途。", "主父直須食五鼎，淵明元祇愛吾廬。", "佚居自大同蛙井，巧進貪前乃盜窬。", "顧我蹉跎未忘學，肯將身世較盈虛。"]'),
('eaf51fad-35d8-4c1b-8121-1d2e0404a4ac','病中遣興','李呂','宋','宋诗','song-poetry','','[]','多難從來氣不舒，老而多病背攣如。',64,'全唐诗/poet.song.125000.json','["多難從來氣不舒，老而多病背攣如。", "足瘍所頼非心害，目眚猶欣見舊書。", "白晝欲眠神思倦，青春閒度物情踈。", "生涯淡薄隨時過，他是他非莫問渠。"]'),
('c5b6c252-2019-4523-b2ca-ddf3cbf30242','詩勉粹夫進學兼示諸子','李呂','宋','宋诗','song-poetry','','[]','閒憶當年闖孔門，未能無意覺斯民。',64,'全唐诗/poet.song.125000.json','["閒憶當年闖孔門，未能無意覺斯民。", "浮名浮利雖關命，多病多愁故惱人。", "九十春光渾易老，二三子者莫因循。", "老夫耄矣誠堪笑，何惜同來試問津。"]'),
('52c2e35f-2382-4d86-85f9-6fe97ac0e6aa','吉祥寺舊名永壽初李昪爲徐溫養子徐知訓不能容置酒欲殺之行酒吏刁彥能以手爪昪悟而逃伏此寺山谷作記無咎書','李呂','宋','宋诗','song-poetry','','[]','招提一徑入垂楊，翠竹千竿粉籜香。',64,'全唐诗/poet.song.125000.json','["招提一徑入垂楊，翠竹千竿粉籜香。", "正要銀絲好看客，不須雪乳苦搜腸。", "興亡徐李一彈指，文字晁黄兩擅場。", "八十老僧無箇事，猶將經卷佞空王。"]'),
('f54d15e5-6a41-478d-ab7d-19d1f724c7a2','感興','李呂','宋','宋诗','song-poetry','','[]','聚滅元同水上漚，癡人貪著不知休。',64,'全唐诗/poet.song.125000.json','["聚滅元同水上漚，癡人貪著不知休。", "生便當路栽荆棘，死代群雛作馬牛。", "上隴計全謀蜀道，長城功半廢沙丘。", "古來大手猶如此，只合將心向內求。"]'),
('c92b4934-d8b8-4a68-a3d5-c27b67b63fa9','見菊','李呂','宋','宋诗','song-poetry','','[]','病夫省睡起凌晨，遲菊朦朧破萼新。',64,'全唐诗/poet.song.125000.json','["病夫省睡起凌晨，遲菊朦朧破萼新。", "雨細正應添潤澤，煙輕尤覺長精神。", "近來霜重傷禾死，幾見民憂灑涕頻。", "却是東籬賸黄菊，不堪易粟當金銀。"]'),
('1927f3ea-0aec-4a32-ac98-2bfb02f46819','庚戌仲春携小子訪別晦翁過親友江清卿之門其嗣子尚幼不果見次早道經江清卿墓下悵然有懷','李呂','宋','宋诗','song-poetry','','[]','肩輿兀兀度山村，細雨凄風日易昏。',64,'全唐诗/poet.song.125000.json','["肩輿兀兀度山村，細雨凄風日易昏。", "問店舊曾來托宿，支頤今覺頓銷魂。", "故人委蛻荒春草，倦客空懷合暮雲。", "古木陰連藏小隠，招呼無復笑迎門。"]'),
('4c693437-9810-4904-9b49-e370a003d7cb','次黄象之韵','李呂','宋','宋诗','song-poetry','','[]','踈山元是讀書山，相望麻姑舊醮壇。',64,'全唐诗/poet.song.125000.json','["踈山元是讀書山，相望麻姑舊醮壇。", "梵剎雄誇今日勝，隠居誰作故人看。", "閒隨米運川涂迥，喜入林亭境界寬。", "我已經營謝公屐，竚君好去九遷官。"]'),
('aa509d08-f8c2-4893-b453-7cf276c622fc','借用鄧彥高韻','李呂','宋','宋诗','song-poetry','','[]','性學絲毫未易通，醇疵何敢議軻雄。',64,'全唐诗/poet.song.125000.json','["性學絲毫未易通，醇疵何敢議軻雄。", "文章事業須年少，朴鈍情懷屬老翁。", "閒把笑談窮物外，漫裒今古著胸中。", "觸來方寸有餘地，喜到小齋緣素風。"]'),
('a51b7aa4-c9a4-483d-a24a-a91732c74ae7','憂旱','李呂','宋','宋诗','song-poetry','','[]','田圃如燔木葉黄，火輪從早出扶桑。',64,'全唐诗/poet.song.125000.json','["田圃如燔木葉黄，火輪從早出扶桑。", "佇觀罪己侔湯德，更願求言舉漢章。", "冤死豈能無孝婦，當烹應復有弘羊。", "可憐野老吞聲哭，此意何由達上蒼。"]'),
('65052c47-5ab8-40be-8473-f0dc012c33f0','送王晉卿赴廷試','李呂','宋','宋诗','song-poetry','','[]','怪底先生思湧泉，少年筆勢已翩翩。',64,'全唐诗/poet.song.125000.json','["怪底先生思湧泉，少年筆勢已翩翩。", "馬嘶長道空驤首，龍擘滄波竟上天。", "分付風雲身九萬，更看禮樂字三千。", "期君未可班行去，細聽臚音黼座前。"]'),
('abf7ad10-5055-4694-97b1-e0627e1c9fae','送黄元董赴廷試','李呂','宋','宋诗','song-poetry','','[]','江夏無雙最擅名，君家群從總能文。',64,'全唐诗/poet.song.125000.json','["江夏無雙最擅名，君家群從總能文。", "丹枝只爲一門種，黄卷仍收再世勳。", "天上鴛鴻方接武，眼前駑蹇漫成群。", "蜀軍自昔鋒尤選，一戰憑君靜楚氛。"]'),
('7419d8bc-1886-4593-877f-606c27e51d14','送郭順之赴廷試','李呂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','半生鐵硯不償勞，攬鏡驚心已二毛。',64,'全唐诗/poet.song.125000.json','["半生鐵硯不償勞，攬鏡驚心已二毛。", "縛虎正須還老手，插貂未肯付兒曹。", "九天日月披晨翳，三峽魚龍息夜濤。", "聞說西湖冠天下，水光山色動揮毫。"]'),
('dcc91e2c-add7-4932-b23f-f59e423243ac','送楊文赴廷試','李呂','宋','宋诗','song-poetry','','[]','只今冠蓋盛諸楊，連歲科名屬雁行。',64,'全唐诗/poet.song.125000.json','["只今冠蓋盛諸楊，連歲科名屬雁行。", "筆下戈矛吾退舍，胸中珠琲海傾藏。", "雞群有鶴人誰識，熊掌兼魚子厭嘗。", "一振斯文千古事，憑君更爲引天潢。"]'),
('80b2ea65-6039-4537-9da2-47ddccc95f47','送楊道父赴廷試','李呂','宋','宋诗','song-poetry','','[]','每念先游嘗慨嘆，於君先世最周旋。',64,'全唐诗/poet.song.125000.json','["每念先游嘗慨嘆，於君先世最周旋。", "神駒墮地真千里，老木蟠空已百年。", "此去漢庭應籍甚，向來蜀産久蕭然。", "錦衣歸日烘晴晝，應與萊衣巧鬭鮮。"]'),
('e8887a90-e7e8-4a3f-9cd5-60d762879a31','送趙勝仲赴廷試','李呂','宋','宋诗','song-poetry','','[]','過眼紛紛亂驌驦，誰知龍種不尋常。',64,'全唐诗/poet.song.125000.json','["過眼紛紛亂驌驦，誰知龍種不尋常。", "更生學苦藜分照，長吉詩多錦作囊。", "已作怒鵬橫絕漢，更隨鳴鳳集高崗。", "天將一第酬寒士，分付宗枝亦有光。"]'),
('2678d581-32a8-4b4b-86bc-506746785aa0','贈畫師郭叔詹','李呂','宋','宋诗','song-poetry','','[]','蚤覺儒冠多誤身，聊工傳寫養偏親。',64,'全唐诗/poet.song.125000.json','["蚤覺儒冠多誤身，聊工傳寫養偏親。", "丹青遊戲臻能事，造化生成羨逼真。", "筆下豈皆行路輩，眼中誰是築岩人。", "會當詔作雲臺像，畫手惟君妙入神。"]'),
('6c942003-ea10-4a36-baf1-a32a422dc20e','喜雪應制次韻','李呂','宋','宋诗','song-poetry','','[]','嘉平瑞雪映蒼華，寒凍河源萬里沙。',64,'全唐诗/poet.song.125000.json','["嘉平瑞雪映蒼華，寒凍河源萬里沙。", "貝闕珠宮眩雲海，瓊林玉樹散空花。", "先春知爲農祥應，澤物深隨德意遐。", "不隔寵光迴寸草，何妨梅柳自萌芽。"]'),
('c994410c-7619-4f56-9afa-114efbf0a94d','追挽劉平父二首  其一','李呂','宋','宋诗','song-poetry','','[]','奕世旂常記姓名，屏山道學藹餘馨。',64,'全唐诗/poet.song.125000.json','["奕世旂常記姓名，屏山道學藹餘馨。", "流風與世爲標的，好義於君見典型。", "琴韻祗求追古意，吟懷偏喜旁林扃。", "相逢恨晚情猶厚，悵望音容隔杳冥。"]'),
('6732dafd-3019-4e0a-9adb-65a65d5589e8','追挽劉平父二首  其二','李呂','宋','宋诗','song-poetry','','[]','高才入用合求聞，却向丘園號隠君。',64,'全唐诗/poet.song.125000.json','["高才入用合求聞，却向丘園號隠君。", "馳騁古人真我事，泥塗軒冕付時人。", "黄粱未熟驚塵世，白璧空埋慘暮雲。", "頼得相門餘慶在，諸郎峙玉正詵詵。"]'),
('75476807-d4f3-4119-937d-65c9a8659cfa','登一覽亭有懷亡弟成老下世','李呂','宋','宋诗','song-poetry','','[]','半年懶向此經行，上巳重來雨乍晴。',64,'全唐诗/poet.song.125000.json','["半年懶向此經行，上巳重來雨乍晴。", "三徑就荒春草合，一亭依舊暮山橫。", "悵懷丘壑空陳迹，極目園林不勝情。", "老境何堪風斷雁，倚欄揮淚咽溪聲。"]'),
('74a43562-b503-4348-ae1e-d331d28cbc76','代人次韻','李呂','宋','宋诗','song-poetry','','[]','當時選勝入經營，杖履寧論陰與晴。',64,'全唐诗/poet.song.125000.json','["當時選勝入經營，杖履寧論陰與晴。", "丘壑只應胸次有，溪山故著面前橫。", "可憐永隔笑談樂，何况從來兄弟情。", "峴首人登休墮淚，攪林風雨作秋聲。"]'),
('68fcc8d5-b344-4426-9d47-9ee520f3b03e','宣和殿新竹應制次韻','李呂','宋','宋诗','song-poetry','','[]','千竿倏忽散層雲，疑有風雷爲駿奔。',64,'全唐诗/poet.song.125000.json','["千竿倏忽散層雲，疑有風雷爲駿奔。", "峻擢已應煩地媼，巧裁仍復借天孫。", "已驚虎豹留皮處，更看龍蛇起陸痕。", "聖主工夫同造物，坐令溫詔發霜根。"]'),
('c5c4cd66-8505-43b6-a5ce-b0325c7d18f5','題游少張逸老軒','李呂','宋','宋诗','song-poetry','','[]','勞生著意在榮觀，炊熟黄粱萬慮寬。',64,'全唐诗/poet.song.125000.json','["勞生著意在榮觀，炊熟黄粱萬慮寬。", "溢目琴書聊自樂，半窗風月不吾慳。", "從誰更覓安心法，回首幾經行路難。", "料想已能同水鏡，任他胸次九疑山。"]'),
('bead086a-1d65-43e0-8a38-0e10dda46bb4','代人挽妻父號道者','李呂','宋','宋诗','song-poetry','','[]','里閈推高足善良，不才何幸玷東牀。',64,'全唐诗/poet.song.125000.json','["里閈推高足善良，不才何幸玷東牀。", "修容方喜超賓館，奠雁翻成舉酹觴。", "晚鐸飄聲空有恨，酸風吹淚不成行。", "諸郎頭角多餘慶，褒贈行看爲顯揚。"]'),
('e3a96e4a-bcb5-4da3-bd1b-abb7999408b2','癸丑七月十九日以老病分任諸子以家務因爲詩以示戒','李呂','宋','宋诗','song-poetry','','[]','子舍分勞非獲已，息肩養疾樂閒居。',64,'全唐诗/poet.song.125000.json','["子舍分勞非獲已，息肩養疾樂閒居。", "家傳道義頻加意，俗愛便宜莫計渠。", "要是人人躬孝悌，更令世世飽詩書。", "從今光大成吾志，可免時稱賤丈夫。"]'),
('fdf1d34b-7e05-4eb0-9abc-da2b9213f151','復齋學者','李呂','宋','宋诗','song-poetry','','[]','孟氏求放心，羲易戒迷復。',24,'全唐诗/poet.song.125000.json','["孟氏求放心，羲易戒迷復。", "可嘆聲利場，紛紛競馳逐。"]'),
('4a9f584e-5d20-4fbd-b210-b6597cf25f0f','潭溪釣者','李呂','宋','宋诗','song-poetry','','[]','踞坐魚磯上，無心同狎鷗。',24,'全唐诗/poet.song.125000.json','["踞坐魚磯上，無心同狎鷗。", "敲針漫勞力，故爾投直鉤。"]'),
('2adfb5b8-5420-4736-be24-67bdb3305d7d','卧雲樵者','李呂','宋','宋诗','song-poetry','','[]','山深成獨往，伐木聲丁丁。',24,'全唐诗/poet.song.125000.json','["山深成獨往，伐木聲丁丁。", "莫作爛柯客，長年玩一枰。"]'),
('afc13603-0d4f-42e7-b7cd-9478d78c8f12','老圃拙者','李呂','宋','宋诗','song-poetry','','[]','春蔬含綠滋，荒畦自鋤芟。',24,'全唐诗/poet.song.125000.json','["春蔬含綠滋，荒畦自鋤芟。", "萬事付一默，維摩許同參。"]'),
('1a12afad-e48d-4882-9c7f-23c9803164e7','雲莊耕者','李呂','宋','宋诗','song-poetry','','[]','莘野樂堯舜，谷口豈其鄉。',24,'全唐诗/poet.song.125000.json','["莘野樂堯舜，谷口豈其鄉。", "自是不可掩，區區非近名。"]'),
('84c784ce-c8eb-4de1-b545-aa2835eb7e7d','題七者寮','李呂','宋','宋诗','song-poetry','','[]','瑩心冽寒泉，砥節介如石。',24,'全唐诗/poet.song.125000.json','["瑩心冽寒泉，砥節介如石。", "本無市朝念，自與紅塵隔。"]'),
('0835891a-bf0e-4625-bad2-4de9ed718642','題東寮','李呂','宋','宋诗','song-poetry','','[]','羲和鞭日馭，發軔自暘谷。',24,'全唐诗/poet.song.125000.json','["羲和鞭日馭，發軔自暘谷。", "道人耕寸田，開窗納餘燠。"]'),
('fe17db87-f2c4-4020-a0e2-a3c94e908970','止宿寮','李呂','宋','宋诗','song-poetry','','[]','所重一言契，寧懸千里期。',24,'全唐诗/poet.song.125000.json','["所重一言契，寧懸千里期。", "他年風雨夜，還意劇談詩。"]'),
('44e837f0-e525-4a01-8a47-bb3b3d9331b3','山臺','李呂','宋','宋诗','song-poetry','','[]','蠟屐恣幽尋，未能得其要。',24,'全唐诗/poet.song.125000.json','["蠟屐恣幽尋，未能得其要。", "登臨一放目，千峯供俎豆。"]'),
('4a8c04d3-7504-43b5-bd36-571bfe1049a2','寓齋','李呂','宋','宋诗','song-poetry','','[]','萍梗天地間，初不異萬物。',24,'全唐诗/poet.song.125000.json','["萍梗天地間，初不異萬物。", "可能發深省，惟有一事實。"]'),
('170190e9-e4c0-475e-bf0c-999a5dc303c1','觀善齋','李呂','宋','宋诗','song-poetry','','[]','群居有深益，相視無餘事。',24,'全唐诗/poet.song.125000.json','["群居有深益，相視無餘事。", "此道存諸中，瞭然見眸子。"]'),
('3bca4ed2-0442-49df-8c04-9351ab858bb7','和邑宰張元若酹月亭詩四首  其一','李呂','宋','宋诗','song-poetry','','[]','太白邀月飲，祇許老坡會。',24,'全唐诗/poet.song.125000.json','["太白邀月飲，祇許老坡會。", "汗漫赤壁遊，浩歌邈相對。"]'),
('aa49fabd-f66b-455c-9184-1ec79be51613','和邑宰張元若酹月亭詩四首  其二','李呂','宋','宋诗','song-poetry','','[]','周郎佳少年，定霸在一戰。',24,'全唐诗/poet.song.125000.json','["周郎佳少年，定霸在一戰。", "勉哉志士心，分陰疾如電。"]'),
('d8af5a30-9bec-4a4c-a489-e52aaed60d68','和邑宰張元若酹月亭詩四首  其三','李呂','宋','宋诗','song-poetry','','[]','古人有大志，聞鷄非惡聲。',24,'全唐诗/poet.song.125000.json','["古人有大志，聞鷄非惡聲。", "信知酹月意，與此同條生。"]'),
('cd797dea-0e41-4986-8657-8ff2ea12bdae','和邑宰張元若酹月亭詩四首  其四','李呂','宋','宋诗','song-poetry','','[]','明府命世才，宇量特閎遠。',24,'全唐诗/poet.song.125000.json','["明府命世才，宇量特閎遠。", "爲名江上亭，拈出句中眼。"]'),
('76b37f46-ad5a-4d97-9199-03db427c6ec5','橘香亭二首  其一','李呂','宋','宋诗','song-poetry','','[]','滿林飽風霜，千奴列亭下。',24,'全唐诗/poet.song.125000.json','["滿林飽風霜，千奴列亭下。", "未許吳姬手，藉此長聲價。"]'),
('285cf429-cba1-4d8b-bb13-d886f2e0691f','橘香亭二首  其二','李呂','宋','宋诗','song-poetry','','[]','花落飄碎瓊，果熟染黄蠟。',24,'全唐诗/poet.song.125000.json','["花落飄碎瓊，果熟染黄蠟。", "張君鼻觀間，莫著蘭麝雜。"]'),
('c23c05bf-2931-4d87-bc0a-03827fd5d2c6','鐵笛亭','李呂','宋','宋诗','song-poetry','','[]','孤吹人已遠，橫笛處猶在。',24,'全唐诗/poet.song.125000.json','["孤吹人已遠，橫笛處猶在。", "清名欣有託，奔雲放天籟。"]'),
('996a9bed-0735-45d2-b405-c86f8cdb6ba3','井泉','李呂','宋','宋诗','song-poetry','','[]','山溜碧泓澄，清甘歸色味。',24,'全唐诗/poet.song.125000.json','["山溜碧泓澄，清甘歸色味。", "儻逢張又新，應不落第二。"]'),
('016f5a8e-3b7f-47a1-a0a2-d12f6585901d','禪友','李呂','宋','宋诗','song-poetry','','[]','寄語同參人，切忌隨他轉。',24,'全唐诗/poet.song.125000.json','["寄語同參人，切忌隨他轉。", "若向句中尋，相逢不識面。"]'),
('f14e14cb-6fed-4e68-96a9-6c6576d215fb','棋友','李呂','宋','宋诗','song-poetry','','[]','閒尋十九路，坐斷千萬心。',24,'全唐诗/poet.song.125000.json','["閒尋十九路，坐斷千萬心。", "運甓何爲者，當知惜寸陰。"]'),
('a460e3c5-0f2b-4af7-9eca-c114a1362578','琴友','李呂','宋','宋诗','song-poetry','','[]','金玉聲清圓，鸞鳳勢翔舞。',24,'全唐诗/poet.song.125000.json','["金玉聲清圓，鸞鳳勢翔舞。", "重是古人風，勿效兒女語。"]'),
('cb7211d3-506b-41b8-a8b0-f3720e755751','文友','李呂','宋','宋诗','song-poetry','','[]','摛辭氣爲主，盛氣理或差。',24,'全唐诗/poet.song.125000.json','["摛辭氣爲主，盛氣理或差。", "大音等韶頀，小巧同春葩。"]'),
('34b0eb85-be1a-4d00-9ec2-e6f29c388da7','題君山觀招真閣六首  其一','李呂','宋','宋诗','song-poetry','','[]','蠟屐發興屢，幾爲春泥阻。',24,'全唐诗/poet.song.125000.json','["蠟屐發興屢，幾爲春泥阻。", "此行不作難，霽色隨步武。"]'),
('3318d9e4-9fb2-4bda-85f2-25aea1e47b4a','題君山觀招真閣六首  其二','李呂','宋','宋诗','song-poetry','','[]','數峯碧巑岏，烏君成道山。',24,'全唐诗/poet.song.125000.json','["數峯碧巑岏，烏君成道山。", "仙遊杳難問，空鎖白雲閒。"]'),
('06c3e2ff-87d8-441d-beba-35ce877c65ad','題君山觀招真閣六首  其三','李呂','宋','宋诗','song-poetry','','[]','雙蔓正排空，云是玉真府。',24,'全唐诗/poet.song.125000.json','["雙蔓正排空，云是玉真府。", "採芝何許入，忽此駕修羽。"]'),
('23491121-30d0-423d-b676-438011d0b3e3','題君山觀招真閣六首  其四','李呂','宋','宋诗','song-poetry','','[]','觀宇藏山崦，昔居火宅僧。',24,'全唐诗/poet.song.125000.json','["觀宇藏山崦，昔居火宅僧。", "因緣有時節，羽服奉香燈。"]'),
('aa440109-b68f-4c88-abf5-97b955c9273d','題君山觀招真閣六首  其五','李呂','宋','宋诗','song-poetry','','[]','翬飛新樓臺，像設舊金碧。',24,'全唐诗/poet.song.125000.json','["翬飛新樓臺，像設舊金碧。", "焚修人已老，倚杖對山石。"]'),
('990e75b1-bc15-42d4-a1b3-affe0440d615','題君山觀招真閣六首  其六','李呂','宋','宋诗','song-poetry','','[]','彩侍過丘林，星行忽一周。',24,'全唐诗/poet.song.125000.json','["彩侍過丘林，星行忽一周。", "春暉今已矣，涕淚不能收。"]'),
('81e6b681-f330-4d5e-8ab6-8cfc83d2c6b9','巢雲','李呂','宋','宋诗','song-poetry','','[]','幽棲寄山隈，欣賞亦何有。',24,'全唐诗/poet.song.125000.json','["幽棲寄山隈，欣賞亦何有。", "時許巢白雲，紛然入窗牖。"]'),
('156d56ec-6d8c-4ff8-84a7-da755b100903','上黄端明壽詩以竚期三入後一品見玄孫爲韻  其一','李呂','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','英聲久飛揚，寰海共傾竚。',24,'全唐诗/poet.song.125000.json','["英聲久飛揚，寰海共傾竚。", "學者仰泰山，蒼生待霖雨。"]'),
('e31a6493-8406-41a2-b05f-2fc5e0a22ab8','上黄端明壽詩以竚期三入後一品見玄孫爲韻  其二','李呂','宋','宋诗','song-poetry','','[]','器識誰能及，功名自有期。',24,'全唐诗/poet.song.125000.json','["器識誰能及，功名自有期。", "一朝聞正論，親切在彤墀。"]'),
('45611a44-a960-4ab7-a6b1-1f1424fc497d','上黄端明壽詩以竚期三入後一品見玄孫爲韻  其三','李呂','宋','宋诗','song-poetry','','[]','獻替先其大，從容接每三。',24,'全唐诗/poet.song.125000.json','["獻替先其大，從容接每三。", "但知言謇謇，肯顧府潭潭。"]'),
('c53f69bc-db12-4e0c-a0a7-ecf362fcab7e','上黄端明壽詩以竚期三入後一品見玄孫爲韻  其四','李呂','宋','宋诗','song-poetry','','[]','仗節朔庭回，建議光明入。',24,'全唐诗/poet.song.125000.json','["仗節朔庭回，建議光明入。", "盡得强敵情，何人敢輕襲。"]'),
('d8f44afa-6e97-42da-8bd4-f7212d734c14','上黄端明壽詩以竚期三入後一品見玄孫爲韻  其五','李呂','宋','宋诗','song-poetry','','[]','僎升時許同，孟馬寧處後。',24,'全唐诗/poet.song.125000.json','["僎升時許同，孟馬寧處後。", "人特誦謙光，我獨知德厚。"]'),
('acb51d75-037f-4b7c-b716-943757ecd1d3','上黄端明壽詩以竚期三入後一品見玄孫爲韻  其六','李呂','宋','宋诗','song-poetry','','[]','姓字本無雙，山林今見一。',24,'全唐诗/poet.song.125000.json','["姓字本無雙，山林今見一。", "動必合禮經，心焉在王室。"]'),
('f59f0a73-d6f4-4b85-8b64-cc06631ea587','上黄端明壽詩以竚期三入後一品見玄孫爲韻  其七','李呂','宋','宋诗','song-poetry','','[]','溫旨再褒榮，王人就咨諗。',24,'全唐诗/poet.song.125000.json','["溫旨再褒榮，王人就咨諗。", "早晚詔公歸，餘波潤群品。"]'),
('054e12b9-9599-413f-b211-8390ba92c203','上黄端明壽詩以竚期三入後一品見玄孫爲韻  其八','李呂','宋','宋诗','song-poetry','','[]','骨秀類天人，神清若巖電。',24,'全唐诗/poet.song.125000.json','["骨秀類天人，神清若巖電。", "壽與山嶽齊，造物茲可見。"]'),
('760edd8f-1bb3-41d9-a54e-836be994a17a','上黄端明壽詩以竚期三入後一品見玄孫爲韻  其九','李呂','宋','宋诗','song-poetry','','[]','賤子甘藏拙，無心學草玄。',24,'全唐诗/poet.song.125000.json','["賤子甘藏拙，無心學草玄。", "自然多坎壈，不是樂盤旋。"]');
